window.BILARA["dn16"] = window.BILARA["dn16"] || {};
window.BILARA["dn16"]["vi"] = {
  "dn16:0.1": "Trường Bộ Kinh 16 ",
  "dn16:0.2": "Kinh Đại Bát Niết-bàn ",
  "dn16:1.1.1": "Tôi nghe như vầy—",
  "dn16:1.1.2": "Một thời, Thế Tôn trú tại Rājagaha, trên núi Gijjhakūṭa. ",
  "dn16:1.1.3": "Lúc bấy giờ, vua nước Magadha là Ajātasattu, con bà Vedehī, muốn tiến đánh dân Vajjī. ",
  "dn16:1.1.4": "Vua nói như sau: ",
  "dn16:1.1.5": "“Ta sẽ tiêu diệt dân Vajjī này, tuy họ có đại uy lực, đại oai thế như vậy; ta sẽ hủy diệt dân Vajjī, khiến họ rơi vào tai họa và suy vong.” ",
  "dn16:1.2.1": "Rồi vua nước Magadha là Ajātasattu, con bà Vedehī, gọi bà-la-môn Vassakāra, vị đại thần của Magadha, và bảo: ",
  "dn16:1.2.2": "“Này bà-la-môn, hãy đi đến chỗ Thế Tôn; đến rồi, nhân danh ta, cúi đầu đảnh lễ dưới chân Thế Tôn, và thăm hỏi Thế Tôn có ít bệnh, ít não, khinh an, có sức lực, an trú lạc chăng: ",
  "dn16:1.2.3": "‘Bạch Thế Tôn, vua nước Magadha là Ajātasattu, con bà Vedehī, cúi đầu đảnh lễ dưới chân Thế Tôn, và thăm hỏi Thế Tôn có ít bệnh, ít não, khinh an, có sức lực, an trú lạc chăng.’ ",
  "dn16:1.2.4": "Và hãy nói như sau: ",
  "dn16:1.2.5": "‘Bạch Thế Tôn, vua nước Magadha là Ajātasattu, con bà Vedehī, muốn tiến đánh dân Vajjī. ",
  "dn16:1.2.6": "Vua nói như sau: ",
  "dn16:1.2.7": "“Ta sẽ tiêu diệt dân Vajjī này, tuy họ có đại uy lực, đại oai thế như vậy; ta sẽ hủy diệt dân Vajjī, khiến họ rơi vào tai họa và suy vong.”’ ",
  "dn16:1.2.8": "Thế Tôn trả lời thế nào, ông hãy khéo ghi nhớ rồi về tâu lại cho ta. ",
  "dn16:1.2.9": "Vì các Như Lai không nói lời hư dối.” ",
  "dn16:1.3.0": "1. Bà-la-môn Vassakāra ",
  "dn16:1.3.1": "“Vâng, thưa đại vương,” bà-la-môn Vassakāra, vị đại thần của Magadha, vâng lời vua nước Magadha là Ajātasattu, con bà Vedehī, rồi cho thắng những cỗ xe tốt đẹp, lên một cỗ xe tốt đẹp, và đi ra khỏi Rājagaha bằng những cỗ xe tốt đẹp, hướng đến núi Gijjhakūṭa. ",
  "dn16:1.3.2": "Đi xe đến chỗ nào xe còn đi được, ông xuống xe rồi đi bộ đến chỗ Thế Tôn; đến nơi, ông chào hỏi thân thiện với Thế Tôn. ",
  "dn16:1.3.3": "Sau khi nói những lời chào hỏi thân tình đáng ghi nhớ, ông ngồi xuống một bên. Ngồi xuống một bên, bà-la-môn Vassakāra, vị đại thần của Magadha, bạch Thế Tôn: ",
  "dn16:1.3.4": "“Thưa ngài Gotama, vua nước Magadha là Ajātasattu, con bà Vedehī, cúi đầu đảnh lễ dưới chân ngài Gotama, và thăm hỏi ngài Gotama có ít bệnh, ít não, khinh an, có sức lực, an trú lạc chăng. ",
  "dn16:1.3.5": "Thưa ngài Gotama, vua nước Magadha là Ajātasattu, con bà Vedehī, muốn tiến đánh dân Vajjī. ",
  "dn16:1.3.6": "Vua nói như sau: ",
  "dn16:1.3.7": "‘Ta sẽ tiêu diệt dân Vajjī này, tuy họ có đại uy lực, đại oai thế như vậy; ta sẽ hủy diệt dân Vajjī, khiến họ rơi vào tai họa và suy vong.’” ",
  "dn16:1.4.0": "2. Những pháp khiến quốc gia không suy tàn ",
  "dn16:1.4.1": "Lúc bấy giờ, tôn giả Ānanda đang đứng phía sau Thế Tôn, quạt hầu Thế Tôn. ",
  "dn16:1.4.2": "Rồi Thế Tôn gọi tôn giả Ānanda: ",
  "dn16:1.4.3": "“Này Ānanda, ông có nghe rằng: ‘dân Vajjī thường xuyên hội họp, hội họp đông đủ’ chăng?” ",
  "dn16:1.4.4": "“Bạch Thế Tôn, con có nghe rằng: ‘dân Vajjī thường xuyên hội họp, hội họp đông đủ.’” ",
  "dn16:1.4.5": "“Này Ānanda, chừng nào dân Vajjī còn thường xuyên hội họp, hội họp đông đủ, thì này Ānanda, dân Vajjī chỉ có thể được chờ đợi là hưng thịnh, không suy tàn. ",
  "dn16:1.4.6": "Này Ānanda, ông có nghe rằng: ‘Người Vajji hội họp trong đoàn kết, giải tán trong đoàn kết, và cùng nhau làm các việc của người Vajji’ không?",
  "dn16:1.4.7": "“Bạch Thế Tôn, con có nghe rằng: ‘Người Vajji hội họp trong đoàn kết, giải tán trong đoàn kết, và cùng nhau làm các việc của người Vajji’.”",
  "dn16:1.4.8": "“Này Ānanda, chừng nào người Vajji còn hội họp trong đoàn kết, giải tán trong đoàn kết, và cùng nhau làm các việc của người Vajji, thì này Ānanda, người Vajji chỉ có thể được mong đợi là hưng thịnh, không suy giảm.",
  "dn16:1.4.9": "Này Ānanda, ông có nghe rằng: ‘Người Vajji không đặt ra điều chưa được đặt ra, không bãi bỏ điều đã được đặt ra, và sống thuận theo các pháp cổ truyền của người Vajji đã được quy định’ không?",
  "dn16:1.4.10": "“Bạch Thế Tôn, con có nghe rằng: ‘Người Vajji không đặt ra điều chưa được đặt ra, không bãi bỏ điều đã được đặt ra, và sống thuận theo các pháp cổ truyền của người Vajji đã được quy định’.”",
  "dn16:1.4.11": "“Này Ānanda, chừng nào người Vajji không đặt ra điều chưa được đặt ra, không bãi bỏ điều đã được đặt ra, và sống thuận theo các pháp cổ truyền của người Vajji đã được quy định, thì này Ānanda, người Vajji chỉ có thể được mong đợi là hưng thịnh, không suy giảm.",
  "dn16:1.4.12": "Này Ānanda, ông có nghe rằng: ‘Những vị trưởng lão của người Vajji, người Vajji tôn kính, trọng vọng, kính nể, cúng dường, và cho rằng lời các vị ấy đáng được lắng nghe’ không?",
  "dn16:1.4.13": "“Bạch Thế Tôn, con có nghe rằng: ‘Những vị trưởng lão của người Vajji, người Vajji tôn kính, trọng vọng, kính nể, cúng dường, và cho rằng lời các vị ấy đáng được lắng nghe’.”",
  "dn16:1.4.14": "“Này Ānanda, chừng nào người Vajji còn tôn kính, trọng vọng, kính nể, cúng dường những vị trưởng lão của người Vajji, và cho rằng lời các vị ấy đáng được lắng nghe, thì này Ānanda, người Vajji chỉ có thể được mong đợi là hưng thịnh, không suy giảm.",
  "dn16:1.4.15": "Này Ānanda, ông có nghe rằng: ‘Người Vajji không bắt cóc và cưỡng ép giữ lại các phụ nữ và thiếu nữ của các gia đình’ không?",
  "dn16:1.4.16": "“Bạch Thế Tôn, con có nghe rằng: ‘Người Vajji không bắt cóc và cưỡng ép giữ lại các phụ nữ và thiếu nữ của các gia đình’.”",
  "dn16:1.4.17": "“Này Ānanda, chừng nào người Vajji không bắt cóc và cưỡng ép giữ lại các phụ nữ và thiếu nữ của các gia đình, thì này Ānanda, người Vajji chỉ có thể được mong đợi là hưng thịnh, không suy giảm.",
  "dn16:1.4.18": "Này Ānanda, ông có nghe rằng: ‘Những thánh tích của người Vajji, ở trong và ở ngoài, người Vajji tôn kính, trọng vọng, kính nể, cúng dường, và không để suy giảm các lễ cúng hợp pháp đã được dâng cúng và thực hiện từ trước đối với các nơi ấy’ không?",
  "dn16:1.4.19": "“Bạch Thế Tôn, con có nghe rằng: ‘Những thánh tích của người Vajji, ở trong và ở ngoài, người Vajji tôn kính, trọng vọng, kính nể, cúng dường, và không để suy giảm các lễ cúng hợp pháp đã được dâng cúng và thực hiện từ trước đối với các nơi ấy’.”",
  "dn16:1.4.20": "“Này Ānanda, chừng nào người Vajji còn tôn kính, trọng vọng, kính nể, cúng dường những thánh tích của người Vajji ở trong và ở ngoài, và không để suy giảm các lễ cúng hợp pháp đã được dâng cúng và thực hiện từ trước đối với các nơi ấy, thì này Ānanda, người Vajji chỉ có thể được mong đợi là hưng thịnh, không suy giảm.",
  "dn16:1.4.21": "Này Ānanda, ông có nghe rằng: ‘Người Vajji khéo thiết lập sự che chở, bảo vệ và hộ trì đúng pháp đối với các bậc A-la-hán, để các vị A-la-hán chưa đến có thể đến trong xứ, và các vị A-la-hán đã đến có thể sống an ổn trong xứ’ không?",
  "dn16:1.4.22": "“Bạch Thế Tôn, con có nghe rằng: ‘Người Vajji khéo thiết lập sự che chở, bảo vệ và hộ trì đúng pháp đối với các bậc A-la-hán, để các vị A-la-hán chưa đến có thể đến trong xứ, và các vị A-la-hán đã đến có thể sống an ổn trong xứ’.”",
  "dn16:1.4.23": "“Này Ānanda, chừng nào sự che chở, bảo vệ và hộ trì đúng pháp đối với các bậc A-la-hán của người Vajji còn được khéo thiết lập, để các vị A-la-hán chưa đến có thể đến trong xứ, và các vị A-la-hán đã đến có thể sống an ổn trong xứ, thì này Ānanda, người Vajji chỉ có thể được mong đợi là hưng thịnh, không suy giảm.”",
  "dn16:1.5.1": "Bấy giờ, Thế Tôn gọi bà-la-môn Vassakāra, vị đại thần của Magadha:",
  "dn16:1.5.2": "“Này bà-la-môn, có một thời ta trú tại Vesālī, ở đền Sārandada.",
  "dn16:1.5.3": "Tại đó, ta đã thuyết giảng bảy pháp không suy giảm này cho người Vajji.",
  "dn16:1.5.4": "Này bà-la-môn, chừng nào bảy pháp không suy giảm này còn được duy trì nơi người Vajji, và người Vajji còn được thấy là sống theo bảy pháp không suy giảm này, thì này bà-la-môn, người Vajji chỉ có thể được mong đợi là hưng thịnh, không suy giảm.”",
  "dn16:1.5.5": "Khi được nói vậy, bà-la-môn Vassakāra, vị đại thần của Magadha, bạch Thế Tôn rằng:",
  "dn16:1.5.6": "“Thưa Tôn giả Gotama, chỉ cần người Vajji có được dù chỉ một pháp không suy giảm thôi, thì cũng chỉ có thể được mong đợi là hưng thịnh, không suy giảm.",
  "dn16:1.5.7": "Huống chi là có đủ cả bảy pháp không suy giảm.",
  "dn16:1.5.8": "Thưa Tôn giả Gotama, vua Magadha Ajātasattu, con bà Vedehī, không thể làm gì được người Vajji bằng chiến tranh, trừ phi dùng ly gián, trừ phi gây chia rẽ nội bộ.",
  "dn16:1.5.9": "Thôi nay, thưa Tôn giả Gotama, chúng tôi xin cáo từ, vì chúng tôi có nhiều việc, nhiều bổn phận phải làm.”",
  "dn16:1.5.10": "“Này bà-la-môn, nay ông hãy làm theo điều ông cho là phải thời.”",
  "dn16:1.5.11": "Bấy giờ, bà-la-môn Vassakāra, vị đại thần của Magadha, hoan hỷ tán thán lời Thế Tôn dạy, rồi từ chỗ ngồi đứng dậy và ra đi.",
  "dn16:1.6.0": "3. Các pháp không suy giảm của các Tỳ-kheo",
  "dn16:1.6.1": "Bấy giờ, sau khi bà-la-môn Vassakāra, đại thần xứ Magadha, vừa mới ra đi, Thế Tôn gọi Tôn giả Ānanda:",
  "dn16:1.6.2": "“Này Ānanda, hãy đi tập hợp tất cả các vị tỳ-kheo đang cư trú nương gần Rājagaha đến giảng đường.”",
  "dn16:1.6.3": "“Vâng, bạch Thế Tôn,” Tôn giả Ānanda vâng lời Thế Tôn, tập hợp tất cả các vị tỳ-kheo đang cư trú nương gần Rājagaha tại giảng đường, rồi đi đến chỗ Thế Tôn; đến nơi, đảnh lễ Thế Tôn và đứng sang một bên. Đứng sang một bên, Tôn giả Ānanda bạch Thế Tôn:",
  "dn16:1.6.4": "“Bạch Thế Tôn, chúng tỳ-kheo đã tập hợp xong. Bạch Thế Tôn, nay là lúc nếu Thế Tôn thấy thích hợp.”",
  "dn16:1.6.5": "Bấy giờ, Thế Tôn từ chỗ ngồi đứng dậy, đi đến giảng đường; đến nơi, ngồi xuống chỗ ngồi đã được soạn sẵn.",
  "dn16:1.6.6": "Sau khi ngồi xuống, Thế Tôn gọi các tỳ-kheo:",
  "dn16:1.6.7": "“Này các tỳ-kheo, Ta sẽ thuyết cho các ông bảy pháp không suy giảm,",
  "dn16:1.6.8": "hãy lắng nghe, khéo tác ý, Ta sẽ nói.”",
  "dn16:1.6.9": "“Vâng, bạch Thế Tôn,” các tỳ-kheo ấy vâng đáp Thế Tôn.",
  "dn16:1.6.10": "Thế Tôn nói như sau:",
  "dn16:1.6.11": "“Này các tỳ-kheo, chừng nào các tỳ-kheo còn thường xuyên hội họp, hội họp đông đủ, thì này các tỳ-kheo, sự tăng trưởng của các tỳ-kheo có thể được mong đợi, không phải suy giảm.",
  "dn16:1.6.12": "Này các tỳ-kheo, chừng nào các tỳ-kheo còn hội họp trong hòa hợp, giải tán trong hòa hợp, và làm các công việc của Tăng trong hòa hợp, thì này các tỳ-kheo, sự tăng trưởng của các tỳ-kheo có thể được mong đợi, không phải suy giảm.",
  "dn16:1.6.13": "Này các tỳ-kheo, chừng nào các tỳ-kheo không đặt ra điều chưa được chế định, không bãi bỏ điều đã được chế định, và sống thực hành đúng theo các học giới đã được chế định, thì này các tỳ-kheo, sự tăng trưởng của các tỳ-kheo có thể được mong đợi, không phải suy giảm.",
  "dn16:1.6.14": "Này các tỳ-kheo, chừng nào các tỳ-kheo còn kính trọng, tôn trọng, quý trọng, cúng dường các vị tỳ-kheo trưởng lão, những vị nhiều kinh nghiệm, xuất gia đã lâu, là cha của Tăng chúng, là người dẫn dắt Tăng chúng, và còn xem lời các vị ấy là điều cần được lắng nghe, thì này các tỳ-kheo, sự tăng trưởng của các tỳ-kheo có thể được mong đợi, không phải suy giảm.",
  "dn16:1.6.15": "Này các tỳ-kheo, chừng nào các tỳ-kheo không bị chi phối bởi ái dục đã khởi lên, thứ dẫn đến tái sinh, thì này các tỳ-kheo, sự tăng trưởng của các tỳ-kheo có thể được mong đợi, không phải suy giảm.",
  "dn16:1.6.16": "Này các tỳ-kheo, chừng nào các tỳ-kheo còn ưa thích các chỗ ở nơi rừng núi, thì này các tỳ-kheo, sự tăng trưởng của các tỳ-kheo có thể được mong đợi, không phải suy giảm.",
  "dn16:1.6.17": "Này các tỳ-kheo, chừng nào các tỳ-kheo còn tự mình an trú niệm như sau: ‘Làm sao để các bạn đồng phạm hạnh hiền thiện chưa đến sẽ đến, và các bạn đồng phạm hạnh hiền thiện đã đến sẽ được an trú an lạc’, thì này các tỳ-kheo, sự tăng trưởng của các tỳ-kheo có thể được mong đợi, không phải suy giảm.",
  "dn16:1.6.18": "Này các tỳ-kheo, chừng nào bảy pháp không suy giảm này còn được duy trì nơi các tỳ-kheo, và các tỳ-kheo còn được thấy là sống đúng theo bảy pháp không suy giảm này, thì này các tỳ-kheo, sự tăng trưởng của các tỳ-kheo có thể được mong đợi, không phải suy giảm.",
  "dn16:1.7.1": "“Này các tỳ-kheo, Ta sẽ thuyết cho các ông thêm bảy pháp không suy giảm nữa, hãy lắng nghe, khéo tác ý, Ta sẽ nói.”",
  "dn16:1.7.2": "“Vâng, bạch Thế Tôn,” các tỳ-kheo ấy vâng đáp Thế Tôn.",
  "dn16:1.7.3": "Thế Tôn nói như sau:",
  "dn16:1.7.4": "“Này các tỳ-kheo, chừng nào các tỳ-kheo không ham công việc, không thích công việc, không đắm say trong sự ham thích công việc, thì này các tỳ-kheo, sự tăng trưởng của các tỳ-kheo có thể được mong đợi, không phải suy giảm.",
  "dn16:1.7.5": "Này các tỳ-kheo, chừng nào các tỳ-kheo không ham nói chuyện, không thích nói chuyện, không đắm say trong sự ham thích nói chuyện, thì này các tỳ-kheo, sự tăng trưởng của các tỳ-kheo có thể được mong đợi, không phải suy giảm.",
  "dn16:1.7.6": "Này các tỳ-kheo, chừng nào các tỳ-kheo không ham ngủ nghỉ, không thích ngủ nghỉ, không đắm say trong sự ham thích ngủ nghỉ, thì này các tỳ-kheo, sự tăng trưởng của các tỳ-kheo có thể được mong đợi, không phải suy giảm.",
  "dn16:1.7.7": "Này các tỳ-kheo, chừng nào các tỳ-kheo không ham tụ hội, không thích tụ hội, không đắm say trong sự ham thích tụ hội, thì này các tỳ-kheo, sự tăng trưởng của các tỳ-kheo có thể được mong đợi, không phải suy giảm.",
  "dn16:1.7.8": "Này các tỳ-kheo, chừng nào các tỳ-kheo không có ác dục, không bị các dục vọng xấu ác chi phối, thì này các tỳ-kheo, sự tăng trưởng của các tỳ-kheo có thể được mong đợi, không phải suy giảm.",
  "dn16:1.7.9": "Này các tỳ-kheo, chừng nào các tỳ-kheo không có bạn ác, không có đồng bạn ác, không giao du với kẻ ác, thì này các tỳ-kheo, sự tăng trưởng của các tỳ-kheo có thể được mong đợi, không phải suy giảm.",
  "dn16:1.7.10": "Này các tỳ-kheo, chừng nào các tỳ-kheo không dừng lại giữa chừng chỉ vì đạt được một chút thành tựu thấp kém, thì này các tỳ-kheo, sự tăng trưởng của các tỳ-kheo có thể được mong đợi, không phải suy giảm.",
  "dn16:1.8.1": "Này các tỳ-kheo, chừng nào bảy pháp không suy giảm này còn được duy trì nơi các tỳ-kheo, và các tỳ-kheo còn được thấy là sống đúng theo bảy pháp không suy giảm này, thì này các tỳ-kheo, sự tăng trưởng của các tỳ-kheo có thể được mong đợi, không phải suy giảm.",
  "dn16:1.8.2": "“Này các tỳ-kheo, Ta sẽ thuyết cho các ông thêm bảy pháp không suy giảm nữa …”",
  "dn16:1.8.3": "Này các Tỳ-kheo, chừng nào các Tỳ-kheo còn có lòng tin … ",
  "dn16:1.8.4": "còn có tàm quý … ",
  "dn16:1.8.5": "còn biết hổ thẹn, sợ hãi điều ác … ",
  "dn16:1.8.6": "còn học rộng … ",
  "dn16:1.8.7": "còn tinh cần tinh tấn … ",
  "dn16:1.8.8": "còn an trú chánh niệm … ",
  "dn16:1.8.9": "còn có trí tuệ, này các Tỳ-kheo, chỉ có sự tăng trưởng của các Tỳ-kheo là điều có thể được mong đợi, không phải sự suy giảm.",
  "dn16:1.8.10": "Này các Tỳ-kheo, chừng nào bảy pháp không suy giảm này còn được duy trì nơi các Tỳ-kheo, và các Tỳ-kheo còn được thấy là sống đúng theo bảy pháp không suy giảm này, thì này các Tỳ-kheo, chỉ có sự tăng trưởng của các Tỳ-kheo là điều có thể được mong đợi, không phải sự suy giảm.",
  "dn16:1.8.11": "Này các Tỳ-kheo, ta sẽ thuyết cho các ông thêm bảy pháp không suy giảm nữa. Hãy lắng nghe, hãy khéo tác ý, ta sẽ nói.",
  "dn16:1.8.12": "“Thưa vâng, bạch Thế Tôn”, các Tỳ-kheo ấy vâng đáp Thế Tôn.",
  "dn16:1.8.13": "Thế Tôn nói như sau:",
  "dn16:1.9.1": "“Này các Tỳ-kheo, chừng nào các Tỳ-kheo còn tu tập niệm giác chi … ",
  "dn16:1.9.2": "còn tu tập trạch pháp giác chi … ",
  "dn16:1.9.3": "còn tu tập tinh tấn giác chi … ",
  "dn16:1.9.4": "còn tu tập hỷ giác chi … ",
  "dn16:1.9.5": "còn tu tập khinh an giác chi … ",
  "dn16:1.9.6": "còn tu tập định giác chi … ",
  "dn16:1.9.7": "còn tu tập xả giác chi, này các Tỳ-kheo, chỉ có sự tăng trưởng của các Tỳ-kheo là điều có thể được mong đợi, không phải sự suy giảm.",
  "dn16:1.10.1": "Này các Tỳ-kheo, chừng nào bảy pháp không suy giảm này còn được duy trì nơi các Tỳ-kheo, và các Tỳ-kheo còn được thấy là sống đúng theo bảy pháp không suy giảm này, thì này các Tỳ-kheo, chỉ có sự tăng trưởng của các Tỳ-kheo là điều có thể được mong đợi, không phải sự suy giảm.",
  "dn16:1.10.2": "Này các Tỳ-kheo, ta sẽ thuyết cho các ông thêm bảy pháp không suy giảm nữa. Hãy lắng nghe, hãy khéo tác ý, ta sẽ nói.",
  "dn16:1.10.3": "“Thưa vâng, bạch Thế Tôn”, các Tỳ-kheo ấy vâng đáp Thế Tôn.",
  "dn16:1.10.4": "Thế Tôn nói như sau:",
  "dn16:1.10.5": "“Này các Tỳ-kheo, chừng nào các Tỳ-kheo còn tu tập tưởng về vô thường … ",
  "dn16:1.10.6": "còn tu tập tưởng về vô ngã … ",
  "dn16:1.10.7": "còn tu tập tưởng về bất tịnh … ",
  "dn16:1.10.8": "còn tu tập tưởng về sự nguy hại … ",
  "dn16:1.10.9": "còn tu tập tưởng về từ bỏ … ",
  "dn16:1.10.10": "còn tu tập tưởng về ly tham … ",
  "dn16:1.10.11": "còn tu tập tưởng về diệt, này các Tỳ-kheo, chỉ có sự tăng trưởng của các Tỳ-kheo là điều có thể được mong đợi, không phải sự suy giảm.",
  "dn16:1.10.12": "Này các Tỳ-kheo, chừng nào bảy pháp không suy giảm này còn được duy trì nơi các Tỳ-kheo, và các Tỳ-kheo còn được thấy là sống đúng theo bảy pháp không suy giảm này, thì này các Tỳ-kheo, chỉ có sự tăng trưởng của các Tỳ-kheo là điều có thể được mong đợi, không phải sự suy giảm.",
  "dn16:1.11.1": "Này các Tỳ-kheo, Ta sẽ thuyết cho các ông sáu pháp không suy giảm. Hãy lắng nghe, hãy khéo tác ý, Ta sẽ nói.",
  "dn16:1.11.2": "“Vâng, bạch Thế Tôn”, các Tỳ-kheo ấy vâng đáp Thế Tôn.",
  "dn16:1.11.3": "Thế Tôn nói như sau:",
  "dn16:1.11.4": "“Này các Tỳ-kheo, chừng nào các Tỳ-kheo còn an trú thân hành từ ái đối với các đồng phạm hạnh, cả trước mặt lẫn sau lưng, thì này các Tỳ-kheo, chỉ có sự tăng trưởng của các Tỳ-kheo được chờ đợi, không phải suy giảm.",
  "dn16:1.11.5": "Này các Tỳ-kheo, chừng nào các Tỳ-kheo còn an trú khẩu hành từ ái …",
  "dn16:1.11.6": "còn an trú ý hành từ ái đối với các đồng phạm hạnh, cả trước mặt lẫn sau lưng, thì này các Tỳ-kheo, chỉ có sự tăng trưởng của các Tỳ-kheo được chờ đợi, không phải suy giảm.",
  "dn16:1.11.7": "Này các Tỳ-kheo, chừng nào các Tỳ-kheo đối với những lợi dưỡng hợp pháp, có được đúng pháp, cho đến cả vật nhỏ nhặt thuộc về bình bát, còn là người thọ dụng không chia riêng, cùng thọ dụng chung với các đồng phạm hạnh có giới đức, thì này các Tỳ-kheo, chỉ có sự tăng trưởng của các Tỳ-kheo được chờ đợi, không phải suy giảm.",
  "dn16:1.11.8": "Này các Tỳ-kheo, chừng nào các Tỳ-kheo còn sống đồng nhất về giới với các đồng phạm hạnh, cả trước mặt lẫn sau lưng, trong những giới không bị sứt mẻ, không bị rách, không bị đốm, không bị tỳ vết, đưa đến giải thoát, được người trí tán thán, không bị chấp thủ, đưa đến định, thì này các Tỳ-kheo, chỉ có sự tăng trưởng của các Tỳ-kheo được chờ đợi, không phải suy giảm.",
  "dn16:1.11.9": "Này các Tỳ-kheo, chừng nào các Tỳ-kheo còn sống đồng nhất về kiến với các đồng phạm hạnh, cả trước mặt lẫn sau lưng, với loại chánh kiến thuộc bậc Thánh, có khả năng đưa ra khỏi, dẫn người thực hành đúng đến sự đoạn tận khổ đau, thì này các Tỳ-kheo, chỉ có sự tăng trưởng của các Tỳ-kheo được chờ đợi, không phải suy giảm.",
  "dn16:1.11.10": "Này các Tỳ-kheo, chừng nào sáu pháp không suy giảm này còn tồn tại giữa các Tỳ-kheo, và các Tỳ-kheo còn được thấy là sống trong sáu pháp không suy giảm này, thì này các Tỳ-kheo, chỉ có sự tăng trưởng của các Tỳ-kheo được chờ đợi, không phải suy giảm.”",
  "dn16:1.11.11": "(...)",
  "dn16:1.12.1": "Tại đó, khi trú ở Rājagaha, trên núi Gijjhakūṭa, Thế Tôn thường thuyết cho các Tỳ-kheo bài pháp thoại này:",
  "dn16:1.12.2": "“Đây là giới, đây là định, đây là tuệ.",
  "dn16:1.12.3": "Định được tu tập nhờ giới thì có quả lớn, có lợi ích lớn.",
  "dn16:1.12.4": "Tuệ được tu tập nhờ định thì có quả lớn, có lợi ích lớn.",
  "dn16:1.12.5": "Tâm được tu tập nhờ tuệ thì được giải thoát chân chánh khỏi các lậu hoặc, tức là—",
  "dn16:1.12.6": "dục lậu, hữu lậu, vô minh lậu.”",
  "dn16:1.13.1": "Bấy giờ, sau khi trú tại Rājagaha tùy theo sở thích, Thế Tôn gọi Tôn giả Ānanda:",
  "dn16:1.13.2": "“Này Ānanda, hãy đi, chúng ta sẽ đến Ambalaṭṭhikā.”",
  "dn16:1.13.3": "“Vâng, bạch Thế Tôn”, Tôn giả Ānanda vâng đáp Thế Tôn.",
  "dn16:1.13.4": "Bấy giờ, Thế Tôn cùng với đại chúng Tỳ-kheo đi đến Ambalaṭṭhikā.",
  "dn16:1.14.1": "Tại đó, Thế Tôn trú ở Ambalaṭṭhikā, tại nhà vua.",
  "dn16:1.14.2": "Tại đó nữa, khi trú ở Ambalaṭṭhikā, tại nhà vua, Thế Tôn thường thuyết cho các Tỳ-kheo bài pháp thoại này:",
  "dn16:1.14.3": "“Đây là giới, đây là định, đây là tuệ.",
  "dn16:1.14.4": "Định được tu tập nhờ giới thì có quả lớn, có lợi ích lớn.",
  "dn16:1.14.5": "Tuệ được tu tập nhờ định thì có quả lớn, có lợi ích lớn.",
  "dn16:1.14.6": "Tâm được tu tập nhờ tuệ thì được giải thoát chân chánh khỏi các lậu hoặc, tức là—",
  "dn16:1.14.7": "dục lậu, hữu lậu, vô minh lậu.”",
  "dn16:1.15.1": "Bấy giờ, sau khi trú tại Ambalaṭṭhikā tùy theo sở thích, Thế Tôn gọi Tôn giả Ānanda:",
  "dn16:1.15.2": "“Này Ānanda, hãy đi, chúng ta sẽ đến Nāḷandā.”",
  "dn16:1.15.3": "“Vâng, bạch Thế Tôn”, Tôn giả Ānanda vâng đáp Thế Tôn.",
  "dn16:1.15.4": "Rồi Thế Tôn cùng với đại chúng Tỳ-kheo đi đến Nāḷandā,",
  "dn16:1.15.5": "tại đó Thế Tôn trú ở Nāḷandā, trong vườn xoài của Pāvārika.",
  "dn16:1.16.0": "4. Tiếng sư tử rống của Sāriputta",
  "dn16:1.16.1": "Bấy giờ Tôn giả Sāriputta đi đến chỗ Thế Tôn; sau khi đến, đảnh lễ Thế Tôn rồi ngồi xuống một bên. Khi đã ngồi xuống một bên, Tôn giả Sāriputta bạch Thế Tôn rằng:",
  "dn16:1.16.2": "“Bạch Thế Tôn, con có lòng tịnh tín như vậy đối với Thế Tôn;",
  "dn16:1.16.3": "chưa từng có, sẽ không có, và hiện nay cũng không có một sa-môn hay bà-la-môn nào khác vượt hơn Thế Tôn về giác ngộ.”",
  "dn16:1.16.4": "“Này Sāriputta, lời nói hùng tráng này của ông thật lớn lao, lời khẳng định dứt khoát đã được nắm giữ, tiếng sư tử rống đã được cất lên:",
  "dn16:1.16.5": "‘Bạch Thế Tôn, con có lòng tịnh tín như vậy đối với Thế Tôn;",
  "dn16:1.16.6": "chưa từng có, sẽ không có, và hiện nay cũng không có một sa-môn hay bà-la-môn nào khác vượt hơn Thế Tôn về giác ngộ.’",
  "dn16:1.16.7": "Này Sāriputta, những bậc A-la-hán Chánh Đẳng Giác trong thời quá khứ ấy, tất cả các đức Thế Tôn ấy có được ông dùng tâm biết rõ tâm mà thấu triệt rằng:",
  "dn16:1.16.8": "‘Các đức Thế Tôn ấy có giới hạnh như vậy, có pháp như vậy, có trí tuệ như vậy, sống như vậy, giải thoát như vậy’ chăng?”",
  "dn16:1.16.9": "“Thưa không, bạch Thế Tôn.”",
  "dn16:1.16.10": "“Còn này Sāriputta, những bậc A-la-hán Chánh Đẳng Giác trong thời vị lai ấy, tất cả các đức Thế Tôn ấy có được ông dùng tâm biết rõ tâm mà thấu triệt rằng:",
  "dn16:1.16.11": "‘Các đức Thế Tôn ấy sẽ có giới hạnh như vậy, có pháp như vậy, có trí tuệ như vậy, sống như vậy, giải thoát như vậy’ chăng?”",
  "dn16:1.16.12": "“Thưa không, bạch Thế Tôn.”",
  "dn16:1.16.13": "“Còn này Sāriputta, Ta hiện nay là bậc A-la-hán Chánh Đẳng Giác, có được ông dùng tâm biết rõ tâm mà thấu triệt rằng:",
  "dn16:1.16.14": "‘Thế Tôn có giới hạnh như vậy, có pháp như vậy, có trí tuệ như vậy, sống như vậy, giải thoát như vậy’ chăng?”",
  "dn16:1.16.15": "“Thưa không, bạch Thế Tôn.”",
  "dn16:1.16.16": "“Vậy thì này Sāriputta, đối với các bậc A-la-hán Chánh Đẳng Giác quá khứ, vị lai và hiện tại, ông không có trí biết tâm. ",
  "dn16:1.16.17": "Thế thì vì sao, này Sāriputta, ông lại nói lên lời hùng tráng lớn lao này, nắm giữ lời khẳng định dứt khoát, cất lên tiếng sư tử rống rằng:",
  "dn16:1.16.18": "‘Bạch Thế Tôn, con có lòng tịnh tín như vậy đối với Thế Tôn; chưa từng có, sẽ không có, và hiện nay cũng không có một sa-môn hay bà-la-môn nào khác vượt hơn Thế Tôn về giác ngộ’?”",
  "dn16:1.17.1": "“Bạch Thế Tôn, con không có trí biết tâm đối với các bậc A-la-hán Chánh Đẳng Giác quá khứ, vị lai và hiện tại,",
  "dn16:1.17.2": "nhưng con biết được sự suy luận theo pháp. ",
  "dn16:1.17.3": "Ví như, bạch Thế Tôn, nơi biên địa của vua có một thành trì kiên cố, nền móng vững chắc, tường thành và cổng thành bền chắc, chỉ có một cửa,",
  "dn16:1.17.4": "ở đó có người giữ cửa thông minh, khéo léo, sáng suốt, ngăn người lạ và cho người quen đi vào. ",
  "dn16:1.17.5": "Người ấy đi tuần tự theo con đường quanh khắp thành ấy, không thấy một kẽ hở nào nơi tường thành hay một lỗ hổng nào nơi tường thành, cho đến cả một chỗ đủ cho con mèo chui ra cũng không. ",
  "dn16:1.17.6": "Người ấy nghĩ như sau:",
  "dn16:1.17.7": "‘Bất cứ những sinh vật lớn nào đi vào hay đi ra thành này, tất cả đều đi vào hay đi ra bằng chính cửa này.’",
  "dn16:1.17.8": "Cũng vậy, bạch Thế Tôn, con biết được sự suy luận theo pháp:",
  "dn16:1.17.9": "‘Bạch Thế Tôn, những vị A-la-hán Chánh Đẳng Giác nào đã có trong thời quá khứ, tất cả các đức Thế Tôn ấy sau khi đoạn trừ năm triền cái, những cấu uế của tâm làm suy yếu trí tuệ, an trú tâm vững chắc trong bốn niệm xứ, tu tập bảy giác chi như thật, đã chứng ngộ vô thượng chánh đẳng giác.",
  "dn16:1.17.10": "Bạch Thế Tôn, những vị A-la-hán Chánh Đẳng Giác nào sẽ có trong thời vị lai, tất cả các đức Thế Tôn ấy sau khi đoạn trừ năm triền cái, những cấu uế của tâm làm suy yếu trí tuệ, an trú tâm vững chắc trong bốn niệm xứ, tu tập bảy giác chi như thật, sẽ chứng ngộ vô thượng chánh đẳng giác.",
  "dn16:1.17.11": "Bạch Thế Tôn, chính Thế Tôn hiện nay là bậc A-la-hán Chánh Đẳng Giác, sau khi đoạn trừ năm triền cái, những cấu uế của tâm làm suy yếu trí tuệ, an trú tâm vững chắc trong bốn niệm xứ, tu tập bảy giác chi như thật, đã chứng ngộ vô thượng chánh đẳng giác.’",
  "dn16:1.18.1": "Tại đó, khi đang trú ở Nāḷandā, trong vườn xoài của Pāvārika, Thế Tôn thường thuyết cho các tỳ-kheo bài pháp thoại này:",
  "dn16:1.18.2": "“Đây là giới, đây là định, đây là tuệ.",
  "dn16:1.18.3": "Định được tu tập nhờ giới có quả lớn, lợi ích lớn.",
  "dn16:1.18.4": "Tuệ được tu tập nhờ định có quả lớn, lợi ích lớn.",
  "dn16:1.18.5": "Tâm được tu tập nhờ tuệ được giải thoát chân chánh khỏi các lậu hoặc, đó là—",
  "dn16:1.18.6": "dục lậu, hữu lậu, vô minh lậu.”",
  "dn16:1.19.0": "5. Tai hại của giới hạnh xấu ác",
  "dn16:1.19.1": "Rồi Thế Tôn, sau khi ở Nāḷandā tùy ý, gọi Tôn giả Ānanda:",
  "dn16:1.19.2": "“Này Ānanda, hãy đi, chúng ta sẽ đến Pāṭaligāma.”",
  "dn16:1.19.3": "“Vâng, bạch Thế Tôn,” Tôn giả Ānanda vâng đáp Thế Tôn.",
  "dn16:1.19.4": "Rồi Thế Tôn cùng với đại chúng tỳ-kheo đi đến Pāṭaligāma.",
  "dn16:1.20.1": "Các nam cư sĩ ở Pāṭaligāma nghe rằng: “Nghe nói Thế Tôn đã đến Pāṭaligāma.”",
  "dn16:1.20.2": "Rồi các nam cư sĩ ở Pāṭaligāma đi đến chỗ Thế Tôn; đến nơi, đảnh lễ Thế Tôn rồi ngồi xuống một bên. Khi đã ngồi xuống một bên, các nam cư sĩ ở Pāṭaligāma bạch Thế Tôn:",
  "dn16:1.20.3": "“Bạch Thế Tôn, xin Thế Tôn nhận lời đến nhà khách của chúng con.”",
  "dn16:1.20.4": "Thế Tôn im lặng nhận lời.",
  "dn16:1.21.1": "Rồi các nam cư sĩ ở Pāṭaligāma, biết Thế Tôn đã nhận lời, từ chỗ ngồi đứng dậy, đảnh lễ Thế Tôn, đi nhiễu bên phải rồi đi đến nhà khách; đến nơi, họ trải khắp nhà khách, sắp đặt các chỗ ngồi, đặt bình nước, thắp đèn dầu, rồi đi đến chỗ Thế Tôn; đến nơi, đảnh lễ Thế Tôn rồi đứng sang một bên. Khi đã đứng sang một bên, các nam cư sĩ ở Pāṭaligāma bạch Thế Tôn:",
  "dn16:1.21.2": "“Bạch Thế Tôn, nhà khách đã được trải dọn khắp nơi, các chỗ ngồi đã được sắp đặt, bình nước đã được đặt, đèn dầu đã được thắp;",
  "dn16:1.21.3": "bây giờ, bạch Thế Tôn, khi nào Thế Tôn thấy là hợp thời.”",
  "dn16:1.22.1": "Rồi Thế Tôn vào buổi chiều, sau khi đắp y, mang theo y bát, cùng với chúng tỳ-kheo đi đến nhà khách; đến nơi, rửa chân, bước vào nhà khách rồi ngồi dựa cột giữa, mặt hướng về phía đông.",
  "dn16:1.22.2": "Chúng tỳ-kheo cũng rửa chân, bước vào nhà khách rồi ngồi dựa vách phía tây, mặt hướng về phía đông, lấy Thế Tôn làm vị trí trung tâm.",
  "dn16:1.22.3": "Các nam cư sĩ ở Pāṭaligāma cũng rửa chân, bước vào nhà khách rồi ngồi dựa vách phía đông, mặt hướng về phía tây, lấy Thế Tôn làm vị trí trung tâm.",
  "dn16:1.22.4": "(…)",
  "dn16:1.23.1": "Rồi Thế Tôn gọi các nam cư sĩ ở Pāṭaligāma:",
  "dn16:1.23.2": "“Này các gia chủ, có năm tai hại này của người ác giới, do giới hạnh bị hư hoại.",
  "dn16:1.23.3": "Thế nào là năm?",
  "dn16:1.23.4": "Ở đây, này các gia chủ, người ác giới, giới hạnh hư hoại, do nhân phóng dật mà phải chịu tổn thất lớn về tài sản.",
  "dn16:1.23.5": "Đây là tai hại thứ nhất của người ác giới, do giới hạnh bị hư hoại.",
  "dn16:1.23.6": "Lại nữa, này các gia chủ, người giới hạnh xấu ác, giới đức suy đồi, tiếng xấu đồn xa.",
  "dn16:1.23.7": "Đây là tai hại thứ hai của người giới đức suy đồi.",
  "dn16:1.23.8": "Lại nữa, này các gia chủ, người giới hạnh xấu ác, giới đức suy đồi, khi đến bất cứ hội chúng nào — dù là hội chúng sát-đế-lỵ, hội chúng bà-la-môn, hội chúng gia chủ hay hội chúng sa-môn — đều đến với tâm không tự tin, bối rối.",
  "dn16:1.23.9": "Đây là tai hại thứ ba của người giới đức suy đồi.",
  "dn16:1.23.10": "Lại nữa, này các gia chủ, người giới hạnh xấu ác, giới đức suy đồi, khi mạng chung thì tâm trí mê loạn.",
  "dn16:1.23.11": "Đây là tai hại thứ tư của người giới đức suy đồi.",
  "dn16:1.23.12": "Lại nữa, này các gia chủ, người giới hạnh xấu ác, giới đức suy đồi, sau khi thân hoại mạng chung, sinh vào cõi dữ, ác thú, đọa xứ, địa ngục.",
  "dn16:1.23.13": "Đây là tai hại thứ năm của người giới đức suy đồi.",
  "dn16:1.23.14": "Này các gia chủ, đó là năm tai hại của người giới đức suy đồi.",
  "dn16:1.24.0": "6. Lợi ích của người có giới",
  "dn16:1.24.1": "Này các gia chủ, có năm lợi ích này của người có giới nhờ thành tựu giới.",
  "dn16:1.24.2": "Năm điều ấy là gì?",
  "dn16:1.24.3": "Ở đây, này các gia chủ, người có giới, thành tựu giới, nhờ sống không phóng dật mà đạt được khối tài sản lớn.",
  "dn16:1.24.4": "Đây là lợi ích thứ nhất của người có giới nhờ thành tựu giới.",
  "dn16:1.24.5": "Lại nữa, này các gia chủ, người có giới, thành tựu giới, được tiếng tốt đồn xa.",
  "dn16:1.24.6": "Đây là lợi ích thứ hai của người có giới nhờ thành tựu giới.",
  "dn16:1.24.7": "Lại nữa, này các gia chủ, người có giới, thành tựu giới, khi đến bất cứ hội chúng nào — dù là hội chúng sát-đế-lỵ, hội chúng bà-la-môn, hội chúng gia chủ hay hội chúng sa-môn — đều đến với tâm tự tin, không bối rối.",
  "dn16:1.24.8": "Đây là lợi ích thứ ba của người có giới nhờ thành tựu giới.",
  "dn16:1.24.9": "Lại nữa, này các gia chủ, người có giới, thành tựu giới, khi mạng chung thì tâm trí không mê loạn.",
  "dn16:1.24.10": "Đây là lợi ích thứ tư của người có giới nhờ thành tựu giới.",
  "dn16:1.24.11": "Lại nữa, này các gia chủ, người có giới, thành tựu giới, sau khi thân hoại mạng chung, sinh vào cõi lành, cõi trời.",
  "dn16:1.24.12": "Đây là lợi ích thứ năm của người có giới nhờ thành tựu giới.",
  "dn16:1.24.13": "Này các gia chủ, đó là năm lợi ích của người có giới nhờ thành tựu giới.",
  "dn16:1.25.1": "Bấy giờ, Thế Tôn sau khi dùng pháp thoại chỉ dạy, khuyến khích, làm phấn chấn, làm hoan hỷ các nam cư sĩ ở Pāṭaligāma suốt phần lớn đêm, liền cho họ lui về:",
  "dn16:1.25.2": "“Này các gia chủ, đêm đã khuya rồi, nay các ông hãy làm những gì các ông cho là hợp thời.”",
  "dn16:1.25.3": "“Vâng, bạch Thế Tôn”, các nam cư sĩ ở Pāṭaligāma vâng đáp Thế Tôn, rồi từ chỗ ngồi đứng dậy, đảnh lễ Thế Tôn, đi nhiễu bên phải và ra về.",
  "dn16:1.25.4": "Rồi Thế Tôn, sau khi các nam cư sĩ ở Pāṭaligāma ra về không bao lâu, đi vào tịnh thất trống.",
  "dn16:1.26.0": "7. Xây dựng thành Pāṭaliputta",
  "dn16:1.26.1": "Lúc bấy giờ, hai đại thần Magadha là Sunidha và Vassakāra đang cho xây dựng thành ở Pāṭaligāma để chống lại người Vajji.",
  "dn16:1.26.2": "Khi ấy, có rất nhiều chư thiên, đến hàng ngàn vị, đang chọn các khu đất ở Pāṭaligāma.",
  "dn16:1.26.3": "Ở nơi nào các vị thiên thần có đại oai lực chọn đất, thì tại nơi ấy tâm của các vua và các đại thần của vua hướng đến việc xây dựng nhà cửa cho các vị có đại oai lực.",
  "dn16:1.27.1": "Ở nơi nào các vị thiên thần bậc trung chọn đất, thì tại nơi ấy tâm của các vua và các đại thần của vua hướng đến việc xây dựng nhà cửa cho các vị bậc trung.",
  "dn16:1.27.2": "Ở nơi nào các vị thiên thần bậc thấp chọn đất, thì tại nơi ấy tâm của các vua và các đại thần của vua hướng đến việc xây dựng nhà cửa cho các vị bậc thấp.",
  "dn16:1.27.3": "Với thiên nhãn thanh tịnh, siêu nhân, Thế Tôn đã thấy các vị thiên thần ấy, hàng ngàn vị, đang chọn đất tại làng Pāṭali.",
  "dn16:1.27.4": "Rồi vào lúc gần sáng, Thế Tôn thức dậy và gọi Tôn giả Ānanda:",
  "dn16:1.27.5": "“Này Ānanda, ai đang xây thành ở làng Pāṭali vậy?”",
  "dn16:1.27.6": "“Bạch Thế Tôn, Sunidha và Vassakāra, các đại thần nước Magadha, đang xây thành ở làng Pāṭali để ngăn chặn dân Vajjī.”",
  "dn16:1.28.1": "“Này Ānanda, ví như đã bàn bạc cùng với chư thiên cõi Tāvatiṁsa,",
  "dn16:1.28.2": "cũng vậy, này Ānanda, Sunidha và Vassakāra, các đại thần nước Magadha, đang xây thành ở làng Pāṭali để ngăn chặn dân Vajjī.",
  "dn16:1.28.3": "Ở đây, này Ānanda, với thiên nhãn thanh tịnh, siêu nhân, Ta đã thấy rất nhiều vị thiên thần, hàng ngàn vị, đang chọn đất tại làng Pāṭali.",
  "dn16:1.28.4": "Ở nơi nào, này Ānanda, các vị thiên thần có đại oai lực chọn đất, thì tại nơi ấy tâm của các vua và các đại thần của vua hướng đến việc xây dựng nhà cửa cho các vị có đại oai lực.",
  "dn16:1.28.5": "Ở nơi nào các vị thiên thần bậc trung chọn đất, thì tại nơi ấy tâm của các vua và các đại thần của vua hướng đến việc xây dựng nhà cửa cho các vị bậc trung.",
  "dn16:1.28.6": "Ở nơi nào các vị thiên thần bậc thấp chọn đất, thì tại nơi ấy tâm của các vua và các đại thần của vua hướng đến việc xây dựng nhà cửa cho các vị bậc thấp.",
  "dn16:1.28.7": "Này Ānanda, trong phạm vi nào có chỗ cư trú của bậc thánh, trong phạm vi nào có đường giao thương, thì Pāṭaliputta này sẽ trở thành thành phố bậc nhất, một nơi hàng hóa tụ hội.",
  "dn16:1.28.8": "Nhưng này Ānanda, Pāṭaliputta sẽ có ba tai họa—",
  "dn16:1.28.9": "do lửa, do nước, hoặc do nội bộ chia rẽ.”",
  "dn16:1.29.1": "Rồi Sunidha và Vassakāra, các đại thần nước Magadha, đi đến chỗ Thế Tôn; đến nơi, họ chào hỏi Thế Tôn,",
  "dn16:1.29.2": "sau khi nói những lời thăm hỏi thân thiện và đáng ghi nhớ, họ đứng sang một bên. Đứng sang một bên, Sunidha và Vassakāra, các đại thần nước Magadha, bạch Thế Tôn:",
  "dn16:1.29.3": "“Xin Tôn giả Gotama nhận lời thọ trai ngày nay cùng với chúng Tỳ-kheo.”",
  "dn16:1.29.4": "Thế Tôn im lặng nhận lời.",
  "dn16:1.30.1": "Rồi Sunidha và Vassakāra, các đại thần nước Magadha, biết Thế Tôn đã nhận lời, liền đi đến chỗ ở của mình; đến nơi, họ cho chuẩn bị các món ăn thượng vị loại cứng và loại mềm, rồi cho báo giờ đến Thế Tôn:",
  "dn16:1.30.2": "“Đã đến giờ, thưa Tôn giả Gotama, bữa ăn đã sẵn sàng.”",
  "dn16:1.30.3": "Rồi vào buổi sáng, Thế Tôn đắp y, mang bát và y, cùng với chúng Tỳ-kheo đi đến chỗ ở của Sunidha và Vassakāra, các đại thần nước Magadha; đến nơi, Ngài ngồi xuống chỗ ngồi đã soạn sẵn.",
  "dn16:1.30.4": "Rồi Sunidha và Vassakāra, các đại thần nước Magadha, tự tay dâng cúng và làm cho chúng Tỳ-kheo có Đức Phật đứng đầu được thỏa mãn với các món ăn thượng vị loại cứng và loại mềm.",
  "dn16:1.30.5": "Rồi Sunidha và Vassakāra, các đại thần nước Magadha, khi Thế Tôn đã dùng bữa xong, tay đã rời khỏi bát, liền lấy một chỗ ngồi thấp khác và ngồi sang một bên.",
  "dn16:1.31.1": "Khi Sunidha và Vassakāra, các đại thần nước Magadha, ngồi sang một bên, Thế Tôn đã tùy hỷ bằng những bài kệ này:",
  "dn16:1.31.2": "“Ở nơi nào người trí lập",
  "dn16:1.31.3": "chỗ ở của mình;",
  "dn16:1.31.4": "sau khi cúng dường tại đó những người có giới đức,",
  "dn16:1.31.5": "những vị phạm hạnh tự chế.”",
  "dn16:1.31.6": "Những vị chư thiên nào ở tại đó, ",
  "dn16:1.31.7": "hãy cúng dường đến các vị ấy; ",
  "dn16:1.31.8": "được cúng dường, các vị ấy sẽ cúng dường lại, ",
  "dn16:1.31.9": "được tôn kính, các vị ấy sẽ tôn kính người ấy. ",
  "dn16:1.31.10": "Rồi các vị ấy sẽ thương tưởng người ấy, ",
  "dn16:1.31.11": "như mẹ thương đứa con ruột của mình; ",
  "dn16:1.31.12": "người được chư thiên thương tưởng, ",
  "dn16:1.31.13": "luôn thấy những điều tốt lành.” ",
  "dn16:1.31.14": "Rồi Thế Tôn sau khi tùy hỷ với hai vị đại thần Magadha là Sunidha và Vassakāra bằng những bài kệ này, liền từ chỗ ngồi đứng dậy và ra đi. ",
  "dn16:1.32.1": "Lúc bấy giờ, hai vị đại thần Magadha là Sunidha và Vassakāra đi theo sau Thế Tôn, ",
  "dn16:1.32.2": "nghĩ rằng: “Hôm nay Sa-môn Gotama sẽ đi ra bằng cửa nào, cửa ấy sẽ được gọi là cửa Gotama. ",
  "dn16:1.32.3": "Ngài sẽ vượt sông Hằng tại bến nào, bến ấy sẽ được gọi là bến Gotama.” ",
  "dn16:1.32.4": "Rồi Thế Tôn đi ra bằng cửa nào, cửa ấy được gọi là cửa Gotama. ",
  "dn16:1.32.5": "Rồi Thế Tôn đi đến sông Hằng. ",
  "dn16:1.33.1": "Lúc bấy giờ, sông Hằng nước đầy tràn, ngang bờ, đến mức quạ cũng có thể uống được. ",
  "dn16:1.33.2": "Một số người tìm thuyền, một số người tìm bè, một số người kết mảng để từ bờ này sang bờ kia, vì muốn qua bờ bên kia. ",
  "dn16:1.33.3": "Rồi Thế Tôn—ví như một người lực lưỡng co cánh tay đang duỗi ra, hoặc duỗi cánh tay đang co lại; cũng vậy—biến mất ở bờ này sông Hằng và hiện ra ở bờ bên kia cùng với chúng Tỳ-kheo. ",
  "dn16:1.34.1": "Thế Tôn thấy những người ấy, một số đang tìm thuyền, một số đang tìm bè, một số đang kết mảng để từ bờ này sang bờ kia, vì muốn qua bờ bên kia. ",
  "dn16:1.34.2": "Rồi Thế Tôn, sau khi biết rõ ý nghĩa ấy, vào lúc ấy đã thốt lên lời cảm hứng này: ",
  "dn16:1.34.3": "“Những ai vượt qua biển nước, ",
  "dn16:1.34.4": "sau khi làm cầu, bỏ lại các vũng lầy; ",
  "dn16:1.34.5": "người đời còn kết bè, ",
  "dn16:1.34.6": "còn bậc trí thì đã vượt qua.” ",
  "dn16:1.34.7": "Phần tụng đọc thứ nhất. ",
  "dn16:2.1.0": "8. Bàn về các Thánh đế ",
  "dn16:2.1.1": "Rồi Thế Tôn gọi Tôn giả Ānanda: ",
  "dn16:2.1.2": "“Này Ānanda, hãy đến, chúng ta sẽ đi đến Koṭigāma.” ",
  "dn16:2.1.3": "“Vâng, bạch Thế Tôn,” Tôn giả Ānanda vâng đáp Thế Tôn. ",
  "dn16:2.1.4": "Rồi Thế Tôn cùng với đại chúng Tỳ-kheo đi đến Koṭigāma. ",
  "dn16:2.1.5": "Tại đó, Thế Tôn trú ở Koṭigāma. ",
  "dn16:2.2.1": "Tại đó, Thế Tôn gọi các tỳ-kheo: ",
  "dn16:2.2.2": "“Này các tỳ-kheo, do không thấu hiểu, không thể nhập bốn Thánh đế nên ta và các ông đã lang thang, trôi lăn trong luân hồi suốt thời gian dài như vậy. ",
  "dn16:2.2.3": "Bốn là những gì? ",
  "dn16:2.2.4": "Này các tỳ-kheo, do không thấu hiểu, không thể nhập Thánh đế về khổ nên ta và các ông đã lang thang, trôi lăn trong luân hồi suốt thời gian dài như vậy. ",
  "dn16:2.2.5": "Này các tỳ-kheo, do không thấu hiểu, không thể nhập Thánh đế về nguồn gốc của khổ nên ta và các ông đã lang thang, trôi lăn trong luân hồi suốt thời gian dài như vậy. ",
  "dn16:2.2.6": "Này các tỳ-kheo, do không thấu hiểu, không thể nhập Thánh đế về sự diệt khổ nên ta và các ông đã lang thang, trôi lăn trong luân hồi suốt thời gian dài như vậy. ",
  "dn16:2.2.7": "Này các tỳ-kheo, do không thấu hiểu, không thể nhập Thánh đế về con đường đưa đến sự diệt khổ nên ta và các ông đã lang thang, trôi lăn trong luân hồi suốt thời gian dài như vậy. ",
  "dn16:2.2.8": "Này các tỳ-kheo, đây là Thánh đế về khổ đã được thấu hiểu, đã được thể nhập; Thánh đế về nguồn gốc của khổ đã được thấu hiểu, đã được thể nhập; Thánh đế về sự diệt khổ đã được thấu hiểu, đã được thể nhập; Thánh đế về con đường đưa đến sự diệt khổ đã được thấu hiểu, đã được thể nhập; ái hữu đã bị đoạn tận, sự dẫn dắt đến hữu đã chấm dứt, nay không còn tái sinh nữa.” ",
  "dn16:2.3.1": "Thế Tôn đã nói như vậy. ",
  "dn16:2.3.2": "Nói xong, bậc Thiện Thệ lại nói thêm rằng: ",
  "dn16:2.3.3": "“Do không thấy đúng như thật ",
  "dn16:2.3.4": "bốn Thánh đế, ",
  "dn16:2.3.5": "nên đã trôi lăn suốt thời gian dài ",
  "dn16:2.3.6": "trong hết đời sống này đến đời sống khác. ",
  "dn16:2.3.7": "Nay những điều ấy đã được thấy, ",
  "dn16:2.3.8": "sự dẫn dắt đến hữu đã bị nhổ tận gốc; ",
  "dn16:2.3.9": "gốc rễ của khổ đã bị đoạn tận, ",
  "dn16:2.3.10": "nay không còn tái sinh nữa.” ",
  "dn16:2.4.1": "Tại đó nữa, khi trú ở Koṭigāma, Thế Tôn thường thuyết cho các tỳ-kheo bài pháp này: ",
  "dn16:2.4.2": "“Đây là giới, đây là định, đây là tuệ. ",
  "dn16:2.4.3": "Định được tu tập trên nền tảng giới có quả lớn, lợi ích lớn. ",
  "dn16:2.4.4": "Tuệ được tu tập trên nền tảng định có quả lớn, lợi ích lớn. ",
  "dn16:2.4.5": "Tâm được tu tập trên nền tảng tuệ thì được giải thoát chân chánh khỏi các lậu hoặc, đó là—",
  "dn16:2.4.6": "dục lậu, hữu lậu, vô minh lậu.” ",
  "dn16:2.5.0": "9. Hướng đến giác ngộ với pháp không còn trở lui",
  "dn16:2.5.1": "Bấy giờ, sau khi ở Koṭigāma tùy ý, Thế Tôn gọi tôn giả Ānanda: ",
  "dn16:2.5.2": "“Này Ānanda, hãy đi, chúng ta sẽ đến Nātikā.” ",
  "dn16:2.5.3": "“Vâng, bạch Thế Tôn,” tôn giả Ānanda vâng đáp Thế Tôn. ",
  "dn16:2.5.4": "Bấy giờ, Thế Tôn cùng với đại chúng tỳ-kheo đi đến Nātikā. ",
  "dn16:2.5.5": "Tại đó, ở Nātikā, Thế Tôn trú tại am Giñjakā.",
  "dn16:2.6.1": "Bấy giờ Tôn giả Ānanda đi đến chỗ Thế Tôn; sau khi đến, đảnh lễ Thế Tôn rồi ngồi xuống một bên. Ngồi xuống một bên, Tôn giả Ānanda bạch Thế Tôn như sau:",
  "dn16:2.6.2": "“Bạch Thế Tôn, vị tỳ-kheo tên Sāḷho đã mệnh chung tại Nātika, vị ấy đi về đâu, sanh thú thế nào?",
  "dn16:2.6.3": "Bạch Thế Tôn, vị tỳ-kheo-ni tên Nandā đã mệnh chung tại Nātika, vị ấy đi về đâu, sanh thú thế nào?",
  "dn16:2.6.4": "Bạch Thế Tôn, nam cư sĩ tên Sudatto đã mệnh chung tại Nātika, vị ấy đi về đâu, sanh thú thế nào?",
  "dn16:2.6.5": "Bạch Thế Tôn, nữ cư sĩ tên Sujātā đã mệnh chung tại Nātika, vị ấy đi về đâu, sanh thú thế nào?",
  "dn16:2.6.6": "Bạch Thế Tôn, nam cư sĩ tên Kukkuṭo đã mệnh chung tại Nātika, vị ấy đi về đâu, sanh thú thế nào?",
  "dn16:2.6.7": "Bạch Thế Tôn, nam cư sĩ tên Kāḷimbo …",
  "dn16:2.6.8": "Bạch Thế Tôn, nam cư sĩ tên Nikaṭo …",
  "dn16:2.6.9": "Bạch Thế Tôn, nam cư sĩ tên Kaṭissaho …",
  "dn16:2.6.10": "Bạch Thế Tôn, nam cư sĩ tên Tuṭṭho …",
  "dn16:2.6.11": "Bạch Thế Tôn, nam cư sĩ tên Santuṭṭho …",
  "dn16:2.6.12": "Bạch Thế Tôn, nam cư sĩ tên Bhaddo …",
  "dn16:2.6.13": "Bạch Thế Tôn, nam cư sĩ tên Subhaddo đã mệnh chung tại Nātika, vị ấy đi về đâu, sanh thú thế nào?”",
  "dn16:2.7.1": "“Này Ānanda, tỳ-kheo Sāḷho do đoạn tận các lậu hoặc, đã tự mình với thắng trí chứng ngộ, ngay trong hiện tại an trú trong tâm giải thoát vô lậu, tuệ giải thoát.",
  "dn16:2.7.2": "Này Ānanda, tỳ-kheo-ni Nandā do đoạn tận năm hạ phần kiết sử, đã hóa sanh, tại đó nhập Niết-bàn, không còn trở lui từ thế giới ấy.",
  "dn16:2.7.3": "Này Ānanda, nam cư sĩ Sudatto do đoạn tận ba kiết sử, làm mỏng tham, sân, si, là bậc Nhất lai, chỉ còn trở lại thế gian này một lần nữa rồi sẽ chấm dứt khổ đau.",
  "dn16:2.7.4": "Này Ānanda, nữ cư sĩ Sujātā do đoạn tận ba kiết sử, là bậc Dự lưu, không còn rơi vào đọa xứ, nhất định hướng đến giác ngộ.",
  "dn16:2.7.5": "Này Ānanda, nam cư sĩ Kukkuṭo do đoạn tận năm hạ phần kiết sử, đã hóa sanh, tại đó nhập Niết-bàn, không còn trở lui từ thế giới ấy.",
  "dn16:2.7.6": "Này Ānanda, nam cư sĩ Kāḷimbo …",
  "dn16:2.7.7": "Này Ānanda, nam cư sĩ Nikaṭo …",
  "dn16:2.7.8": "Này Ānanda, nam cư sĩ Kaṭissaho …",
  "dn16:2.7.9": "Này Ānanda, nam cư sĩ Tuṭṭho …",
  "dn16:2.7.10": "Này Ānanda, nam cư sĩ Santuṭṭho …",
  "dn16:2.7.11": "Này Ānanda, nam cư sĩ Bhaddo …",
  "dn16:2.7.12": "Này Ānanda, nam cư sĩ Subhaddo do đoạn tận năm hạ phần kiết sử, đã hóa sanh, tại đó nhập Niết-bàn, không còn trở lui từ thế giới ấy.",
  "dn16:2.7.13": "Này Ānanda, hơn năm mươi nam cư sĩ ở Nātika đã mệnh chung; do đoạn tận năm hạ phần kiết sử, họ đã hóa sanh, tại đó nhập Niết-bàn, không còn trở lui từ thế giới ấy.",
  "dn16:2.7.14": "Này Ānanda, hơn chín mươi nam cư sĩ ở Nātika đã mệnh chung; do đoạn tận ba kiết sử, làm mỏng tham, sân, si, họ là bậc Nhất lai, chỉ còn trở lại thế gian này một lần nữa rồi sẽ chấm dứt khổ đau.",
  "dn16:2.7.15": "Này Ānanda, hơn năm trăm nam cư sĩ ở Nātika đã mệnh chung; do đoạn tận ba kiết sử, họ là bậc Dự lưu, không còn rơi vào đọa xứ, nhất định hướng đến giác ngộ.",
  "dn16:2.8.0": "10. Pháp môn gương Pháp",
  "dn16:2.8.1": "Này Ānanda, việc một con người phải chết không có gì lạ.",
  "dn16:2.8.2": "Chính vào lúc ấy, sau khi Như Lai đã qua đời, các ông sẽ đến hỏi về ý nghĩa này; đó là sự phiền nhiễu đối với Như Lai, này Ānanda.",
  "dn16:2.8.3": "Vì vậy, này Ānanda, Ta sẽ thuyết pháp môn gọi là gương pháp, nhờ đầy đủ pháp môn ấy, vị Thánh đệ tử nếu muốn có thể tự mình tuyên bố về mình rằng:",
  "dn16:2.8.4": "‘Ta đã đoạn tận địa ngục, đã đoạn tận loài bàng sinh, đã đoạn tận cảnh giới ngạ quỷ, đã đoạn tận ác đạo, khổ cảnh, đọa xứ; ta là bậc Nhập lưu, không còn pháp phải đọa lạc, đã được quyết định, hướng đến giác ngộ.’",
  "dn16:2.9.1": "Và này Ānanda, pháp môn gương pháp ấy là gì, nhờ đầy đủ pháp môn ấy, vị Thánh đệ tử nếu muốn có thể tự mình tuyên bố về mình rằng:",
  "dn16:2.9.2": "‘Ta đã đoạn tận địa ngục, đã đoạn tận loài bàng sinh, đã đoạn tận cảnh giới ngạ quỷ, đã đoạn tận ác đạo, khổ cảnh, đọa xứ; ta là bậc Nhập lưu, không còn pháp phải đọa lạc, đã được quyết định, hướng đến giác ngộ’?",
  "dn16:2.9.3": "Ở đây, này Ānanda, vị Thánh đệ tử thành tựu lòng tịnh tín bất động đối với Phật:",
  "dn16:2.9.4": "‘Thế Tôn ấy là bậc A-la-hán, Chánh Đẳng Giác, đầy đủ minh và hạnh, Thiện Thệ, bậc hiểu biết thế gian, bậc điều ngự vô thượng đối với những người đáng được điều phục, bậc Đạo Sư của chư thiên và loài người, là Phật, là Thế Tôn.’",
  "dn16:2.9.5": "Thành tựu lòng tịnh tín bất động đối với Pháp:",
  "dn16:2.9.6": "‘Pháp do Thế Tôn khéo thuyết, thiết thực hiện tại, không bị thời gian chi phối, đến để mà thấy, có khả năng hướng thượng, được người trí tự mình giác hiểu.’",
  "dn16:2.9.7": "Thành tựu lòng tịnh tín bất động đối với Tăng:",
  "dn16:2.9.8": "‘Tăng chúng đệ tử của Thế Tôn là bậc khéo thực hành, là bậc thực hành ngay thẳng, là bậc thực hành đúng pháp, là bậc thực hành chân chánh; tức là bốn đôi, tám hạng người. Tăng chúng đệ tử của Thế Tôn ấy xứng đáng được cúng dường, xứng đáng được tiếp đón, xứng đáng được hiến cúng, xứng đáng được chắp tay cung kính, là ruộng phước vô thượng ở đời.’",
  "dn16:2.9.9": "Vị ấy thành tựu các giới được bậc Thánh ái kính, không sứt mẻ, không rạn nứt, không tỳ vết, không uế tạp, đưa đến giải thoát, được người trí tán thán, không bị chấp thủ, đưa đến định.",
  "dn16:2.9.10": "Này Ānanda, đó là pháp môn gương pháp ấy, nhờ đầy đủ pháp môn ấy, vị Thánh đệ tử nếu muốn có thể tự mình tuyên bố về mình rằng:",
  "dn16:2.9.11": "‘Ta đã đoạn tận địa ngục, đã đoạn tận loài bàng sinh, đã đoạn tận cảnh giới ngạ quỷ, đã đoạn tận ác đạo, khổ cảnh, đọa xứ; ta là bậc Nhập lưu, không còn pháp phải đọa lạc, đã được quyết định, hướng đến giác ngộ.’",
  "dn16:2.10.1": "Tại đó, khi trú ở Nātika, trong ngôi nhà gạch, Thế Tôn thường nói với các tỳ-kheo bài pháp thoại này:",
  "dn16:2.10.2": "“Đây là giới, đây là định, đây là tuệ.",
  "dn16:2.10.3": "Định được tu tập nhờ giới thì có quả lớn, có lợi ích lớn.",
  "dn16:2.10.4": "Tuệ được tu tập nhờ định thì có quả lớn, có lợi ích lớn.",
  "dn16:2.10.5": "Tâm được tu tập nhờ tuệ thì được giải thoát chân chánh khỏi các lậu hoặc, tức là—",
  "dn16:2.10.6": "dục lậu, hữu lậu, vô minh lậu.”",
  "dn16:2.10.7": "(…)",
  "dn16:2.11.1": "Rồi Thế Tôn, sau khi ở Nātika tùy ý bao lâu, liền gọi Tôn giả Ānanda:",
  "dn16:2.11.2": "“Này Ānanda, hãy đi, chúng ta sẽ đến Vesālī.”",
  "dn16:2.11.3": "“Vâng, bạch Thế Tôn,” Tôn giả Ānanda vâng đáp Thế Tôn.",
  "dn16:2.11.4": "Rồi Thế Tôn cùng với đại chúng tỳ-kheo đi đến Vesālī.",
  "dn16:2.11.5": "Tại đó, Thế Tôn trú ở Vesālī, trong rừng xoài của Ambapālī.",
  "dn16:2.12.1": "Tại đó, Thế Tôn gọi các tỳ-kheo:",
  "dn16:2.12.2": "“Này các tỳ-kheo, tỳ-kheo hãy sống chánh niệm, tỉnh giác,",
  "dn16:2.12.3": "đó là lời giáo huấn của Ta dành cho các ông.",
  "dn16:2.12.4": "Và này các tỳ-kheo, thế nào là tỳ-kheo có chánh niệm?",
  "dn16:2.12.5": "Ở đây, này các Tỳ-kheo, vị Tỳ-kheo sống quán thân trên thân, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời.",
  "dn16:2.12.6": "Đối với các cảm thọ, vị ấy sống quán cảm thọ …",
  "dn16:2.12.7": "Đối với tâm, vị ấy sống quán tâm …",
  "dn16:2.12.8": "Đối với các pháp, vị ấy sống quán pháp, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời.",
  "dn16:2.12.9": "Như vậy, này các Tỳ-kheo, vị Tỳ-kheo là người có chánh niệm.",
  "dn16:2.13.1": "Và này các Tỳ-kheo, thế nào là vị Tỳ-kheo có tỉnh giác?",
  "dn16:2.13.2": "Ở đây, này các Tỳ-kheo, vị Tỳ-kheo khi đi tới đi lui đều làm với tỉnh giác, khi nhìn thẳng nhìn quanh đều làm với tỉnh giác, khi co tay duỗi tay đều làm với tỉnh giác, khi mang y tăng-già-lê, bình bát và y phục đều làm với tỉnh giác, khi ăn, uống, nhai, nếm đều làm với tỉnh giác, khi đại tiện tiểu tiện đều làm với tỉnh giác, khi đi, đứng, ngồi, nằm, thức, nói, im lặng đều làm với tỉnh giác.",
  "dn16:2.13.3": "Như vậy, này các Tỳ-kheo, vị Tỳ-kheo là người có tỉnh giác.",
  "dn16:2.13.4": "Này các Tỳ-kheo, vị Tỳ-kheo hãy sống chánh niệm, tỉnh giác,",
  "dn16:2.13.5": "đó là lời giáo huấn của Ta dành cho các ông.”",
  "dn16:2.14.0": "11. Kỹ nữ Ambapālī",
  "dn16:2.14.1": "Kỹ nữ Ambapālī nghe rằng: “Đức Thế Tôn được biết là đã đến Vesāli, hiện đang trú tại Vesāli trong vườn xoài của ta.”",
  "dn16:2.14.2": "Bấy giờ, kỹ nữ Ambapālī cho thắng những cỗ xe tốt đẹp, rồi lên một cỗ xe tốt đẹp, cùng những cỗ xe tốt đẹp đi ra khỏi Vesāli. Nàng đi đến khu vườn của mình.",
  "dn16:2.14.3": "Đi xe đến chỗ nào xe có thể đi được, rồi xuống xe và đi bộ đến chỗ Đức Thế Tôn; đến nơi, sau khi đảnh lễ Đức Thế Tôn, nàng ngồi xuống một bên.",
  "dn16:2.14.4": "Khi kỹ nữ Ambapālī ngồi xuống một bên, Đức Thế Tôn thuyết pháp thoại cho nàng, khiến nàng hiểu rõ, khuyến khích, làm phấn chấn, làm hoan hỷ.",
  "dn16:2.14.5": "Bấy giờ, kỹ nữ Ambapālī, sau khi được Đức Thế Tôn thuyết pháp thoại khiến hiểu rõ, khuyến khích, làm phấn chấn, làm hoan hỷ, bạch Đức Thế Tôn rằng:",
  "dn16:2.14.6": "“Bạch Thế Tôn, xin Đức Thế Tôn nhận lời thọ thực ngày mai tại chỗ con, cùng với chúng Tỳ-kheo.”",
  "dn16:2.14.7": "Đức Thế Tôn im lặng nhận lời.",
  "dn16:2.14.8": "Bấy giờ, kỹ nữ Ambapālī, biết Đức Thế Tôn đã nhận lời, liền từ chỗ ngồi đứng dậy, đảnh lễ Đức Thế Tôn, đi nhiễu bên phải rồi ra về.",
  "dn16:2.15.1": "Các Licchavī ở Vesāli nghe rằng: “Đức Thế Tôn được biết là đã đến Vesāli, hiện đang trú tại Vesāli trong vườn Ambapālī.”",
  "dn16:2.15.2": "Bấy giờ, các Licchavī ấy cho thắng những cỗ xe tốt đẹp, rồi lên những cỗ xe tốt đẹp, cùng những cỗ xe tốt đẹp đi ra khỏi Vesāli.",
  "dn16:2.15.3": "Ở đó, một số Licchavī màu xanh, sắc xanh, y phục xanh, trang sức xanh; một số Licchavī màu vàng, sắc vàng, y phục vàng, trang sức vàng; một số Licchavī màu đỏ, sắc đỏ, y phục đỏ, trang sức đỏ; một số Licchavī màu trắng, sắc trắng, y phục trắng, trang sức trắng.",
  "dn16:2.16.1": "Bấy giờ, kỹ nữ Ambapālī cho xe mình chạy sát xe, bánh xe sát bánh xe, ách xe sát ách xe với các Licchavī trẻ tuổi.",
  "dn16:2.16.2": "Bấy giờ, các Licchavī ấy nói với kỹ nữ Ambapālī rằng:",
  "dn16:2.16.3": "“Này Ambapālī, sao cô lại cho xe mình chạy sát xe, bánh xe sát bánh xe, ách xe sát ách xe với các Licchavī trẻ tuổi vậy?”",
  "dn16:2.16.4": "“Thưa các công tử, vì con đã thỉnh Đức Thế Tôn thọ thực ngày mai cùng với chúng Tỳ-kheo.”",
  "dn16:2.16.5": "“Này Ambapālī, hãy nhường bữa ăn ấy cho chúng tôi với giá một trăm ngàn.”",
  "dn16:2.16.6": "“Thưa các công tử, dù các vị có cho con cả thành Vesāli cùng vùng phụ cận, con cũng không nhường bữa ăn ấy.”",
  "dn16:2.16.7": "Bấy giờ, các Licchavī búng ngón tay:",
  "dn16:2.16.8": "“Thật chúng ta đã bị Ambakā thắng rồi! Thật chúng ta đã bị Ambakā thắng rồi!”",
  "dn16:2.16.9": "Bấy giờ, những người Licchavi ấy đi đến rừng xoài của Ambapālī.",
  "dn16:2.17.1": "Thế Tôn thấy những người Licchavi ấy từ đằng xa đang đi đến.",
  "dn16:2.17.2": "Thấy vậy, Ngài gọi các tỳ-kheo:",
  "dn16:2.17.3": "“Này các tỳ-kheo, những tỳ-kheo nào chưa từng thấy chư thiên cõi Tāvatiṁsa, hãy nhìn hội chúng Licchavi;",
  "dn16:2.17.4": "này các tỳ-kheo, hãy ngắm hội chúng Licchavi;",
  "dn16:2.17.5": "này các tỳ-kheo, hãy quan sát kỹ hội chúng Licchavi—",
  "dn16:2.17.6": "giống như chư thiên cõi Tāvatiṁsa.”",
  "dn16:2.18.1": "Bấy giờ, những người Licchavi ấy đi xe đến chỗ nào xe còn đi được, rồi xuống xe và đi bộ đến chỗ Thế Tôn; đến nơi, họ đảnh lễ Thế Tôn rồi ngồi xuống một bên.",
  "dn16:2.18.2": "Khi những người Licchavi ấy ngồi xuống một bên, Thế Tôn thuyết pháp, chỉ bày, khuyến khích, làm phấn chấn, làm hoan hỷ họ bằng lời pháp.",
  "dn16:2.18.3": "Bấy giờ, những người Licchavi ấy, sau khi được Thế Tôn chỉ bày, khuyến khích, làm phấn chấn, làm hoan hỷ bằng lời pháp, bạch Thế Tôn:",
  "dn16:2.18.4": "“Bạch Thế Tôn, xin Thế Tôn nhận lời thọ trai ngày mai cùng với chúng tỳ-kheo.”",
  "dn16:2.18.5": "Bấy giờ, Thế Tôn nói với những người Licchavi ấy:",
  "dn16:2.18.6": "“Này các Licchavi, ta đã nhận lời thọ trai ngày mai của kỹ nữ Ambapālī rồi.”",
  "dn16:2.18.7": "Bấy giờ, những người Licchavi ấy búng ngón tay:",
  "dn16:2.18.8": "“Than ôi, chúng ta đã bị Ambakā thắng rồi, chúng ta đã bị Ambakā qua mặt rồi!”",
  "dn16:2.18.9": "Bấy giờ, những người Licchavi ấy hoan hỷ tán thán lời Thế Tôn dạy, rồi từ chỗ ngồi đứng dậy, đảnh lễ Thế Tôn, đi nhiễu bên phải và ra về.",
  "dn16:2.19.1": "Bấy giờ, kỹ nữ Ambapālī sau khi đêm ấy đã qua, cho chuẩn bị tại khu vườn của mình các món ăn thượng vị, rồi cho báo giờ đến Thế Tôn:",
  "dn16:2.19.2": "“Bạch Thế Tôn, đã đến giờ, bữa ăn đã chuẩn bị xong.”",
  "dn16:2.19.3": "Bấy giờ, vào buổi sáng, Thế Tôn đắp y, cầm y bát, cùng với chúng tỳ-kheo đi đến nhà của kỹ nữ Ambapālī; đến nơi, Ngài ngồi xuống chỗ ngồi đã được dọn sẵn.",
  "dn16:2.19.4": "Bấy giờ, kỹ nữ Ambapālī tự tay dâng cúng và làm cho chúng tỳ-kheo có Đức Phật đứng đầu được thỏa mãn với các món ăn thượng vị.",
  "dn16:2.19.5": "Bấy giờ, kỹ nữ Ambapālī, sau khi Thế Tôn dùng bữa xong và đã cất tay khỏi bát, lấy một ghế thấp khác rồi ngồi xuống một bên.",
  "dn16:2.19.6": "Khi ngồi xuống một bên, kỹ nữ Ambapālī bạch Thế Tôn:",
  "dn16:2.19.7": "“Bạch Thế Tôn, con xin cúng dường khu vườn này đến chúng tỳ-kheo có Đức Phật đứng đầu.”",
  "dn16:2.19.8": "Thế Tôn nhận khu vườn.",
  "dn16:2.19.9": "Bấy giờ, Thế Tôn dùng lời pháp chỉ bày, khuyến khích, làm phấn chấn, làm hoan hỷ kỹ nữ Ambapālī, rồi từ chỗ ngồi đứng dậy ra đi.",
  "dn16:2.20.1": "Tại đó, khi trú ở Vesāli, trong rừng xoài của Ambapālī, Thế Tôn thường nói với các tỳ-kheo bài pháp này:",
  "dn16:2.20.2": "“Đây là giới, đây là định, đây là tuệ.",
  "dn16:2.20.3": "Định được tu tập trên nền tảng giới thì có quả lớn, có lợi ích lớn.",
  "dn16:2.20.4": "Tuệ được tu tập trên nền tảng định thì có quả lớn, có lợi ích lớn.",
  "dn16:2.20.5": "Tâm được tu tập trên nền tảng tuệ thì được giải thoát chân chánh khỏi các lậu hoặc, đó là—",
  "dn16:2.20.6": "lậu hoặc do dục, lậu hoặc do hữu, lậu hoặc do vô minh.”",
  "dn16:2.21.0": "12. Đi đến Veḷuvagāmaka để an cư mùa mưa",
  "dn16:2.21.1": "Bấy giờ, sau khi trú tại vườn xoài của Ambapālī tùy theo ý thích, Thế Tôn gọi Tôn giả Ānanda:",
  "dn16:2.21.2": "“Này Ānanda, hãy đi, chúng ta sẽ đến Veḷuvagāmaka.”",
  "dn16:2.21.3": "“Vâng, bạch Thế Tôn,” Tôn giả Ānanda vâng đáp Thế Tôn.",
  "dn16:2.21.4": "Bấy giờ, Thế Tôn cùng với đại chúng Tỳ-kheo đi đến Veḷuvagāmaka.",
  "dn16:2.21.5": "Tại đó, Thế Tôn trú ở Veḷuvagāmaka.",
  "dn16:2.22.1": "Tại đó, Thế Tôn gọi các Tỳ-kheo:",
  "dn16:2.22.2": "“Này các Tỳ-kheo, các ông hãy đi an cư mùa mưa quanh vùng Vesālī, nơi nào có bạn bè, người quen, hay chỗ đã được mời.",
  "dn16:2.22.3": "Còn Ta sẽ an cư mùa mưa ngay tại đây, ở Veḷuvagāmaka.”",
  "dn16:2.22.4": "“Vâng, bạch Thế Tôn,” các Tỳ-kheo ấy vâng lời Thế Tôn rồi đi an cư mùa mưa quanh vùng Vesālī, nơi nào có bạn bè, người quen, hay chỗ đã được mời.",
  "dn16:2.22.5": "Còn Thế Tôn an cư mùa mưa ngay tại đó, ở Veḷuvagāmaka.",
  "dn16:2.23.1": "Bấy giờ, khi Thế Tôn đã an cư mùa mưa, một cơn bệnh dữ dội phát sinh, những cảm thọ đau đớn dữ dội khởi lên, gần đến cái chết.",
  "dn16:2.23.2": "Nhưng Thế Tôn chánh niệm tỉnh giác, chịu đựng chúng mà không bị dao động.",
  "dn16:2.23.3": "Bấy giờ, Thế Tôn nghĩ rằng:",
  "dn16:2.23.4": "“Thật không thích hợp cho Ta nếu chưa từ biệt các thị giả, chưa cáo biệt Tăng chúng mà nhập Niết-bàn.",
  "dn16:2.23.5": "Hay là Ta dùng tinh tấn đẩy lui cơn bệnh này, duy trì mạng sống mà trú lại.”",
  "dn16:2.24.1": "Bấy giờ, Thế Tôn dùng tinh tấn đẩy lui cơn bệnh ấy, duy trì mạng sống mà trú lại.",
  "dn16:2.24.2": "Rồi cơn bệnh ấy của Thế Tôn lắng dịu.",
  "dn16:2.24.3": "Bấy giờ, Thế Tôn khỏi bệnh, không bao lâu sau khi ra khỏi bệnh, từ chỗ ở bước ra và ngồi xuống trên chỗ ngồi đã dọn sẵn trong bóng mát phía sau tịnh xá.",
  "dn16:2.24.4": "Bấy giờ, Tôn giả Ānanda đi đến chỗ Thế Tôn; đến nơi, đảnh lễ Thế Tôn rồi ngồi xuống một bên. Ngồi xuống một bên, Tôn giả Ānanda bạch Thế Tôn:",
  "dn16:2.24.5": "“Bạch Thế Tôn, con thấy Thế Tôn đã dễ chịu; con thấy Thế Tôn đã kham nhẫn được. Nhưng, bạch Thế Tôn, thân con như bị say mê rã rời, các phương hướng không hiện rõ với con, các pháp cũng không hiện ra với con vì bệnh của Thế Tôn.",
  "dn16:2.24.6": "Tuy vậy, bạch Thế Tôn, con vẫn còn chút an ủi rằng:",
  "dn16:2.24.7": "‘Thế Tôn sẽ chưa nhập Niết-bàn, chừng nào Thế Tôn chưa nói điều gì liên hệ đến Tăng chúng.’”",
  "dn16:2.25.1": "“Này Ānanda, Tăng chúng còn mong đợi gì nơi Ta?",
  "dn16:2.25.2": "Này Ānanda, Ta đã thuyết pháp không phân biệt trong ngoài.",
  "dn16:2.25.3": "Này Ānanda, đối với các pháp, Như Lai không có nắm tay của vị thầy.",
  "dn16:2.25.4": "Này Ānanda, nếu có ai nghĩ rằng:",
  "dn16:2.25.5": "‘Ta sẽ lãnh đạo Tăng chúng’ hay ‘Tăng chúng thuộc về Ta’, thì người ấy có thể nói điều gì đó liên hệ đến Tăng chúng.",
  "dn16:2.25.6": "Nhưng này Ānanda, Như Lai không nghĩ như vậy:",
  "dn16:2.25.7": "‘Ta sẽ chăm nom Tăng chúng tỳ-kheo’ hay ‘Tăng chúng tỳ-kheo là do ta chỉ dạy’.",
  "dn16:2.25.8": "Này Ānanda, Như Lai chỉ một lần nào đó mới nói điều gì liên hệ đến Tăng chúng tỳ-kheo.",
  "dn16:2.25.9": "Còn nay, này Ānanda, ta đã già nua, cao tuổi, bậc lão thành, đã đi đến chặng cuối của đời người.",
  "dn16:2.25.10": "Nay ta đã tám mươi tuổi.",
  "dn16:2.25.11": "Ví như, này Ānanda, một cỗ xe cũ nát phải nhờ chằng buộc mới còn vận hành được;",
  "dn16:2.25.12": "cũng vậy, này Ānanda, thân của Như Lai, ta nghĩ, cũng được duy trì nhờ sự chằng buộc.",
  "dn16:2.25.13": "Này Ānanda, vào lúc nào Như Lai không tác ý đến mọi tướng, do sự diệt trừ một số cảm thọ, chứng và an trú trong vô tướng tâm định, thì vào lúc ấy thân của Như Lai được an ổn hơn.",
  "dn16:2.26.1": "Vậy nên, này Ānanda, hãy sống tự mình là ngọn đèn cho mình, tự mình là chỗ nương tựa cho mình, không nương tựa một gì khác; lấy Pháp làm ngọn đèn, lấy Pháp làm chỗ nương tựa, không nương tựa một gì khác.",
  "dn16:2.26.2": "Và này Ānanda, thế nào là vị tỳ-kheo sống tự mình là ngọn đèn cho mình, tự mình là chỗ nương tựa cho mình, không nương tựa một gì khác; lấy Pháp làm ngọn đèn, lấy Pháp làm chỗ nương tựa, không nương tựa một gì khác?",
  "dn16:2.26.3": "Ở đây, này Ānanda, vị tỳ-kheo quán thân trên thân, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời.",
  "dn16:2.26.4": "Trên các cảm thọ …",
  "dn16:2.26.5": "Trên tâm …",
  "dn16:2.26.6": "Trên các pháp, vị ấy quán pháp trên các pháp, nhiệt tâm, tỉnh giác, chánh niệm, nhiếp phục tham ưu ở đời.",
  "dn16:2.26.7": "Như vậy, này Ānanda, vị tỳ-kheo sống tự mình là ngọn đèn cho mình, tự mình là chỗ nương tựa cho mình, không nương tựa một gì khác; lấy Pháp làm ngọn đèn, lấy Pháp làm chỗ nương tựa, không nương tựa một gì khác.",
  "dn16:2.26.8": "Này Ānanda, bất cứ ai hiện nay hay sau khi ta diệt độ mà sống tự mình là ngọn đèn cho mình, tự mình là chỗ nương tựa cho mình, không nương tựa một gì khác; lấy Pháp làm ngọn đèn, lấy Pháp làm chỗ nương tựa, không nương tựa một gì khác, thì những vị tỳ-kheo ấy sẽ là bậc tối thượng trong hàng đệ tử của ta, nếu họ tha thiết học tập.”",
  "dn16:2.26.9": "Phần tụng đọc thứ hai.",
  "dn16:3.1.0": "13. Luận về tướng và ánh sáng báo hiệu",
  "dn16:3.1.1": "Bấy giờ, Thế Tôn vào buổi sáng đắp y, cầm bát và y, đi vào Vesālī để khất thực.",
  "dn16:3.1.2": "Sau khi đi khất thực ở Vesālī, dùng bữa xong, trên đường từ khất thực trở về, Ngài gọi Tôn giả Ānanda:",
  "dn16:3.1.3": "“Này Ānanda, hãy cầm tọa cụ,",
  "dn16:3.1.4": "chúng ta sẽ đi đến đền Cāpāla để nghỉ ban ngày.”",
  "dn16:3.1.5": "“Vâng, bạch Thế Tôn,” Tôn giả Ānanda vâng đáp Thế Tôn, cầm tọa cụ rồi đi theo sau lưng Thế Tôn.",
  "dn16:3.2.1": "Bấy giờ, Thế Tôn đi đến đền Cāpāla; đến nơi, Ngài ngồi xuống trên chỗ ngồi đã soạn sẵn.",
  "dn16:3.2.2": "Tôn giả Ānanda cũng đảnh lễ Thế Tôn rồi ngồi xuống một bên.",
  "dn16:3.2.3": "Khi Tôn giả Ānanda ngồi xuống một bên, Thế Tôn nói với Tôn giả như sau:",
  "dn16:3.2.4": "“Này Ānanda, Vesālī thật khả ái, đền Udena khả ái, đền Gotamaka khả ái, đền Sattamba khả ái, đền Bahuputta khả ái, đền Sārandada khả ái, đền Cāpāla khả ái.",
  "dn16:3.3.1": "Này Ānanda, bất cứ ai đã tu tập, làm cho sung mãn, làm thành cỗ xe, làm thành nền tảng, thiết lập vững chắc, thuần thục, khéo khởi sự bốn thần túc, người ấy nếu muốn có thể sống một kiếp hay phần còn lại của một kiếp.",
  "dn16:3.3.2": "Này Ānanda, Như Lai đã tu tập, làm cho sung mãn, làm thành cỗ xe, làm thành nền tảng, thiết lập vững chắc, thuần thục, khéo khởi sự bốn thần túc; nếu muốn, này Ānanda, Như Lai có thể sống một kiếp hay phần còn lại của một kiếp.”",
  "dn16:3.4.1": "Nhưng dù Thế Tôn đã làm dấu hiệu rõ ràng như vậy, đã phát ra ánh sáng báo hiệu rõ ràng như vậy, Tôn giả Ānanda vẫn không thể hiểu ra;",
  "dn16:3.4.2": "và đã không thỉnh cầu Thế Tôn:",
  "dn16:3.4.3": "“Bạch Thế Tôn, xin Thế Tôn hãy ở lại trọn một kiếp, xin bậc Thiện Thệ hãy ở lại trọn một kiếp vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, vì an lạc cho chư thiên và loài người”, nhưng tâm ông đã bị Ma vương chi phối.",
  "dn16:3.5.1": "Lần thứ hai nữa, Thế Tôn …",
  "dn16:3.5.2": "lần thứ ba nữa, Thế Tôn gọi Tôn giả Ānanda:",
  "dn16:3.5.3": "“Này Ānanda, Vesālī thật khả ái, đền Udena thật khả ái, đền Gotamaka thật khả ái, đền Sattamba thật khả ái, đền Bahuputta thật khả ái, đền Sārandada thật khả ái, đền Cāpāla thật khả ái.",
  "dn16:3.5.4": "Này Ānanda, bất cứ ai đã tu tập, làm cho sung mãn, làm thành cỗ xe, lấy làm nền tảng, thiết lập vững chắc, quen thuộc, khéo khởi sự bốn thần túc, người ấy nếu muốn có thể ở lại trọn một kiếp hay phần còn lại của một kiếp.",
  "dn16:3.5.5": "Này Ānanda, Như Lai đã tu tập, làm cho sung mãn, làm thành cỗ xe, lấy làm nền tảng, thiết lập vững chắc, quen thuộc, khéo khởi sự bốn thần túc; nếu muốn, này Ānanda, Như Lai có thể ở lại trọn một kiếp hay phần còn lại của một kiếp.”",
  "dn16:3.5.6": "Nhưng dù Thế Tôn đã làm ra dấu hiệu rõ ràng như vậy, đã phát ra ánh sáng rõ ràng như vậy, Tôn giả Ānanda vẫn không thể hiểu được;",
  "dn16:3.5.7": "không thỉnh cầu Thế Tôn:",
  "dn16:3.5.8": "“Bạch Thế Tôn, xin Thế Tôn hãy ở lại trọn một kiếp, xin bậc Thiện Thệ hãy ở lại trọn một kiếp vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, vì an lạc cho chư thiên và loài người”, vì tâm ông đã bị Ma vương chi phối.",
  "dn16:3.6.1": "Bấy giờ, Thế Tôn bảo Tôn giả Ānanda:",
  "dn16:3.6.2": "“Này Ānanda, ông hãy đi",
  "dn16:3.6.3": "đến nơi nào ông thấy là hợp thời.”",
  "dn16:3.6.4": "“Vâng, bạch Thế Tôn”, Tôn giả Ānanda vâng đáp Thế Tôn, từ chỗ ngồi đứng dậy, đảnh lễ Thế Tôn, đi nhiễu bên phải rồi ngồi xuống dưới một gốc cây không xa.",
  "dn16:3.7.0": "14. Câu chuyện Ma vương thỉnh cầu",
  "dn16:3.7.1": "Bấy giờ, Ma vương Ác, sau khi Tôn giả Ānanda vừa đi không bao lâu, đi đến chỗ Thế Tôn; đến rồi đứng sang một bên. Đứng sang một bên, Ma vương Ác bạch Thế Tôn rằng:",
  "dn16:3.7.2": "“Bạch Thế Tôn, nay xin Thế Tôn nhập Niết-bàn, xin bậc Thiện Thệ nhập Niết-bàn, nay đã đến thời Thế Tôn nhập Niết-bàn.",
  "dn16:3.7.3": "Bạch Thế Tôn, lời này đã được Thế Tôn nói ra:",
  "dn16:3.7.4": "‘Này Ác ma, Ta sẽ chưa nhập Niết-bàn chừng nào các Tỳ-kheo đệ tử của Ta chưa trở thành những người thông suốt, được huấn luyện, vững vàng, đa văn, gìn giữ Chánh pháp, thực hành đúng pháp và tùy pháp, thực hành chân chánh, sống thuận pháp, sau khi học thọ giáo pháp của bậc Đạo sư mình sẽ có thể trình bày, thuyết giảng, chỉ bày, thiết lập, khai mở, phân tích, làm cho rõ ràng, và khi có tà thuyết khởi lên sẽ khéo bác bỏ đúng pháp, rồi thuyết giảng Chánh pháp có thần biến’.",
  "dn16:3.8.1": "Nhưng nay, bạch Thế Tôn, các Tỳ-kheo đệ tử của Thế Tôn đều là những người thông suốt, được huấn luyện, vững vàng, đa văn, gìn giữ Chánh pháp, thực hành đúng pháp và tùy pháp, thực hành chân chánh, sống thuận pháp; sau khi học thọ giáo pháp của bậc Đạo sư mình, họ trình bày, thuyết giảng, chỉ bày, thiết lập, khai mở, phân tích, làm cho rõ ràng, và khi có tà thuyết khởi lên, họ khéo bác bỏ đúng pháp, rồi thuyết giảng Chánh pháp có thần biến.",
  "dn16:3.8.2": "Bạch Thế Tôn, nay xin Thế Tôn nhập Niết-bàn, xin bậc Thiện Thệ nhập Niết-bàn, nay đã đến thời Thế Tôn nhập Niết-bàn.",
  "dn16:3.8.3": "Bạch Thế Tôn, lời này đã được Thế Tôn nói ra:",
  "dn16:3.8.4": "‘Này Ác ma, Ta sẽ chưa nhập Niết-bàn chừng nào các Tỳ-kheo-ni đệ tử của Ta chưa trở thành những người thông suốt, được huấn luyện, vững vàng, đa văn, gìn giữ Chánh pháp, thực hành đúng pháp và tùy pháp, thực hành chân chánh, sống thuận pháp, sau khi học thọ giáo pháp của bậc Đạo sư mình sẽ có thể trình bày, thuyết giảng, chỉ bày, thiết lập, khai mở, phân tích, làm cho rõ ràng, và khi có tà thuyết khởi lên sẽ khéo bác bỏ đúng pháp, rồi thuyết giảng Chánh pháp có thần biến’.",
  "dn16:3.8.5": "Nhưng nay, bạch Thế Tôn, các Tỳ-kheo-ni đệ tử của Thế Tôn đều là những người thông suốt, được huấn luyện, vững vàng, đa văn, gìn giữ Chánh pháp, thực hành đúng pháp và tùy pháp, thực hành chân chánh, sống thuận pháp; sau khi học thọ giáo pháp của bậc Đạo sư mình, họ trình bày, thuyết giảng, chỉ bày, thiết lập, khai mở, phân tích, làm cho rõ ràng, và khi có tà thuyết khởi lên, họ khéo bác bỏ đúng pháp, rồi thuyết giảng Chánh pháp có thần biến.",
  "dn16:3.8.6": "Bạch Thế Tôn, nay xin Thế Tôn nhập Niết-bàn, xin bậc Thiện Thệ nhập Niết-bàn, nay đã đến thời Thế Tôn nhập Niết-bàn.",
  "dn16:3.8.7": "Bạch Thế Tôn, lời này đã được Thế Tôn nói ra:",
  "dn16:3.8.8": "‘Này Ác ma, Ta sẽ chưa nhập Niết-bàn chừng nào các nam cư sĩ đệ tử của Ta chưa trở thành những người thông suốt, được huấn luyện, vững vàng, đa văn, gìn giữ Chánh pháp, thực hành đúng pháp và tùy pháp, thực hành chân chánh, sống thuận pháp, sau khi học thọ giáo pháp của bậc Đạo sư mình sẽ có thể trình bày, thuyết giảng, chỉ bày, thiết lập, khai mở, phân tích, làm cho rõ ràng, và khi có tà thuyết khởi lên sẽ khéo bác bỏ đúng pháp, rồi thuyết giảng Chánh pháp có thần biến’.",
  "dn16:3.8.9": "Nhưng nay, bạch Thế Tôn, các nam cư sĩ đệ tử của Thế Tôn đều là những người thông suốt, được huấn luyện, vững vàng, đa văn, gìn giữ Chánh pháp, thực hành đúng pháp và tùy pháp, thực hành chân chánh, sống thuận pháp; sau khi học thọ giáo pháp của bậc Đạo sư mình, họ trình bày, thuyết giảng, chỉ bày, thiết lập, khai mở, phân tích, làm cho rõ ràng, và khi có tà thuyết khởi lên, họ khéo bác bỏ đúng pháp, rồi thuyết giảng Chánh pháp có thần biến.",
  "dn16:3.8.10": "Bạch Thế Tôn, nay xin Thế Tôn nhập Niết-bàn, xin bậc Thiện Thệ nhập Niết-bàn, nay đã đến thời Thế Tôn nhập Niết-bàn.",
  "dn16:3.8.11": "Bạch Thế Tôn, lời này đã được Thế Tôn nói ra:",
  "dn16:3.8.12": "‘Này Ác ma, Ta sẽ chưa nhập Niết-bàn chừng nào các nữ cư sĩ đệ tử của Ta chưa trở thành những người thông suốt, được huấn luyện, vững vàng, đa văn, gìn giữ Chánh pháp, thực hành đúng pháp và tùy pháp, thực hành chân chánh, sống thuận pháp, sau khi học thọ giáo pháp của bậc Đạo sư mình sẽ có thể trình bày, thuyết giảng, chỉ bày, thiết lập, khai mở, phân tích, làm cho rõ ràng, và khi có tà thuyết khởi lên sẽ khéo bác bỏ đúng pháp, rồi thuyết giảng Chánh pháp có thần biến’.",
  "dn16:3.8.13": "Hiện nay, bạch Thế Tôn, các nữ cư sĩ đệ tử của Thế Tôn là những người thông đạt, được khéo huấn luyện, tự tin, nghe nhiều, thọ trì Chánh pháp, thực hành đúng pháp và tùy pháp, thực hành đúng đắn, sống thuận pháp; sau khi học thuộc giáo pháp của bậc Đạo sư mình, họ giảng giải, thuyết dạy, trình bày, thiết lập, khai mở, phân tích, làm cho rõ ràng; khi có tà thuyết khởi lên, họ khéo bác bỏ đúng theo Chánh pháp, rồi thuyết giảng Chánh pháp đầy đủ sức thuyết phục.",
  "dn16:3.8.14": "Vậy nay, bạch Thế Tôn, xin Thế Tôn nhập Niết-bàn, xin bậc Thiện Thệ nhập Niết-bàn; nay đã đến thời Thế Tôn nhập Niết-bàn.",
  "dn16:3.8.15": "Bạch Thế Tôn, lời này đã được Thế Tôn nói rằng:",
  "dn16:3.8.16": "‘Này Ác ma, Ta sẽ chưa nhập Niết-bàn chừng nào đời sống phạm hạnh này của Ta chưa được thành tựu, hưng thịnh, rộng lớn, phổ biến, đông người biết đến, lan rộng khắp nơi, được chư thiên và loài người khéo tuyên thuyết.’",
  "dn16:3.8.17": "Nhưng nay, bạch Thế Tôn, đời sống phạm hạnh của Thế Tôn đã thành tựu, hưng thịnh, rộng lớn, phổ biến, đông người biết đến, lan rộng khắp nơi, được chư thiên và loài người khéo tuyên thuyết.",
  "dn16:3.8.18": "Vậy nay, bạch Thế Tôn, xin Thế Tôn nhập Niết-bàn, xin bậc Thiện Thệ nhập Niết-bàn; nay đã đến thời Thế Tôn nhập Niết-bàn.”",
  "dn16:3.9.1": "Khi được nói vậy, Thế Tôn nói với Ma ác độc rằng:",
  "dn16:3.9.2": "“Này Ác ma, ngươi hãy yên tâm, chẳng bao lâu nữa Như Lai sẽ nhập Niết-bàn.",
  "dn16:3.9.3": "Sau ba tháng kể từ nay, Như Lai sẽ nhập Niết-bàn.”",
  "dn16:3.10.0": "15. Từ bỏ thọ hành",
  "dn16:3.10.1": "Bấy giờ, Thế Tôn tại đền Cāpāla, với chánh niệm tỉnh giác, đã từ bỏ thọ hành.",
  "dn16:3.10.2": "Khi Thế Tôn đã từ bỏ thọ hành, một trận đại địa chấn xảy ra, kinh hoàng, rợn tóc gáy; và trống trời cũng vang lên.",
  "dn16:3.10.3": "Bấy giờ, Thế Tôn, sau khi biết rõ ý nghĩa ấy, vào lúc ấy đã thốt lên lời cảm hứng này:",
  "dn16:3.10.4": "“Bậc Mâu-ni đã từ bỏ",
  "dn16:3.10.5": "hành hữu đưa đến tái sinh, dù cân lường hay không thể cân lường;",
  "dn16:3.10.6": "an trú nội tâm, khéo định tĩnh,",
  "dn16:3.10.7": "Ngài đã phá vỡ nó như phá tan một tấm giáp của sự hiện hữu.”",
  "dn16:3.11.0": "16. Nhân duyên của đại địa chấn",
  "dn16:3.11.1": "Bấy giờ, Tôn giả Ānanda nghĩ rằng:",
  "dn16:3.11.2": "“Thật kỳ diệu thay, thưa chư huynh, thật hy hữu thay, thưa chư huynh, trận đại địa chấn này lớn lao biết bao;",
  "dn16:3.11.3": "thật vô cùng lớn lao, trận đại địa chấn này kinh hoàng, rợn tóc gáy; và trống trời cũng vang lên.",
  "dn16:3.11.4": "Vậy nguyên nhân gì, duyên cớ gì khiến đại địa chấn lớn như vậy xuất hiện?”",
  "dn16:3.12.1": "Bấy giờ, Tôn giả Ānanda đi đến chỗ Thế Tôn,",
  "dn16:3.12.2": "sau khi đến, đảnh lễ Thế Tôn rồi ngồi xuống một bên.",
  "dn16:3.12.3": "Ngồi xuống một bên, Tôn giả Ānanda bạch Thế Tôn rằng:",
  "dn16:3.12.4": "“Thật kỳ diệu, bạch Thế Tôn, thật hy hữu, bạch Thế Tôn.",
  "dn16:3.12.5": "Bạch Thế Tôn, trận đại địa chấn này thật lớn lao;",
  "dn16:3.12.6": "bạch Thế Tôn, trận đại địa chấn này thật vô cùng lớn lao, kinh hoàng, rợn tóc gáy; và trống trời cũng vang lên.",
  "dn16:3.12.7": "Vậy nguyên nhân gì, duyên cớ gì khiến đại địa chấn lớn như vậy xuất hiện?”",
  "dn16:3.13.1": "“Này Ānanda, có tám nguyên nhân, tám duyên khiến đại địa chấn lớn xuất hiện.",
  "dn16:3.13.2": "Tám điều ấy là gì?",
  "dn16:3.13.3": "Này Ānanda, đại địa này được đặt trên nước, nước được đặt trên gió, gió ở trong hư không. Này Ānanda, có lúc những cơn gió lớn thổi lên. Khi những cơn gió lớn thổi, chúng làm nước dao động. Nước dao động làm đất rung chuyển.",
  "dn16:3.13.4": "Đây là nhân thứ nhất, duyên thứ nhất cho sự xuất hiện của một trận động đất lớn.",
  "dn16:3.14.1": "Lại nữa, này Ānanda, có vị sa-môn hay bà-la-môn có thần thông, đã đạt được tự tại tâm, hoặc một vị trời có đại thần lực, đại uy lực; vị ấy đã tu tập tưởng về đất là nhỏ hẹp, tưởng về nước là vô lượng. Vị ấy làm cho đất này rung động, chấn động, lay động mạnh, rung chuyển dữ dội.",
  "dn16:3.14.2": "Đây là nhân thứ hai, duyên thứ hai cho sự xuất hiện của một trận động đất lớn.",
  "dn16:3.15.1": "Lại nữa, này Ānanda, khi vị Bồ Tát từ chúng trời Tusita qua đời, tỉnh giác và chánh niệm đi vào thai mẹ, khi ấy đất này rung động, chấn động, lay động mạnh, rung chuyển dữ dội.",
  "dn16:3.15.2": "Đây là nhân thứ ba, duyên thứ ba cho sự xuất hiện của một trận động đất lớn.",
  "dn16:3.16.1": "Lại nữa, này Ānanda, khi vị Bồ Tát tỉnh giác và chánh niệm từ thai mẹ đi ra, khi ấy đất này rung động, chấn động, lay động mạnh, rung chuyển dữ dội.",
  "dn16:3.16.2": "Đây là nhân thứ tư, duyên thứ tư cho sự xuất hiện của một trận động đất lớn.",
  "dn16:3.17.1": "Lại nữa, này Ānanda, khi Như Lai chứng ngộ Vô thượng Chánh đẳng Chánh giác, khi ấy đất này rung động, chấn động, lay động mạnh, rung chuyển dữ dội.",
  "dn16:3.17.2": "Đây là nhân thứ năm, duyên thứ năm cho sự xuất hiện của một trận động đất lớn.",
  "dn16:3.18.1": "Lại nữa, này Ānanda, khi Như Lai chuyển vận bánh xe Pháp vô thượng, khi ấy đất này rung động, chấn động, lay động mạnh, rung chuyển dữ dội.",
  "dn16:3.18.2": "Đây là nhân thứ sáu, duyên thứ sáu cho sự xuất hiện của một trận động đất lớn.",
  "dn16:3.19.1": "Lại nữa, này Ānanda, khi Như Lai tỉnh giác và chánh niệm từ bỏ hành tướng thọ mạng, khi ấy đất này rung động, chấn động, lay động mạnh, rung chuyển dữ dội.",
  "dn16:3.19.2": "Đây là nhân thứ bảy, duyên thứ bảy cho sự xuất hiện của một trận động đất lớn.",
  "dn16:3.20.1": "Lại nữa, này Ānanda, khi Như Lai nhập Niết-bàn không còn dư y, khi ấy đất này rung động, chấn động, lay động mạnh, rung chuyển dữ dội.",
  "dn16:3.20.2": "Đây là nhân thứ tám, duyên thứ tám cho sự xuất hiện của một trận động đất lớn.",
  "dn16:3.20.3": "Này Ānanda, đó là tám nhân, tám duyên cho sự xuất hiện của một trận động đất lớn.",
  "dn16:3.21.0": "17. Tám hội chúng",
  "dn16:3.21.1": "Này Ānanda, có tám hội chúng này.",
  "dn16:3.21.2": "Tám hội chúng ấy là gì?",
  "dn16:3.21.3": "Hội chúng sát-đế-lỵ, hội chúng bà-la-môn, hội chúng gia chủ, hội chúng sa-môn, hội chúng chư thiên Tứ Đại Thiên Vương, hội chúng chư thiên Tam Thập Tam, hội chúng của Ma vương, hội chúng Phạm thiên.",
  "dn16:3.22.1": "Này Ānanda, Ta nhớ đã từng đến hàng trăm hội chúng sát-đế-lỵ.",
  "dn16:3.22.2": "Ở đó, Ta đã từng ngồi cùng, từng đàm luận và từng tham dự thảo luận.",
  "dn16:3.22.3": "Ở đó, sắc diện của họ thế nào thì sắc diện của Ta cũng thế ấy. Giọng nói của họ thế nào thì giọng nói của Ta cũng thế ấy.",
  "dn16:3.22.4": "Ta dùng pháp thoại để chỉ bày, khuyến khích, khích lệ, làm cho hoan hỷ.",
  "dn16:3.22.5": "Khi Ta đang nói, họ không biết:",
  "dn16:3.22.6": "‘Người đang nói này là ai, là chư thiên hay là loài người?’",
  "dn16:3.22.7": "Sau khi dùng pháp thoại để chỉ bày, khuyến khích, khích lệ, làm cho hoan hỷ, Ta biến mất.",
  "dn16:3.22.8": "Và khi Ta đã biến mất, họ cũng không biết:",
  "dn16:3.22.9": "‘Vị này đã biến mất là chư thiên hay loài người?’",
  "dn16:3.23.1": "Này Ānanda, Ta nhớ rõ đã từng đến với hàng trăm hội chúng Bà-la-môn…",
  "dn16:3.23.2": "hội chúng gia chủ…",
  "dn16:3.23.3": "hội chúng sa-môn…",
  "dn16:3.23.4": "hội chúng Tứ Đại Thiên Vương…",
  "dn16:3.23.5": "hội chúng cõi trời Ba Mươi Ba…",
  "dn16:3.23.6": "hội chúng Ma vương…",
  "dn16:3.23.7": "hội chúng Phạm thiên.",
  "dn16:3.23.8": "Ở đó, Ta đã từng ngồi cùng, từng đàm luận và từng tham dự thảo luận với họ.",
  "dn16:3.23.9": "Ở đó, sắc diện của họ thế nào thì sắc diện của Ta cũng thế ấy.",
  "dn16:3.23.10": "Giọng nói của họ thế nào thì giọng nói của Ta cũng thế ấy.",
  "dn16:3.23.11": "Bằng lời nói hợp pháp, Ta chỉ bày, khuyến khích, làm phấn chấn, làm hoan hỷ.",
  "dn16:3.23.12": "Khi Ta đang nói, họ không biết:",
  "dn16:3.23.13": "‘Người đang nói này là chư thiên hay loài người?’",
  "dn16:3.23.14": "Sau khi dùng lời nói hợp pháp để chỉ bày, khuyến khích, làm phấn chấn, làm hoan hỷ, Ta biến mất.",
  "dn16:3.23.15": "Khi Ta đã biến mất, họ không biết:",
  "dn16:3.23.16": "‘Vị này đã biến mất là chư thiên hay loài người?’",
  "dn16:3.23.17": "Này Ānanda, đó là tám hội chúng.",
  "dn16:3.24.0": "18. Tám thắng xứ",
  "dn16:3.24.1": "Này Ānanda, có tám thắng xứ này.",
  "dn16:3.24.2": "Tám là những gì?",
  "dn16:3.25.1": "Một người có tưởng về sắc ở nội thân, thấy các sắc ở bên ngoài, nhỏ, đẹp hoặc xấu.",
  "dn16:3.25.2": "Người ấy có tưởng như sau: ‘Sau khi thắng vượt chúng, ta biết và ta thấy.’",
  "dn16:3.25.3": "Đây là thắng xứ thứ nhất.",
  "dn16:3.26.1": "Một người có tưởng về sắc ở nội thân, thấy các sắc ở bên ngoài, vô lượng, đẹp hoặc xấu.",
  "dn16:3.26.2": "Người ấy có tưởng như sau: ‘Sau khi thắng vượt chúng, ta biết và ta thấy.’",
  "dn16:3.26.3": "Đây là thắng xứ thứ hai.",
  "dn16:3.27.1": "Một người không có tưởng về sắc ở nội thân, thấy các sắc ở bên ngoài, nhỏ, đẹp hoặc xấu.",
  "dn16:3.27.2": "Người ấy có tưởng như sau: ‘Sau khi thắng vượt chúng, ta biết và ta thấy.’",
  "dn16:3.27.3": "Đây là thắng xứ thứ ba.",
  "dn16:3.28.1": "Vị ấy bên trong không có tưởng về sắc, thấy các sắc bên ngoài, hữu lượng hay vô lượng, đẹp hay xấu.",
  "dn16:3.28.2": "Vị ấy có tưởng như sau: ‘Sau khi thắng tri chúng, ta biết, ta thấy.’",
  "dn16:3.28.3": "Đây là thắng xứ thứ tư.",
  "dn16:3.29.1": "Vị ấy bên trong không có tưởng về sắc, thấy các sắc bên ngoài màu xanh, có màu xanh, hiện ra màu xanh, chiếu ánh xanh.",
  "dn16:3.29.2": "Ví như hoa lanh màu xanh, có màu xanh, hiện ra màu xanh, chiếu ánh xanh. Hoặc như tấm vải Ba-la-nại được dệt láng cả hai mặt, màu xanh, có màu xanh, hiện ra màu xanh, chiếu ánh xanh.",
  "dn16:3.29.3": "Cũng vậy, vị ấy bên trong không có tưởng về sắc, thấy các sắc bên ngoài màu xanh, có màu xanh, hiện ra màu xanh, chiếu ánh xanh.",
  "dn16:3.29.4": "Vị ấy có tưởng như sau: ‘Sau khi thắng tri chúng, ta biết, ta thấy.’",
  "dn16:3.29.5": "Đây là thắng xứ thứ năm.",
  "dn16:3.30.1": "Vị ấy bên trong không có tưởng về sắc, thấy các sắc bên ngoài màu vàng, có màu vàng, hiện ra màu vàng, chiếu ánh vàng.",
  "dn16:3.30.2": "Ví như hoa kim hương màu vàng, có màu vàng, hiện ra màu vàng, chiếu ánh vàng. Hoặc như tấm vải Ba-la-nại được dệt láng cả hai mặt, màu vàng, có màu vàng, hiện ra màu vàng, chiếu ánh vàng.",
  "dn16:3.30.3": "Cũng vậy, vị ấy bên trong không có tưởng về sắc, thấy các sắc bên ngoài màu vàng, có màu vàng, hiện ra màu vàng, chiếu ánh vàng.",
  "dn16:3.30.4": "Vị ấy có tưởng như sau: ‘Sau khi thắng tri chúng, ta biết, ta thấy.’",
  "dn16:3.30.5": "Đây là thắng xứ thứ sáu.",
  "dn16:3.31.1": "Vị ấy bên trong không có tưởng về sắc, thấy các sắc bên ngoài màu đỏ, có màu đỏ, hiện ra màu đỏ, chiếu ánh đỏ.",
  "dn16:3.31.2": "Ví như hoa bông trang đỏ, có màu đỏ, hiện ra màu đỏ, chiếu ánh đỏ. Hoặc như tấm vải Ba-la-nại được dệt láng cả hai mặt, màu đỏ, có màu đỏ, hiện ra màu đỏ, chiếu ánh đỏ.",
  "dn16:3.31.3": "Cũng vậy, vị ấy bên trong không có tưởng về sắc, thấy các sắc bên ngoài màu đỏ, có màu đỏ, hiện ra màu đỏ, chiếu ánh đỏ.",
  "dn16:3.31.4": "Vị ấy có tưởng như sau: ‘Sau khi thắng tri chúng, ta biết, ta thấy.’",
  "dn16:3.31.5": "Đây là thắng xứ thứ bảy.",
  "dn16:3.32.1": "Vị ấy bên trong không có tưởng về sắc, thấy các sắc bên ngoài màu trắng, có màu trắng, hiện ra màu trắng, chiếu ánh trắng.",
  "dn16:3.32.2": "Ví như sao mai màu trắng, có màu trắng, hiện ra màu trắng, chiếu ánh trắng. Hoặc như tấm vải Ba-la-nại được dệt láng cả hai mặt, màu trắng, có màu trắng, hiện ra màu trắng, chiếu ánh trắng.",
  "dn16:3.32.3": "Cũng vậy, vị ấy bên trong không có tưởng về sắc, thấy các sắc bên ngoài màu trắng, có màu trắng, hiện ra màu trắng, chiếu ánh trắng.",
  "dn16:3.32.4": "Vị ấy có tưởng như sau: ‘Sau khi thắng tri chúng, ta biết, ta thấy.’",
  "dn16:3.32.5": "Đây là thắng xứ thứ tám.",
  "dn16:3.32.6": "Này A-nan, đây là tám thắng xứ ấy.",
  "dn16:3.33.0": "19. Tám giải thoát",
  "dn16:3.33.1": "Này A-nan, có tám giải thoát này.",
  "dn16:3.33.2": "Thế nào là tám?",
  "dn16:3.33.3": "Có sắc, vị ấy thấy các sắc,",
  "dn16:3.33.4": "đây là giải thoát thứ nhất.",
  "dn16:3.33.5": "Bên trong không có tưởng về sắc, vị ấy thấy các sắc bên ngoài,",
  "dn16:3.33.6": "Đây là giải thoát thứ hai.",
  "dn16:3.33.7": "Vị ấy chuyên chú vào cái đẹp,",
  "dn16:3.33.8": "đây là giải thoát thứ ba.",
  "dn16:3.33.9": "Vượt hẳn mọi tưởng về sắc, với sự diệt mất của tưởng về chướng ngại, không tác ý đến tưởng sai khác, vị ấy nghĩ: ‘Hư không là vô biên’, chứng và an trú trong Không vô biên xứ,",
  "dn16:3.33.10": "đây là giải thoát thứ tư.",
  "dn16:3.33.11": "Vượt hẳn Không vô biên xứ, vị ấy nghĩ: ‘Thức là vô biên’, chứng và an trú trong Thức vô biên xứ,",
  "dn16:3.33.12": "đây là giải thoát thứ năm.",
  "dn16:3.33.13": "Vượt hẳn Thức vô biên xứ, vị ấy nghĩ: ‘Không có gì cả’, chứng và an trú trong Vô sở hữu xứ,",
  "dn16:3.33.14": "đây là giải thoát thứ sáu.",
  "dn16:3.33.15": "Vượt hẳn Vô sở hữu xứ, vị ấy chứng và an trú trong Phi tưởng phi phi tưởng xứ,",
  "dn16:3.33.16": "đây là giải thoát thứ bảy.",
  "dn16:3.33.17": "Vượt hẳn Phi tưởng phi phi tưởng xứ, vị ấy chứng và an trú trong Diệt thọ tưởng định,",
  "dn16:3.33.18": "đây là giải thoát thứ tám.",
  "dn16:3.33.19": "Này Ānanda, đó là tám giải thoát.",
  "dn16:3.33.20": "(...)",
  "dn16:3.34.1": "Này Ānanda, có một thời Ta trú tại Uruvelā, bên bờ sông Nerañjarā, dưới cây đa Ajapāla, ngay sau khi mới giác ngộ.",
  "dn16:3.34.2": "Rồi này Ānanda, Ma vương Ác ma đi đến chỗ Ta; đến rồi đứng sang một bên. Đứng sang một bên, này Ānanda, Ma vương Ác ma nói với Ta như sau:",
  "dn16:3.34.3": "‘Bạch Thế Tôn, nay xin Thế Tôn nhập Niết-bàn; xin bậc Thiện Thệ nhập Niết-bàn; nay đã đến thời Thế Tôn nhập Niết-bàn.’",
  "dn16:3.34.4": "Khi được nói như vậy, này Ānanda, Ta nói với Ma vương Ác ma như sau:",
  "dn16:3.35.1": "‘Này Ác ma, Ta sẽ chưa nhập Niết-bàn khi nào các Tỳ-kheo đệ tử của Ta chưa trở thành những người thông thạo, được huấn luyện, vững vàng, đa văn, gìn giữ Chánh pháp, thực hành đúng pháp và tùy pháp, thực hành chân chánh, sống thuận pháp; sau khi học thọ giáo pháp của bậc Đạo sư mình, họ sẽ giảng giải, thuyết dạy, trình bày, thiết lập, khai mở, phân tích, làm cho rõ ràng; khi có tà thuyết khởi lên, họ sẽ khéo bác bỏ đúng pháp và thuyết giảng Chánh pháp có đầy đủ thần biến.",
  "dn16:3.35.2": "Này Ác ma, Ta sẽ chưa nhập Niết-bàn khi nào các Tỳ-kheo-ni đệ tử của Ta chưa trở thành những người thông thạo, được huấn luyện, vững vàng, đa văn, gìn giữ Chánh pháp, thực hành đúng pháp và tùy pháp, thực hành chân chánh, sống thuận pháp; sau khi học thọ giáo pháp của bậc Đạo sư mình, họ sẽ giảng giải, thuyết dạy, trình bày, thiết lập, khai mở, phân tích, làm cho rõ ràng; khi có tà thuyết khởi lên, họ sẽ khéo bác bỏ đúng pháp và thuyết giảng Chánh pháp có đầy đủ thần biến.",
  "dn16:3.35.3": "Này Ác ma, Ta sẽ chưa nhập Niết-bàn khi nào các nam cư sĩ đệ tử của Ta chưa trở thành những người thông thạo, được huấn luyện, vững vàng, đa văn, gìn giữ Chánh pháp, thực hành đúng pháp và tùy pháp, thực hành chân chánh, sống thuận pháp; sau khi học thọ giáo pháp của bậc Đạo sư mình, họ sẽ giảng giải, thuyết dạy, trình bày, thiết lập, khai mở, phân tích, làm cho rõ ràng; khi có tà thuyết khởi lên, họ sẽ khéo bác bỏ đúng pháp và thuyết giảng Chánh pháp có đầy đủ thần biến.",
  "dn16:3.35.4": "Này Ác ma, Ta sẽ chưa nhập Niết-bàn khi nào các nữ cư sĩ đệ tử của Ta chưa trở thành những người thông thạo, được huấn luyện, vững vàng, đa văn, gìn giữ Chánh pháp, thực hành đúng pháp và tùy pháp, thực hành chân chánh, sống thuận pháp; sau khi học thọ giáo pháp của bậc Đạo sư mình, họ sẽ giảng giải, thuyết dạy, trình bày, thiết lập, khai mở, phân tích, làm cho rõ ràng; khi có tà thuyết khởi lên, họ sẽ khéo bác bỏ đúng pháp và thuyết giảng Chánh pháp có đầy đủ thần biến.",
  "dn16:3.35.5": "Này Ác ma, Ta sẽ chưa nhập Niết-bàn khi nào đời sống phạm hạnh này của Ta chưa được thành tựu, hưng thịnh, rộng lớn, phổ biến, đông người biết đến, lan rộng khắp nơi, được khéo tuyên bố giữa chư thiên và loài người.’",
  "dn16:3.36.1": "Này Ānanda, chính hôm nay, tại đền Cāpāla, Ma vương Ác ma đã đi đến chỗ Ta; đến rồi đứng sang một bên. Đứng sang một bên, này Ānanda, Ma vương Ác ma nói với Ta như sau:",
  "dn16:3.36.2": "‘Bạch Thế Tôn, nay xin Thế Tôn nhập Niết-bàn, xin bậc Thiện Thệ nhập Niết-bàn, nay đã đến thời Thế Tôn nhập Niết-bàn.",
  "dn16:3.36.3": "Bạch Thế Tôn, lời này đã được Thế Tôn nói ra:",
  "dn16:3.36.4": "“Này Ác ma, Ta sẽ chưa nhập Niết-bàn khi nào các Tỳ-kheo đệ tử của Ta chưa trở thành những người thông thạo …",
  "dn16:3.36.5": "khi nào các Tỳ-kheo-ni đệ tử của Ta chưa trở thành những người thông thạo …",
  "dn16:3.36.6": "khi nào các nam cư sĩ đệ tử của Ta chưa trở thành những người thông thạo …",
  "dn16:3.36.7": "cho đến khi các nữ cư sĩ của Ta chưa trở thành những nữ đệ tử…",
  "dn16:3.36.8": "cho đến khi phạm hạnh này của Ta chưa được hưng thịnh, phồn vinh, rộng lớn, được nhiều người biết đến, phổ biến rộng rãi, được khéo tuyên thuyết giữa chư thiên và loài người.”",
  "dn16:3.36.9": "Nhưng nay, bạch Thế Tôn, phạm hạnh của Thế Tôn đã hưng thịnh, phồn vinh, rộng lớn, được nhiều người biết đến, phổ biến rộng rãi, được khéo tuyên thuyết giữa chư thiên và loài người.",
  "dn16:3.36.10": "Vậy nay, bạch Thế Tôn, xin Thế Tôn nhập Niết-bàn, xin bậc Thiện Thệ nhập Niết-bàn, nay đã đến thời Thế Tôn nhập Niết-bàn.”",
  "dn16:3.37.1": "Khi được nói vậy, này Ānanda, Ta đã nói với Ác ma như sau:",
  "dn16:3.37.2": "‘Này Ác ma, hãy an tâm, chẳng bao lâu nữa Như Lai sẽ nhập Niết-bàn.",
  "dn16:3.37.3": "Sau ba tháng nữa, Như Lai sẽ nhập Niết-bàn.’",
  "dn16:3.37.4": "Ngay hôm nay, này Ānanda, tại đền Cāpāla, Như Lai với chánh niệm và tỉnh giác đã từ bỏ thọ hành.”",
  "dn16:3.38.0": "20. Câu chuyện thỉnh cầu của Ānanda",
  "dn16:3.38.1": "Khi được nói vậy, Tôn giả Ānanda bạch Thế Tôn rằng:",
  "dn16:3.38.2": "“Xin Thế Tôn hãy ở lại một kiếp, xin bậc Thiện Thệ hãy ở lại một kiếp, vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, vì an lạc cho chư thiên và loài người.”",
  "dn16:3.38.3": "“Thôi đủ rồi, này Ānanda.",
  "dn16:3.38.4": "Chớ thỉnh cầu Như Lai nữa, này Ānanda, nay không phải lúc để thỉnh cầu Như Lai.”",
  "dn16:3.39.1": "Lần thứ hai, Tôn giả Ānanda…",
  "dn16:3.39.2": "Lần thứ ba, Tôn giả Ānanda bạch Thế Tôn rằng:",
  "dn16:3.39.3": "“Xin Thế Tôn hãy ở lại một kiếp, xin bậc Thiện Thệ hãy ở lại một kiếp, vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, vì an lạc cho chư thiên và loài người.”",
  "dn16:3.39.4": "“Này Ānanda, ông có tin vào sự giác ngộ của Như Lai không?”",
  "dn16:3.39.5": "“Thưa có, bạch Thế Tôn.”",
  "dn16:3.39.6": "“Vậy thì vì sao, này Ānanda, ông lại ép nài Như Lai đến lần thứ ba?”",
  "dn16:3.40.1": "“Bạch Thế Tôn, chính con đã được nghe và tiếp nhận điều này trực tiếp từ Thế Tôn:",
  "dn16:3.40.2": "‘Này Ānanda, bất cứ ai có bốn thần túc đã được tu tập, được làm cho sung mãn, được thực hành như cỗ xe, được đặt làm nền tảng, được an lập, được thuần thục, được khéo khởi lên, thì nếu muốn, người ấy có thể sống trọn một kiếp hay phần còn lại của một kiếp.",
  "dn16:3.40.3": "Này Ānanda, Như Lai có bốn thần túc đã được tu tập, được làm cho sung mãn, được thực hành như cỗ xe, được đặt làm nền tảng, được an lập, được thuần thục, được khéo khởi lên. Nếu muốn, này Ānanda, Như Lai có thể sống trọn một kiếp hay phần còn lại của một kiếp.’”",
  "dn16:3.40.4": "“Này Ānanda, ông có tin điều ấy không?”",
  "dn16:3.40.5": "“Thưa có, bạch Thế Tôn.”",
  "dn16:3.40.6": "“Vậy nên, này Ānanda, chính ông đã làm điều sai trái này, chính ông đã phạm lỗi này, vì khi Như Lai đã làm ra dấu hiệu rõ ràng như vậy, đã phát ra ánh sáng rõ ràng như vậy, ông vẫn không thể hiểu ra, không thỉnh cầu Như Lai rằng:",
  "dn16:3.40.7": "‘Xin Thế Tôn hãy ở lại một kiếp, xin bậc Thiện Thệ hãy ở lại một kiếp, vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, vì an lạc cho chư thiên và loài người.’",
  "dn16:3.40.8": "Nếu ông đã thỉnh cầu Như Lai, này Ānanda, thì Như Lai sẽ từ chối lời ông hai lần, nhưng đến lần thứ ba sẽ chấp nhận.",
  "dn16:3.40.9": "Vậy nên, này Ānanda, chính ông đã làm điều sai trái này, chính ông đã phạm lỗi này.",
  "dn16:3.41.1": "Này Ānanda, có một thời Ta trú tại Rājagaha, trên núi Gijjhakūṭa.",
  "dn16:3.41.2": "Tại đó nữa, này Ānanda, Ta đã nói với ông:",
  "dn16:3.41.3": "‘Này Ānanda, thành Vương Xá thật khả ái, núi Linh Thứu thật khả ái.",
  "dn16:3.41.4": "Này Ānanda, bất cứ ai đã tu tập, làm cho sung mãn, làm thành cỗ xe, lấy làm nền tảng, thiết lập vững chắc, khéo thực hành bốn thần túc, người ấy nếu muốn có thể sống trọn một kiếp hay phần còn lại của một kiếp.",
  "dn16:3.41.5": "Này Ānanda, Như Lai đã tu tập, làm cho sung mãn, làm thành cỗ xe, lấy làm nền tảng, thiết lập vững chắc, khéo thực hành bốn thần túc. Nếu muốn, này Ānanda, Như Lai có thể sống trọn một kiếp hay phần còn lại của một kiếp.’",
  "dn16:3.41.6": "Dầu vậy, này Ānanda, khi Như Lai đã làm dấu hiệu rõ ràng, đã phát ra ánh sáng rõ ràng như thế, ông vẫn không thể hiểu ra, không thỉnh cầu Như Lai:",
  "dn16:3.41.7": "‘Bạch Thế Tôn, xin Thế Tôn hãy ở lại trọn một kiếp, xin Thiện Thệ hãy ở lại trọn một kiếp, vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, an lạc cho chư thiên và loài người.’",
  "dn16:3.41.8": "Nếu ông, này Ānanda, đã thỉnh cầu Như Lai, thì Như Lai sẽ từ chối ông đến hai lần, nhưng đến lần thứ ba sẽ chấp thuận.",
  "dn16:3.41.9": "Vì vậy, này Ānanda, đây chính là lỗi của ông, đây chính là sự sai phạm của ông.",
  "dn16:3.42.1": "Này Ānanda, có một thời ta trú ngay tại thành Vương Xá, ở cây đa Gotama …",
  "dn16:3.42.2": "ngay tại thành Vương Xá, ta trú ở Corapapāta …",
  "dn16:3.42.3": "ngay tại thành Vương Xá, ta trú ở hang Bảy Lá bên sườn núi Vebhāra …",
  "dn16:3.42.4": "ngay tại thành Vương Xá, ta trú ở tảng đá đen bên sườn Isigili …",
  "dn16:3.42.5": "ngay tại thành Vương Xá, ta trú ở mỏm đá Sappasoṇḍika trong rừng Sītavana …",
  "dn16:3.42.6": "ngay tại thành Vương Xá, ta trú ở Tapodārāma …",
  "dn16:3.42.7": "ngay tại thành Vương Xá, ta trú ở Trúc Lâm, chỗ nuôi sóc Kalandaka …",
  "dn16:3.42.8": "ngay tại thành Vương Xá, ta trú ở vườn xoài của Jīvaka …",
  "dn16:3.42.9": "ngay tại thành Vương Xá, ta trú ở vườn Nai tại Maddakucchi.",
  "dn16:3.43.1": "Tại những nơi ấy nữa, này Ānanda, ta đã nói với ông:",
  "dn16:3.43.2": "‘Này Ānanda, thành Vương Xá thật khả ái, núi Linh Thứu thật khả ái, cây đa Gotama thật khả ái, Corapapāta thật khả ái, hang Bảy Lá bên sườn núi Vebhāra thật khả ái, tảng đá đen bên sườn Isigili thật khả ái, mỏm đá Sappasoṇḍika trong rừng Sītavana thật khả ái, Tapodārāma thật khả ái, Trúc Lâm, chỗ nuôi sóc Kalandaka thật khả ái, vườn xoài của Jīvaka thật khả ái, vườn Nai tại Maddakucchi thật khả ái.",
  "dn16:3.44.1": "Này Ānanda, bất cứ ai đã tu tập, làm cho sung mãn, làm thành cỗ xe, lấy làm nền tảng, thiết lập vững chắc, khéo thực hành bốn thần túc …",
  "dn16:3.44.2": "này Ānanda, nếu muốn, Như Lai có thể sống trọn một kiếp hay phần còn lại của một kiếp.’",
  "dn16:3.44.3": "Dầu vậy, này Ānanda, khi Như Lai đã làm dấu hiệu rõ ràng, đã phát ra ánh sáng rõ ràng như thế, ông vẫn không thể hiểu ra, không thỉnh cầu Như Lai:",
  "dn16:3.44.4": "‘Bạch Thế Tôn, xin Thế Tôn hãy ở lại trọn một kiếp, xin Thiện Thệ hãy ở lại trọn một kiếp, vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, an lạc cho chư thiên và loài người.’",
  "dn16:3.44.5": "Nếu ông, này Ānanda, đã thỉnh cầu Như Lai, thì Như Lai sẽ từ chối ông đến hai lần, nhưng đến lần thứ ba sẽ chấp thuận.",
  "dn16:3.44.6": "Vì vậy, này Ānanda, đây chính là lỗi của ông, đây chính là sự sai phạm của ông.",
  "dn16:3.45.1": "Này Ānanda, có một thời ta trú ngay tại Vesālī này, ở đền Udena.",
  "dn16:3.45.2": "Tại đó nữa, này Ānanda, ta đã nói với ông:",
  "dn16:3.45.3": "‘Này Ānanda, Vesālī thật khả ái, đền Udena thật khả ái.",
  "dn16:3.45.4": "Này Ānanda, bất cứ ai đã tu tập, làm cho sung mãn, làm thành cỗ xe, lấy làm nền tảng, thiết lập vững chắc, khéo thực hành bốn thần túc, người ấy nếu muốn có thể sống trọn một kiếp hay phần còn lại của một kiếp.",
  "dn16:3.45.5": "Này Ānanda, Như Lai đã tu tập, làm cho sung mãn, làm thành cỗ xe, lấy làm nền tảng, thiết lập vững chắc, khéo thực hành bốn thần túc. Nếu muốn, này Ānanda, Như Lai có thể sống trọn một kiếp hay phần còn lại của một kiếp.’",
  "dn16:3.45.6": "Dầu vậy, này Ānanda, khi Như Lai đã làm dấu hiệu rõ ràng, đã phát ra ánh sáng rõ ràng như thế, ông vẫn không thể hiểu ra, không thỉnh cầu Như Lai:",
  "dn16:3.45.7": "‘Thôi, bạch Thế Tôn, xin Thế Tôn hãy ở lại trọn một kiếp, xin bậc Thiện Thệ hãy ở lại trọn một kiếp vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, vì an lạc cho chư thiên và loài người.’",
  "dn16:3.45.8": "Nếu này Ānanda, ông đã thỉnh cầu Như Lai, thì Như Lai sẽ từ chối lời thỉnh ấy đến hai lần, rồi đến lần thứ ba sẽ chấp nhận. Vì vậy, này Ānanda, lỗi ấy là của chính ông, sự sai phạm ấy là của chính ông.",
  "dn16:3.46.1": "Này Ānanda, có một thời ta trú ngay tại Vesālī này, ở đền Gotamaka …",
  "dn16:3.46.2": "ngay tại Vesālī này, ta trú ở đền Sattamba …",
  "dn16:3.46.3": "ngay tại Vesālī này, ta trú ở đền Bahuputta …",
  "dn16:3.46.4": "ngay tại Vesālī này, ta trú ở đền Sārandada …",
  "dn16:3.47.1": "Chính hôm nay, này Ānanda, tại đền Cāpāla, ta đã nói với ông rằng:",
  "dn16:3.47.2": "‘Này Ānanda, Vesālī thật khả ái, đền Udena thật khả ái, đền Gotamaka thật khả ái, đền Sattamba thật khả ái, đền Bahuputta thật khả ái, đền Sārandada thật khả ái, đền Cāpāla thật khả ái.",
  "dn16:3.47.3": "Này Ānanda, bất cứ ai đã tu tập, làm cho sung mãn, làm thành cỗ xe, lấy làm nền tảng, thiết lập vững chắc, huân tập, khéo khởi sự bốn thần túc, người ấy nếu muốn có thể ở lại trọn một kiếp hay phần còn lại của một kiếp.",
  "dn16:3.47.4": "Này Ānanda, Như Lai đã tu tập, làm cho sung mãn, làm thành cỗ xe, lấy làm nền tảng, thiết lập vững chắc, huân tập, khéo khởi sự bốn thần túc; nếu muốn, này Ānanda, Như Lai có thể ở lại trọn một kiếp hay phần còn lại của một kiếp.’",
  "dn16:3.47.5": "Dù vậy, này Ānanda, khi Như Lai đã làm ra dấu hiệu rõ ràng, đã phát ra ánh sáng rõ ràng như thế, ông vẫn không thể hiểu ra, không thỉnh cầu Như Lai rằng:",
  "dn16:3.47.6": "‘Xin Thế Tôn hãy ở lại trọn một kiếp, xin bậc Thiện Thệ hãy ở lại trọn một kiếp vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, vì an lạc cho chư thiên và loài người.’",
  "dn16:3.47.7": "Nếu này Ānanda, ông đã thỉnh cầu Như Lai, thì Như Lai sẽ từ chối lời thỉnh ấy đến hai lần, rồi đến lần thứ ba sẽ chấp nhận.",
  "dn16:3.47.8": "Vì vậy, này Ānanda, lỗi ấy là của chính ông, sự sai phạm ấy là của chính ông.",
  "dn16:3.48.1": "Này Ānanda, chẳng phải ta đã nói trước với ông rằng:",
  "dn16:3.48.2": "‘Đối với tất cả những gì thân yêu, khả ý, đều có sự đổi khác, sự chia lìa, sự biến đổi.",
  "dn16:3.48.3": "Này Ānanda, làm sao có thể có chuyện điều gì đã sinh, đã hiện hữu, đã được tạo thành, có bản chất phải hoại diệt, lại có thể không hoại diệt? Không có trường hợp ấy.’",
  "dn16:3.48.4": "Còn điều này nữa, này Ānanda, thọ hành đã bị Như Lai từ bỏ, nhổ bỏ, buông bỏ, đoạn trừ, xả ly,",
  "dn16:3.48.5": "và lời nói đã được tuyên bố dứt khoát rằng:",
  "dn16:3.48.6": "‘Chẳng bao lâu nữa, Như Lai sẽ nhập Niết-bàn. Sau ba tháng nữa, Như Lai sẽ nhập Niết-bàn.’",
  "dn16:3.48.7": "Và việc Như Lai vì nhân duyên mạng sống mà sẽ thu hồi lại điều ấy, không có trường hợp ấy.",
  "dn16:3.48.8": "Nào, này Ānanda, chúng ta hãy đi đến Đại Lâm, giảng đường Trùng Các.’",
  "dn16:3.48.9": "‘Vâng, bạch Thế Tôn,’ Tôn giả Ānanda vâng đáp Thế Tôn.",
  "dn16:3.49.1": "Bấy giờ Thế Tôn cùng với Tôn giả Ānanda đi đến Đại Lâm, giảng đường Trùng Các; sau khi đến, Ngài nói với Tôn giả Ānanda:",
  "dn16:3.49.2": "‘Này Ānanda, ông hãy đi tập hợp tất cả các vị tỳ-kheo đang trú nương quanh Vesālī, cho họ hội họp tại giảng đường.’",
  "dn16:3.49.3": "‘Vâng, bạch Thế Tôn,’ Tôn giả Ānanda vâng lời Thế Tôn, tập hợp tất cả các vị tỳ-kheo đang trú nương quanh Vesālī tại giảng đường, rồi đi đến chỗ Thế Tôn; sau khi đến, đảnh lễ Thế Tôn rồi đứng sang một bên. Đứng sang một bên, Tôn giả Ānanda bạch Thế Tôn rằng:",
  "dn16:3.49.4": "‘Bạch Thế Tôn, chúng tỳ-kheo đã hội họp, nay xin Thế Tôn tùy thời.’",
  "dn16:3.49.5": "(…)",
  "dn16:3.50.1": "Bấy giờ Thế Tôn đi đến giảng đường; sau khi đến, Ngài ngồi xuống trên chỗ ngồi đã soạn sẵn.",
  "dn16:3.50.2": "Sau khi ngồi xuống, Thế Tôn nói với các tỳ-kheo:",
  "dn16:3.50.3": "“Vậy nên, này các Tỳ-kheo, những pháp nào Ta đã do thắng trí mà thuyết giảng, các ông phải khéo thọ trì, thực hành, tu tập, làm cho sung mãn, để đời sống phạm hạnh này được lâu dài, tồn tại bền vững, vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, an lạc cho chư thiên và loài người.",
  "dn16:3.50.4": "Và này các Tỳ-kheo, những pháp nào là những pháp Ta đã do thắng trí mà thuyết giảng, các ông phải khéo thọ trì, thực hành, tu tập, làm cho sung mãn, để đời sống phạm hạnh này được lâu dài, tồn tại bền vững, vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, an lạc cho chư thiên và loài người?",
  "dn16:3.50.5": "Đó là: bốn niệm xứ, bốn chánh cần, bốn thần túc, năm căn, năm lực, bảy giác chi, Thánh đạo tám ngành.",
  "dn16:3.51.1": "Này các Tỳ-kheo, đó là những pháp Ta đã do thắng trí mà thuyết giảng, các ông phải khéo thọ trì, thực hành, tu tập, làm cho sung mãn, để đời sống phạm hạnh này được lâu dài, tồn tại bền vững, vì lợi ích cho số đông, vì hạnh phúc cho số đông, vì lòng thương tưởng đời, vì lợi ích, an lạc cho chư thiên và loài người.”",
  "dn16:3.51.2": "Rồi Thế Tôn gọi các Tỳ-kheo:",
  "dn16:3.51.3": "“Này các Tỳ-kheo, giờ đây Ta nhắn nhủ các ông,",
  "dn16:3.51.4": "các hành là pháp phải hoại diệt, hãy tinh tấn không phóng dật mà thành tựu.",
  "dn16:3.51.5": "Chẳng bao lâu nữa, Như Lai sẽ nhập parinibbāna.",
  "dn16:3.51.6": "Sau ba tháng kể từ nay, Như Lai sẽ nhập parinibbāna.”",
  "dn16:3.51.7": "Thế Tôn đã nói như vậy.",
  "dn16:3.51.8": "Nói xong như vậy, bậc Thiện Thệ, rồi tiếp đó bậc Đạo Sư lại nói thêm rằng:",
  "dn16:3.51.9": "“Tuổi già của Ta đã chín muồi,",
  "dn16:3.51.10": "mạng sống của Ta còn ít ỏi;",
  "dn16:3.51.11": "Ta sẽ từ biệt các ông mà ra đi,",
  "dn16:3.51.12": "Ta đã tự mình nương tựa nơi mình.",
  "dn16:3.51.13": "Hãy không phóng dật, có chánh niệm,",
  "dn16:3.51.14": "hãy sống giới hạnh tốt đẹp, này các Tỳ-kheo;",
  "dn16:3.51.15": "hãy khéo an trú trong tư tưởng định tĩnh,",
  "dn16:3.51.16": "hãy giữ gìn tâm mình.",
  "dn16:3.51.17": "Ai trong pháp và luật này",
  "dn16:3.51.18": "sống không phóng dật,",
  "dn16:3.51.19": "đoạn lìa vòng luân hồi sinh tử,",
  "dn16:3.51.20": "sẽ chấm dứt khổ đau.”",
  "dn16:3.51.21": "Phần tụng đọc thứ ba.",
  "dn16:4.1.0": "21. Ngoảnh nhìn như voi chúa",
  "dn16:4.1.1": "Bấy giờ, vào buổi sáng, Thế Tôn đắp y, cầm bát và y, đi vào Vesāli khất thực.",
  "dn16:4.1.2": "Sau khi đi khất thực ở Vesāli, dùng bữa xong, trên đường từ khất thực trở về, Ngài ngoảnh nhìn Vesāli như voi chúa rồi gọi Tôn giả Ānanda:",
  "dn16:4.1.3": "“Này Ānanda, đây sẽ là lần cuối cùng Như Lai nhìn thấy Vesāli.",
  "dn16:4.1.4": "Nào, Ānanda, chúng ta hãy đi đến Bhaṇḍagāma.”",
  "dn16:4.1.5": "“Vâng, bạch Thế Tôn,” Tôn giả Ānanda vâng đáp Thế Tôn.",
  "dn16:4.2.1": "Bấy giờ, Thế Tôn cùng với đại chúng Tỳ-kheo đi đến làng Bhaṇḍa.",
  "dn16:4.2.2": "Tại đó, Thế Tôn trú ở làng Bhaṇḍa.",
  "dn16:4.2.3": "Tại đó, Thế Tôn gọi các Tỳ-kheo:",
  "dn16:4.2.4": "“Này các Tỳ-kheo, do không thấu hiểu, không chứng ngộ bốn pháp này mà suốt thời gian dài, Ta và các ông đã phải rong ruổi, luân chuyển trong sinh tử.",
  "dn16:4.2.5": "Bốn pháp ấy là gì?",
  "dn16:4.2.6": "Này các Tỳ-kheo, do không thấu hiểu, không chứng ngộ giới thánh mà suốt thời gian dài, Ta và các ông đã phải rong ruổi, luân chuyển trong sinh tử.",
  "dn16:4.2.7": "Này các Tỳ-kheo, do không thấu hiểu, không chứng ngộ định thánh mà suốt thời gian dài, Ta và các ông đã phải rong ruổi, luân chuyển trong sinh tử.",
  "dn16:4.2.8": "Này các Tỳ-kheo, do không thấu hiểu, không chứng ngộ tuệ thánh mà suốt thời gian dài, Ta và các ông đã phải rong ruổi, luân chuyển trong sinh tử.",
  "dn16:4.2.9": "Này các Tỳ-kheo, do không thấu hiểu, không chứng ngộ giải thoát thánh mà suốt thời gian dài, Ta và các ông đã phải rong ruổi, luân chuyển trong sinh tử.",
  "dn16:4.2.10": "Này các Tỳ-kheo, nay giới thánh này đã được thấu hiểu, đã được chứng ngộ; định thánh đã được thấu hiểu, đã được chứng ngộ; tuệ thánh đã được thấu hiểu, đã được chứng ngộ; giải thoát thánh đã được thấu hiểu, đã được chứng ngộ; ái hữu đã bị đoạn tận, nhân dẫn đến hữu đã bị diệt, nay không còn tái sinh nữa.”",
  "dn16:4.3.1": "Thế Tôn nói như vậy.",
  "dn16:4.3.2": "Nói xong, bậc Thiện Thệ lại nói thêm rằng:",
  "dn16:4.3.3": "“Giới, định và tuệ,",
  "dn16:4.3.4": "cùng với giải thoát vô thượng;",
  "dn16:4.3.5": "những pháp này đã được",
  "dn16:4.3.6": "Gotama đầy vinh quang giác ngộ.",
  "dn16:4.3.7": "Vì vậy, Đức Phật sau khi tự mình thắng tri,",
  "dn16:4.3.8": "đã thuyết pháp cho các Tỳ-kheo;",
  "dn16:4.3.9": "bậc Đạo Sư chấm dứt khổ đau,",
  "dn16:4.3.10": "bậc có mắt đã nhập Niết-bàn.”",
  "dn16:4.4.1": "Tại đó, khi trú ở làng Bhaṇḍa, Thế Tôn thường xuyên thuyết cho các Tỳ-kheo bài pháp thoại này:",
  "dn16:4.4.2": "“Đây là giới, đây là định, đây là tuệ.",
  "dn16:4.4.3": "Định được tu tập nhờ giới thì có quả lớn, có lợi ích lớn.",
  "dn16:4.4.4": "Tuệ được tu tập nhờ định thì có quả lớn, có lợi ích lớn.",
  "dn16:4.4.5": "Tâm được tu tập nhờ tuệ thì được giải thoát hoàn toàn khỏi các lậu hoặc, tức là—",
  "dn16:4.4.6": "dục lậu, hữu lậu, vô minh lậu.”",
  "dn16:4.5.0": "22. Bài giảng về bốn đại giáo pháp",
  "dn16:4.5.1": "Bấy giờ, Thế Tôn sau khi ở làng Bhaṇḍa tùy ý thích, liền gọi Tôn giả A-nan:",
  "dn16:4.5.2": "“Này A-nan, hãy đi đến làng Hatthi,",
  "dn16:4.5.3": "đến làng Amba,",
  "dn16:4.5.4": "đến làng Jambugāma,",
  "dn16:4.5.5": "rồi từ đó chúng ta sẽ đi đến Bhoganagara.”",
  "dn16:4.6.1": "“Vâng, bạch Thế Tôn,” Tôn giả Ānanda vâng đáp Thế Tôn.",
  "dn16:4.6.2": "Rồi Thế Tôn cùng với đại chúng Tỳ-kheo đi đến Bhoganagara.",
  "dn16:4.7.1": "Tại đó, Thế Tôn trú ở Bhoganagara, tại đền Ānanda.",
  "dn16:4.7.2": "Tại đó, Thế Tôn gọi các Tỳ-kheo:",
  "dn16:4.7.3": "“Này các Tỳ-kheo, Ta sẽ giảng bốn đại giáo pháp,",
  "dn16:4.7.4": "hãy lắng nghe, hãy khéo tác ý, Ta sẽ nói.”",
  "dn16:4.7.5": "“Vâng, bạch Thế Tôn,” các Tỳ-kheo ấy vâng đáp Thế Tôn.",
  "dn16:4.7.6": "Thế Tôn nói như sau:",
  "dn16:4.8.1": "“Ở đây, này các Tỳ-kheo, có vị Tỳ-kheo nói như vầy:",
  "dn16:4.8.2": "‘Này hiền giả, điều này tôi được nghe trực tiếp từ Thế Tôn, được nhận lãnh trực tiếp,",
  "dn16:4.8.3": "đây là pháp, đây là luật, đây là lời dạy của bậc Đạo Sư.’",
  "dn16:4.8.4": "Này các Tỳ-kheo, lời nói của vị Tỳ-kheo ấy không nên tán đồng cũng không nên bác bỏ.",
  "dn16:4.8.5": "Không tán đồng, không bác bỏ, hãy khéo ghi nhận những từ ngữ và văn cú ấy, rồi đối chiếu với Kinh, so sánh với Luật.",
  "dn16:4.8.6": "Nếu khi đối chiếu với Kinh, so sánh với Luật, mà những điều ấy không phù hợp với Kinh, không tương ứng với Luật, thì ở đây phải kết luận rằng:",
  "dn16:4.8.7": "‘Chắc chắn đây không phải là lời của Thế Tôn ấy;",
  "dn16:4.8.8": "và vị Tỳ-kheo này đã thọ trì sai lầm.’",
  "dn16:4.8.9": "Như vậy, này các Tỳ-kheo, các ông nên từ bỏ điều ấy.",
  "dn16:4.8.10": "Nhưng nếu khi đối chiếu với Kinh, so sánh với Luật, mà những điều ấy phù hợp với Kinh và tương ứng với Luật, thì ở đây phải kết luận rằng:",
  "dn16:4.8.11": "‘Chắc chắn đây là lời của Thế Tôn ấy;",
  "dn16:4.8.12": "và vị Tỳ-kheo này đã thọ trì đúng đắn.’",
  "dn16:4.8.13": "Này các Tỳ-kheo, các ông hãy ghi nhớ đây là đại giáo pháp thứ nhất.",
  "dn16:4.9.1": "Lại nữa, này các Tỳ-kheo, có vị Tỳ-kheo nói như vầy:",
  "dn16:4.9.2": "‘Tại một trú xứ tên là như thế, có Tăng chúng đang trú, với các vị trưởng lão và vị đứng đầu.",
  "dn16:4.9.3": "Tôi đã được nghe trực tiếp trước mặt Tăng chúng ấy, được nhận lãnh trực tiếp,",
  "dn16:4.9.4": "đây là pháp, đây là luật, đây là lời dạy của bậc Đạo Sư.’",
  "dn16:4.9.5": "Này các Tỳ-kheo, lời nói của vị Tỳ-kheo ấy không nên tán đồng cũng không nên bác bỏ.",
  "dn16:4.9.6": "Không tán đồng, không bác bỏ, hãy khéo ghi nhận những từ ngữ và văn cú ấy, rồi đối chiếu với Kinh, so sánh với Luật.",
  "dn16:4.9.7": "Nếu khi đối chiếu với Kinh, so sánh với Luật, mà những điều ấy không phù hợp với Kinh, không tương ứng với Luật, thì ở đây phải kết luận rằng:",
  "dn16:4.9.8": "‘Chắc chắn đây không phải lời của Thế Tôn;",
  "dn16:4.9.9": "và hội chúng ấy đã thọ trì sai lầm.’",
  "dn16:4.9.10": "Như vậy, này các Tỳ-kheo, các ông nên loại bỏ điều ấy.",
  "dn16:4.9.11": "Nhưng nếu khi đối chiếu với các kinh, khi so sánh với luật, chúng phù hợp với kinh và được thấy trong luật, thì ở đây phải đi đến kết luận rằng:",
  "dn16:4.9.12": "‘Chắc chắn đây là lời của Thế Tôn;",
  "dn16:4.9.13": "và hội chúng ấy đã thọ trì đúng đắn.’",
  "dn16:4.9.14": "Này các Tỳ-kheo, hãy ghi nhớ đây là đại giáo pháp thứ hai.",
  "dn16:4.10.1": "Lại nữa, này các Tỳ-kheo, ở đây có vị Tỳ-kheo nói như vầy:",
  "dn16:4.10.2": "‘Tại một trú xứ tên là như thế, có nhiều vị trưởng lão Tỳ-kheo đang cư trú, đa văn, thông đạt truyền thống, trì pháp, trì luật, trì mẫu đề.",
  "dn16:4.10.3": "Tôi đã được nghe trực tiếp, được thọ nhận trực tiếp từ các vị trưởng lão ấy rằng—",
  "dn16:4.10.4": "đây là pháp, đây là luật, đây là lời dạy của bậc Đạo Sư.’",
  "dn16:4.10.5": "Này các Tỳ-kheo, lời nói của vị Tỳ-kheo ấy không nên tán thành …",
  "dn16:4.10.6": "…",
  "dn16:4.10.7": "và không được thấy trong luật, thì ở đây phải đi đến kết luận rằng:",
  "dn16:4.10.8": "‘Chắc chắn đây không phải lời của Thế Tôn;",
  "dn16:4.10.9": "và các vị trưởng lão ấy đã thọ trì sai lầm.’",
  "dn16:4.10.10": "Như vậy, này các Tỳ-kheo, các ông nên loại bỏ điều ấy.",
  "dn16:4.10.11": "Nhưng nếu khi đối chiếu với các kinh …",
  "dn16:4.10.12": "và được thấy trong luật, thì ở đây phải đi đến kết luận rằng:",
  "dn16:4.10.13": "‘Chắc chắn đây là lời của Thế Tôn;",
  "dn16:4.10.14": "và các vị trưởng lão ấy đã thọ trì đúng đắn.’",
  "dn16:4.10.15": "Này các Tỳ-kheo, hãy ghi nhớ đây là đại giáo pháp thứ ba.",
  "dn16:4.11.1": "Lại nữa, này các Tỳ-kheo, ở đây có vị Tỳ-kheo nói như vầy:",
  "dn16:4.11.2": "‘Tại một trú xứ tên là như thế, có một vị trưởng lão Tỳ-kheo đang cư trú, đa văn, thông đạt truyền thống, trì pháp, trì luật, trì mẫu đề.",
  "dn16:4.11.3": "Tôi đã được nghe trực tiếp, được thọ nhận trực tiếp từ vị trưởng lão ấy rằng—",
  "dn16:4.11.4": "đây là pháp, đây là luật, đây là lời dạy của bậc Đạo Sư.’",
  "dn16:4.11.5": "Này các Tỳ-kheo, lời nói của vị Tỳ-kheo ấy không nên tán thành cũng không nên bác bỏ.",
  "dn16:4.11.6": "Không tán thành, không bác bỏ, sau khi khéo ghi nhận những từ ngữ và văn cú ấy, cần đối chiếu với kinh, cần so sánh với luật.",
  "dn16:4.11.7": "Nếu khi đối chiếu với các kinh, khi so sánh với luật, chúng không phù hợp với kinh và không được thấy trong luật, thì ở đây phải đi đến kết luận rằng:",
  "dn16:4.11.8": "‘Chắc chắn đây không phải lời của Thế Tôn;",
  "dn16:4.11.9": "và vị trưởng lão ấy đã thọ trì sai lầm.",
  "dn16:4.11.10": "Này các Tỳ-kheo, như vậy các ông nên bác bỏ điều ấy.",
  "dn16:4.11.11": "Còn nếu những điều ấy khi được đối chiếu với kinh thì phù hợp với kinh, khi được đối chiếu với luật thì phù hợp với luật, phù hợp với cả kinh và được thấy rõ trong luật, thì cần đi đến kết luận rằng:",
  "dn16:4.11.12": "‘Chắc chắn đây là lời của Thế Tôn;",
  "dn16:4.11.13": "và vị trưởng lão ấy đã thọ trì đúng đắn.’",
  "dn16:4.11.14": "Này các Tỳ-kheo, các ông hãy ghi nhớ điều này là đại giáo pháp thứ tư.",
  "dn16:4.11.15": "Này các Tỳ-kheo, các ông hãy ghi nhớ bốn đại giáo pháp này.”",
  "dn16:4.12.1": "Tại đó, khi trú ở Bhoganagara, tại đền Ānanda, Thế Tôn thường thuyết cho các Tỳ-kheo bài pháp như sau:",
  "dn16:4.12.2": "“Đây là giới, đây là định, đây là tuệ.",
  "dn16:4.12.3": "Định được tu tập nhờ giới có quả lớn, lợi ích lớn.",
  "dn16:4.12.4": "Tuệ được tu tập nhờ định có quả lớn, lợi ích lớn.",
  "dn16:4.12.5": "Tâm được tu tập nhờ tuệ thì được giải thoát chân chánh khỏi các lậu hoặc, tức là—",
  "dn16:4.12.6": "dục lậu, hữu lậu, vô minh lậu.”",
  "dn16:4.13.0": "23. Chuyện Cunda, con người thợ rèn",
  "dn16:4.13.1": "Rồi Thế Tôn, sau khi ở Bhoganagara tùy ý bao lâu, đã gọi Tôn giả Ānanda:",
  "dn16:4.13.2": "“Này Ānanda, chúng ta hãy đi đến Pāvā.”",
  "dn16:4.13.3": "“Vâng, bạch Thế Tôn,” Tôn giả Ānanda vâng đáp Thế Tôn.",
  "dn16:4.13.4": "Rồi Thế Tôn cùng với đại chúng Tỳ-kheo đi đến Pāvā.",
  "dn16:4.13.5": "Tại đó, ở Pāvā, Thế Tôn trú trong vườn xoài của Cunda, con người thợ rèn.",
  "dn16:4.14.1": "Cunda, con người thợ rèn, nghe tin: “Nghe nói Thế Tôn đã đến Pāvā, hiện đang trú ở vườn xoài của ta tại Pāvā.”",
  "dn16:4.14.2": "Rồi Cunda, con người thợ rèn, đi đến chỗ Thế Tôn; đến nơi, đảnh lễ Thế Tôn rồi ngồi xuống một bên.",
  "dn16:4.14.3": "Khi Cunda, con người thợ rèn, ngồi xuống một bên, Thế Tôn thuyết pháp, chỉ dạy, khích lệ, làm cho phấn chấn, làm cho hoan hỷ.",
  "dn16:4.14.4": "Rồi Cunda, con người thợ rèn, sau khi được Thế Tôn thuyết pháp, chỉ dạy, khích lệ, làm cho phấn chấn, làm cho hoan hỷ, bạch Thế Tôn rằng:",
  "dn16:4.15.1": "“Bạch Thế Tôn, xin Thế Tôn nhận lời thọ thực ngày mai cùng với chúng Tỳ-kheo.”",
  "dn16:4.15.2": "Thế Tôn im lặng nhận lời.",
  "dn16:4.16.1": "Rồi Cunda, con người thợ rèn, biết Thế Tôn đã nhận lời, liền từ chỗ ngồi đứng dậy, đảnh lễ Thế Tôn, đi nhiễu bên phải rồi ra về.",
  "dn16:4.17.1": "Rồi Cunda, con người thợ rèn, sau khi đêm ấy đã qua, tại nhà mình cho chuẩn bị các món ăn cứng và món ăn mềm thượng vị, cùng rất nhiều món sūkaramaddava, rồi báo giờ đến Thế Tôn rằng:",
  "dn16:4.17.2": "“Bạch Thế Tôn, đã đến giờ, bữa ăn đã chuẩn bị xong.”",
  "dn16:4.18.1": "Rồi Thế Tôn vào buổi sáng đắp y, mang theo y bát, cùng với chúng Tỳ-kheo đi đến nhà của Cunda, con người thợ rèn; đến nơi, ngồi xuống chỗ đã soạn sẵn.",
  "dn16:4.18.2": "Khi đã ngồi xuống, Thế Tôn nói với Cunda, con người thợ rèn:",
  "dn16:4.18.3": "“Này Cunda, món sūkaramaddava mà ông đã chuẩn bị, hãy dâng món ấy cho Ta. ",
  "dn16:4.18.4": "Còn những thức ăn loại cứng và loại mềm khác đã chuẩn bị, hãy dâng cho chúng Tỳ-kheo.” ",
  "dn16:4.18.5": "“Vâng, bạch Thế Tôn”, Cunda, con trai người thợ rèn, vâng lời Thế Tôn, rồi đem món sūkaramaddava đã chuẩn bị dâng lên Thế Tôn. ",
  "dn16:4.18.6": "Còn những thức ăn loại cứng và loại mềm khác đã chuẩn bị, ông dâng cho chúng Tỳ-kheo. ",
  "dn16:4.19.1": "Bấy giờ, Thế Tôn gọi Cunda, con trai người thợ rèn: ",
  "dn16:4.19.2": "“Này Cunda, món sūkaramaddava còn lại của ông, hãy chôn nó xuống một hố. ",
  "dn16:4.19.3": "Này Cunda, Ta không thấy trong thế gian này, cùng với chư thiên, Ma vương, Phạm thiên, trong quần chúng gồm các sa-môn, bà-la-môn, chư thiên và loài người, có ai ăn món ấy mà có thể tiêu hóa được đúng cách, ngoại trừ Như Lai.” ",
  "dn16:4.19.4": "“Vâng, bạch Thế Tôn”, Cunda, con trai người thợ rèn, vâng lời Thế Tôn, chôn món sūkaramaddava còn lại xuống một hố, rồi đi đến chỗ Thế Tôn; đến nơi, đảnh lễ Thế Tôn và ngồi xuống một bên. ",
  "dn16:4.19.5": "Khi Cunda, con trai người thợ rèn, ngồi xuống một bên, Thế Tôn thuyết pháp, chỉ dạy, khuyến khích, làm cho phấn chấn, làm cho hoan hỷ, rồi từ chỗ ngồi đứng dậy ra đi. ",
  "dn16:4.19.6": "(...) ",
  "dn16:4.20.1": "Bấy giờ, sau khi Thế Tôn dùng bữa ăn của Cunda, con trai người thợ rèn, một cơn bệnh dữ dội phát sinh, chứng kiết lỵ ra máu, những cảm thọ đau đớn dữ dội khởi lên, gần đến cái chết. ",
  "dn16:4.20.2": "Nhưng Thế Tôn chánh niệm tỉnh giác, chịu đựng chúng mà không bị khuấy nhiễu. ",
  "dn16:4.20.3": "Bấy giờ, Thế Tôn gọi Tôn giả A-nan: ",
  "dn16:4.20.4": "“Này A-nan, chúng ta hãy đi đến Kusinārā.” ",
  "dn16:4.20.5": "“Vâng, bạch Thế Tôn”, Tôn giả A-nan vâng lời Thế Tôn. ",
  "dn16:4.20.6": "Sau khi dùng bữa ăn của Cunda, ",
  "dn16:4.20.7": "con trai người thợ rèn, như tôi được nghe; ",
  "dn16:4.20.8": "bậc Đại sĩ bị bệnh chạm đến, ",
  "dn16:4.20.9": "trầm trọng, gần đến cái chết. ",
  "dn16:4.20.10": "Và sau khi dùng món sūkaramaddava, ",
  "dn16:4.20.11": "bệnh dữ dội phát sinh nơi bậc Đạo Sư; ",
  "dn16:4.20.12": "Thế Tôn, trong khi bị tháo lỵ, đã nói: ",
  "dn16:4.20.13": "“Ta sẽ đi đến thành Kusinārā.” ",
  "dn16:4.21.0": "24. Xin nước uống ",
  "dn16:4.21.1": "Bấy giờ, Thế Tôn rời khỏi con đường, đi đến dưới một gốc cây nào đó; đến nơi, Ngài gọi Tôn giả A-nan: ",
  "dn16:4.21.2": "“Này A-nan, hãy trải cho Ta tấm y tăng-già-lê gấp bốn; Ta mệt rồi, A-nan, Ta sẽ ngồi.” ",
  "dn16:4.21.3": "“Vâng, bạch Thế Tôn”, Tôn giả A-nan vâng lời Thế Tôn, trải tấm y tăng-già-lê gấp bốn. ",
  "dn16:4.21.4": "Thế Tôn ngồi xuống trên chỗ ngồi đã được trải sẵn. ",
  "dn16:4.22.1": "Sau khi ngồi xuống, Thế Tôn gọi Tôn giả A-nan: ",
  "dn16:4.22.2": "“Này A-nan, hãy mang nước uống cho Ta, Ta khát rồi, A-nan, Ta sẽ uống.” ",
  "dn16:4.22.3": "Khi được nói vậy, Tôn giả A-nan bạch Thế Tôn như sau:",
  "dn16:4.22.4": "“Bạch Thế Tôn, vừa nay khoảng năm trăm cỗ xe đã đi qua, nên nước ấy bị bánh xe khuấy động, ít ỏi, đục ngầu và chảy lăn tăn.",
  "dn16:4.22.5": "Bạch Thế Tôn, sông Kakudhā này ở không xa, nước trong, nước ngon, nước mát, nước sạch, có bến tắm tốt, khả ái.",
  "dn16:4.22.6": "Tại đó, Thế Tôn sẽ uống nước và làm mát thân thể.”",
  "dn16:4.23.1": "Lần thứ hai, Thế Tôn gọi Tôn giả A-nan:",
  "dn16:4.23.2": "“Này A-nan, hãy đi lấy nước cho Ta, Ta khát, này A-nan, Ta sẽ uống.”",
  "dn16:4.23.3": "Lần thứ hai, Tôn giả A-nan bạch Thế Tôn như sau:",
  "dn16:4.23.4": "“Bạch Thế Tôn, vừa nay khoảng năm trăm cỗ xe đã đi qua, nên nước ấy bị bánh xe khuấy động, ít ỏi, đục ngầu và chảy lăn tăn.",
  "dn16:4.23.5": "Bạch Thế Tôn, sông Kakudhā này ở không xa, nước trong, nước ngon, nước mát, nước sạch, có bến tắm tốt, khả ái.",
  "dn16:4.23.6": "Tại đó, Thế Tôn sẽ uống nước và làm mát thân thể.”",
  "dn16:4.24.1": "Lần thứ ba, Thế Tôn gọi Tôn giả A-nan:",
  "dn16:4.24.2": "“Này A-nan, hãy đi lấy nước cho Ta, Ta khát, này A-nan, Ta sẽ uống.”",
  "dn16:4.24.3": "“Vâng, bạch Thế Tôn”, Tôn giả A-nan vâng lời Thế Tôn, cầm bát rồi đi đến con suối ấy.",
  "dn16:4.24.4": "Bấy giờ, con suối ấy vốn bị bánh xe khuấy động, ít ỏi, đục ngầu và đang chảy lăn tăn; khi Tôn giả A-nan đến gần thì trở nên trong, lắng sạch, không còn vẩn đục.",
  "dn16:4.25.1": "Bấy giờ, Tôn giả A-nan nghĩ như sau:",
  "dn16:4.25.2": "“Thật vi diệu thay, thưa chư huynh, thật hy hữu thay, thưa chư huynh, thần lực và oai lực của Như Lai.",
  "dn16:4.25.3": "Vì chính con suối này vốn bị bánh xe khuấy động, ít ỏi, đục ngầu và đang chảy lăn tăn, mà khi tôi đến gần thì trở nên trong, lắng sạch, không còn vẩn đục.”",
  "dn16:4.25.4": "Lấy nước vào bát, Tôn giả đi đến chỗ Thế Tôn; đến nơi, bạch Thế Tôn như sau:",
  "dn16:4.25.5": "“Thật vi diệu, bạch Thế Tôn, thật hy hữu, bạch Thế Tôn, thần lực và oai lực của Như Lai.",
  "dn16:4.25.6": "Bạch Thế Tôn, vừa nay con suối ấy vốn bị bánh xe khuấy động, ít ỏi, đục ngầu và đang chảy lăn tăn; khi con đến gần thì trở nên trong, lắng sạch, không còn vẩn đục.",
  "dn16:4.25.7": "Xin Thế Tôn uống nước, xin bậc Thiện Thệ uống nước.”",
  "dn16:4.25.8": "Bấy giờ, Thế Tôn đã uống nước.",
  "dn16:4.26.0": "25. Chuyện Pukkusa, con trai người Malla",
  "dn16:4.26.1": "Lúc bấy giờ, Pukkusa, con trai người Malla, đệ tử của Āḷāra Kālāma, đang đi trên con đường từ Kusinārā đến Pāvā.",
  "dn16:4.26.2": "Pukkusa, con trai người Malla, thấy Thế Tôn đang ngồi dưới một gốc cây.",
  "dn16:4.26.3": "Thấy vậy, ông đi đến chỗ Thế Tôn; đến nơi, đảnh lễ Thế Tôn rồi ngồi xuống một bên. Khi đã ngồi xuống một bên, Pukkusa, con trai người Malla, bạch Thế Tôn như sau:",
  "dn16:4.26.4": "“Thật vi diệu, bạch Thế Tôn, thật hy hữu, bạch Thế Tôn, các vị xuất gia sống an trú trong sự an tịnh.",
  "dn16:4.27.1": "Thuở trước, bạch Thế Tôn, Āḷāra Kālāma đang đi trên đường, rời khỏi đường cái và ngồi nghỉ ban ngày dưới một gốc cây không xa.",
  "dn16:4.27.2": "Bấy giờ, bạch Thế Tôn, khoảng năm trăm cỗ xe lần lượt đi ngang qua sát bên Āḷāra Kālāma.",
  "dn16:4.27.3": "Rồi, bạch Thế Tôn, có một người đi theo sau đoàn xe ấy, từ phía sau tiến đến chỗ Āḷāra Kālāma; đến nơi, nói với Āḷāra Kālāma như sau:”",
  "dn16:4.27.4": "‘Nhưng, bạch ngài, ngài có thấy khoảng năm trăm cỗ xe đi ngang qua không?’ ",
  "dn16:4.27.5": "‘Này hiền giả, ta không thấy.’ ",
  "dn16:4.27.6": "‘Nhưng, bạch ngài, ngài có nghe tiếng không?’ ",
  "dn16:4.27.7": "‘Này hiền giả, ta không nghe tiếng.’ ",
  "dn16:4.27.8": "‘Nhưng, bạch ngài, ngài có ngủ không?’ ",
  "dn16:4.27.9": "‘Này hiền giả, ta không ngủ.’ ",
  "dn16:4.27.10": "‘Nhưng, bạch ngài, ngài có tỉnh giác không?’ ",
  "dn16:4.27.11": "‘Đúng vậy, này hiền giả.’ ",
  "dn16:4.27.12": "‘Vậy thì, bạch ngài, khi đang tỉnh giác và thức, ngài đã không thấy khoảng năm trăm cỗ xe lần lượt đi ngang qua, cũng không nghe tiếng; ",
  "dn16:4.27.13": "thậm chí y của ngài, bạch ngài, còn bị bụi phủ đầy sao?’ ",
  "dn16:4.27.14": "‘Đúng vậy, này hiền giả.’ ",
  "dn16:4.27.15": "Bấy giờ, bạch Thế Tôn, người ấy nghĩ rằng: ",
  "dn16:4.27.16": "‘Thật vi diệu thay, thưa ông; thật hy hữu thay, thưa ông; các vị xuất gia an trú thật an tịnh thay. ",
  "dn16:4.27.17": "Đến mức khi đang tỉnh giác và thức mà không thấy khoảng năm trăm cỗ xe lần lượt đi ngang qua, cũng không nghe tiếng.’ ",
  "dn16:4.27.18": "Sau khi bày tỏ lòng tịnh tín lớn lao đối với Āḷāra Kālāma, ông ấy ra đi.’",
  "dn16:4.28.1": "‘Ông nghĩ sao, này Pukkusa, ",
  "dn16:4.28.2": "điều nào khó làm hơn, khó đạt được hơn—",
  "dn16:4.28.3": "một người khi đang tỉnh giác và thức mà không thấy khoảng năm trăm cỗ xe lần lượt đi ngang qua, cũng không nghe tiếng; ",
  "dn16:4.28.4": "hay một người khi đang tỉnh giác và thức, trong lúc trời mưa, sấm vang ầm ầm, chớp lóe sáng, sét đánh nổ, mà không thấy, cũng không nghe tiếng?’ ",
  "dn16:4.29.1": "‘Bạch ngài, năm trăm cỗ xe, hay sáu trăm cỗ xe, bảy trăm cỗ xe, tám trăm cỗ xe, chín trăm cỗ xe, một ngàn cỗ xe hay một trăm ngàn cỗ xe thì có đáng gì. ",
  "dn16:4.29.2": "Chính điều này mới khó làm hơn và khó đạt được hơn: một người khi đang tỉnh giác và thức, trong lúc trời mưa, sấm vang ầm ầm, chớp lóe sáng, sét đánh nổ, mà không thấy, cũng không nghe tiếng.’ ",
  "dn16:4.30.1": "‘Này Pukkusa, có một thời ta trú tại Ātumā, trong một nhà chứa rơm. ",
  "dn16:4.30.2": "Lúc bấy giờ, khi trời mưa, sấm vang ầm ầm, chớp lóe sáng, sét đánh nổ, thì ở không xa nhà chứa rơm, hai anh em người cày ruộng và bốn con bò đực đã bị chết. ",
  "dn16:4.30.3": "Rồi, này Pukkusa, dân chúng đông đảo ở Ātumā đi ra và kéo đến chỗ hai anh em người cày ruộng và bốn con bò đực bị chết ấy. ",
  "dn16:4.31.1": "Lúc bấy giờ, này Pukkusa, ta đi ra khỏi nhà chứa rơm và đang kinh hành ngoài trời trước cửa nhà chứa rơm. ",
  "dn16:4.31.2": "Rồi, này Pukkusa, một người từ trong đám đông ấy đi đến chỗ ta; đến nơi, đảnh lễ ta rồi đứng sang một bên. Khi người ấy đứng sang một bên, này Pukkusa, ta nói với người ấy rằng: ",
  "dn16:4.32.1": "‘Này hiền giả, vì sao đám đông này lại tụ họp?’ ",
  "dn16:4.32.2": "‘Bạch ngài, vừa rồi khi trời mưa, sấm vang ầm ầm, chớp lóe sáng, sét đánh nổ, hai anh em người cày ruộng và bốn con bò đực đã bị chết. ",
  "dn16:4.32.3": "Vì việc ấy mà đám đông này tụ họp. ",
  "dn16:4.32.4": "Còn ngài, bạch ngài, lúc ấy ở đâu?’ ",
  "dn16:4.32.5": "‘Chính tại đây, này hiền hữu, tôi đã ở.’",
  "dn16:4.32.6": "‘Nhưng, bạch ngài, ngài có thấy không?’",
  "dn16:4.32.7": "‘Này hiền hữu, tôi đã không thấy.’",
  "dn16:4.32.8": "‘Nhưng, bạch ngài, ngài có nghe tiếng không?’",
  "dn16:4.32.9": "‘Này hiền hữu, tôi đã không nghe tiếng.’",
  "dn16:4.32.10": "‘Nhưng, bạch ngài, ngài có ngủ không?’",
  "dn16:4.32.11": "‘Này hiền hữu, tôi đã không ngủ.’",
  "dn16:4.32.12": "‘Nhưng, bạch ngài, ngài có tỉnh giác không?’",
  "dn16:4.32.13": "‘Đúng vậy, này hiền hữu.’",
  "dn16:4.32.14": "‘Vậy thì, bạch ngài, khi ngài đang tỉnh giác, đang thức, trời mưa, trời gầm vang, chớp lóe lên, sét nổ, mà ngài lại không thấy, cũng không nghe tiếng sao?’",
  "dn16:4.32.15": "‘Đúng vậy, này hiền hữu.’",
  "dn16:4.33.1": "Bấy giờ, này Pukkusa, người ấy nghĩ rằng:",
  "dn16:4.33.2": "‘Thật vi diệu thay, thưa ngài, thật hy hữu thay, thưa ngài, các vị xuất gia an trú với sự an tịnh như vậy.",
  "dn16:4.33.3": "Thật vậy, một người đang tỉnh giác, đang thức, khi trời mưa, trời gầm vang, chớp lóe lên, sét nổ, mà lại không thấy, cũng không nghe tiếng.’",
  "dn16:4.33.4": "Sau khi bày tỏ lòng tịnh tín lớn lao đối với tôi, người ấy đảnh lễ tôi, đi nhiễu bên phải rồi ra đi.’",
  "dn16:4.34.1": "Khi được nói vậy, Pukkusa, con trai dòng Malla, bạch Thế Tôn rằng:",
  "dn16:4.34.2": "“Bạch Thế Tôn, lòng tịnh tín nào con có đối với Āḷāra Kālāma, con xin quăng nó đi trong cơn gió lớn hoặc cuốn trôi nó theo dòng sông chảy xiết.",
  "dn16:4.34.3": "Thật tuyệt vời, bạch Thế Tôn, thật tuyệt vời, bạch Thế Tôn.",
  "dn16:4.34.4": "Ví như, bạch Thế Tôn, người ta dựng đứng lại vật bị úp xuống, mở ra vật bị che kín, chỉ đường cho kẻ lạc lối, đem đèn vào trong bóng tối để những ai có mắt có thể thấy các sắc; cũng vậy, Chánh pháp đã được Thế Tôn trình bày bằng nhiều phương cách.",
  "dn16:4.34.5": "Bạch Thế Tôn, con xin quy y Thế Tôn, quy y Pháp và quy y Tỳ-kheo Tăng.",
  "dn16:4.34.6": "Xin Thế Tôn ghi nhận con là nam cư sĩ từ nay cho đến mạng chung đã quy y.”",
  "dn16:4.35.1": "Bấy giờ Pukkusa, con trai dòng Malla, gọi một người rằng:",
  "dn16:4.35.2": "“Này anh, hãy mang đến cho tôi một cặp y màu vàng óng để mặc.”",
  "dn16:4.35.3": "“Vâng, thưa ngài.” Người ấy vâng lời Pukkusa, con trai dòng Malla, rồi mang đến cặp y màu vàng óng ấy để mặc.",
  "dn16:4.35.4": "Bấy giờ Pukkusa, con trai dòng Malla, dâng cặp y màu vàng óng ấy lên Thế Tôn:",
  "dn16:4.35.5": "“Bạch Thế Tôn, đây là cặp y màu vàng óng để mặc, xin Thế Tôn nhận cho con vì lòng thương tưởng.”",
  "dn16:4.35.6": "“Vậy thì, này Pukkusa, hãy dùng một tấm đắp cho Ta, một tấm đắp cho Ānanda.”",
  "dn16:4.35.7": "“Vâng, bạch Thế Tôn.” Pukkusa, con trai dòng Malla, vâng lời Thế Tôn, lấy một tấm đắp cho Thế Tôn, một tấm đắp cho tôn giả Ānanda.",
  "dn16:4.36.1": "Bấy giờ Thế Tôn thuyết pháp cho Pukkusa, con trai dòng Malla, khiến ông ấy hiểu rõ, khuyến khích, làm phấn chấn, làm hoan hỷ.",
  "dn16:4.36.2": "Rồi Pukkusa, con trai dòng Malla, sau khi được Thế Tôn thuyết pháp khiến hiểu rõ, khuyến khích, làm phấn chấn, làm hoan hỷ, liền từ chỗ ngồi đứng dậy, đảnh lễ Thế Tôn, đi nhiễu bên phải rồi ra đi.",
  "dn16:4.37.1": "Bấy giờ, tôn giả A-nan, sau khi Pukkusa, con trai dòng Malla, vừa đi khỏi không bao lâu, đem cặp y màu vàng ròng ấy đắp lên thân Thế Tôn.",
  "dn16:4.37.2": "Khi được đắp lên thân Thế Tôn, nó trông như đã mất hết vẻ sáng chói.",
  "dn16:4.37.3": "Bấy giờ, tôn giả A-nan bạch Thế Tôn rằng:",
  "dn16:4.37.4": "“Thật vi diệu, bạch Thế Tôn, thật hy hữu, bạch Thế Tôn, sắc da của Như Lai thanh tịnh và sáng chói đến dường ấy.",
  "dn16:4.37.5": "Bạch Thế Tôn, cặp y màu vàng ròng này khi đắp lên thân Thế Tôn thì trông như đã mất hết vẻ sáng chói.”",
  "dn16:4.37.6": "“Đúng vậy, A-nan, đúng vậy, A-nan, có hai thời điểm thân Như Lai đặc biệt thanh tịnh, sắc da đặc biệt sáng chói.",
  "dn16:4.38.1": "Là hai thời điểm nào?",
  "dn16:4.38.2": "Này A-nan, đó là đêm Như Lai chứng ngộ vô thượng chánh đẳng giác, và đêm Như Lai nhập Niết-bàn không còn dư y.",
  "dn16:4.38.3": "Này A-nan, chính trong hai thời điểm ấy thân Như Lai đặc biệt thanh tịnh, sắc da đặc biệt sáng chói.",
  "dn16:4.38.4": "Nhưng hôm nay, này A-nan, vào canh cuối của đêm, tại rừng sa-la của người Malla ở Upavattana thuộc Kusinārā, giữa hai cây sa-la song đôi, Như Lai sẽ nhập Niết-bàn.",
  "dn16:4.38.5": "Nào, A-nan, chúng ta hãy đi đến sông Kakutthā.”",
  "dn16:4.38.6": "“Vâng, bạch Thế Tôn,” tôn giả A-nan vâng đáp Thế Tôn.",
  "dn16:4.38.7": "Cặp y màu vàng ròng,",
  "dn16:4.38.8": "Pukkusa đã mang đến;",
  "dn16:4.38.9": "Bậc Đạo Sư được phủ bằng nó,",
  "dn16:4.38.10": "lại càng rực sáng như sắc vàng.",
  "dn16:4.38.11": "(...)",
  "dn16:4.39.1": "Bấy giờ, Thế Tôn cùng với đại chúng Tỳ-kheo đi đến sông Kakutthā; đến nơi, Ngài xuống sông Kakutthā tắm và uống nước, rồi lên bờ đi đến vườn xoài.",
  "dn16:4.39.2": "Đến nơi, Ngài gọi tôn giả Cunda rằng:",
  "dn16:4.39.3": "“Này Cunda, hãy trải cho Ta tấm y tăng-già-lê gấp bốn; Ta mệt rồi, Cunda, Ta sẽ nằm xuống.”",
  "dn16:4.40.1": "“Vâng, bạch Thế Tôn,” tôn giả Cunda vâng lời Thế Tôn, trải tấm y tăng-già-lê gấp bốn ra.",
  "dn16:4.40.2": "Bấy giờ, Thế Tôn nằm xuống theo thế nằm sư tử, nghiêng hông bên phải, chân này đặt lên chân kia, chánh niệm tỉnh giác, tác ý đến tưởng sẽ đứng dậy.",
  "dn16:4.40.3": "Còn tôn giả Cunda thì ngồi ngay tại đó trước mặt Thế Tôn.",
  "dn16:4.41.1": "Đức Phật đi đến dòng sông Kakutthā,",
  "dn16:4.41.2": "nước trong, nước mát, trong suốt;",
  "dn16:4.41.3": "Bậc Đạo Sư xuống tắm, thân không mệt mỏi,",
  "dn16:4.41.4": "Như Lai, bậc vô song ở đời.",
  "dn16:4.41.5": "Tắm xong và uống nước xong, bậc Đạo Sư bước lên bờ,",
  "dn16:4.41.6": "đi trước giữa chúng Tỳ-kheo;",
  "dn16:4.41.7": "Thế Tôn là bậc thuyết giảng, bậc chuyển vận Pháp ở đời này,",
  "dn16:4.41.8": "Bậc Đại Ẩn sĩ đi đến vườn xoài.",
  "dn16:4.41.9": "Ngài gọi vị tỳ-kheo tên là Cunda,",
  "dn16:4.41.10": "“Hãy trải cho ta một chỗ nằm gấp bốn lớp;",
  "dn16:4.41.11": "Được thúc giục, Cunda với tâm đã được tu tập,",
  "dn16:4.41.12": "liền mau chóng trải chỗ nằm gấp bốn lớp;",
  "dn16:4.41.13": "Bậc Đạo Sư nằm xuống, thân không mệt mỏi,",
  "dn16:4.41.14": "và Cunda cũng ngồi ở phía trước tại đó.",
  "dn16:4.42.1": "Bấy giờ, Thế Tôn gọi Tôn giả Ānanda:",
  "dn16:4.42.2": "“Này Ānanda, có thể có người khiến Cunda, con người thợ rèn, khởi lên hối tiếc rằng:",
  "dn16:4.42.3": "‘Này hiền giả Cunda, thật là bất lợi cho ông, thật là không khéo được cho ông, vì Như Lai sau khi dùng bữa ăn cuối cùng của ông thì đã nhập Niết-bàn.’",
  "dn16:4.42.4": "Này Ānanda, cần phải xóa bỏ sự hối tiếc ấy của Cunda, con người thợ rèn, như sau:",
  "dn16:4.42.5": "‘Này hiền giả Cunda, thật là lợi ích cho ông, thật là khéo được cho ông,",
  "dn16:4.42.6": "vì Như Lai sau khi dùng bữa ăn cuối cùng của ông thì đã nhập Niết-bàn.",
  "dn16:4.42.7": "Này hiền giả Cunda, điều này tôi đã được nghe trực tiếp từ Thế Tôn, đã được thọ nhận trực tiếp:",
  "dn16:4.42.8": "có hai bữa ăn có quả bằng nhau, có dị thục bằng nhau, và còn có quả lớn hơn, lợi ích lớn hơn rất nhiều so với các bữa ăn khác.",
  "dn16:4.42.9": "Hai bữa ấy là những bữa nào?",
  "dn16:4.42.10": "Bữa ăn mà sau khi dùng, Như Lai chứng ngộ Vô thượng Chánh đẳng Chánh giác; và bữa ăn mà sau khi dùng, Như Lai nhập Niết-bàn vào giới Niết-bàn không còn dư y.",
  "dn16:4.42.11": "Hai bữa ăn này có quả bằng nhau, có dị thục bằng nhau, và còn có quả lớn hơn, lợi ích lớn hơn rất nhiều so với các bữa ăn khác.",
  "dn16:4.42.12": "Tôn giả Cunda, con người thợ rèn, đã tích lũy nghiệp đưa đến thọ mạng, đã tích lũy nghiệp đưa đến dung sắc, đã tích lũy nghiệp đưa đến an lạc, đã tích lũy nghiệp đưa đến danh tiếng, đã tích lũy nghiệp đưa đến cõi trời, đã tích lũy nghiệp đưa đến quyền uy.’",
  "dn16:4.42.13": "Này Ānanda, cần phải xóa bỏ sự hối tiếc ấy của Cunda, con người thợ rèn, như vậy.”",
  "dn16:4.43.1": "Bấy giờ, Thế Tôn sau khi biết ý nghĩa này, vào lúc ấy đã thốt lên lời cảm hứng này:",
  "dn16:4.43.2": "“Phước tăng trưởng nơi người bố thí,",
  "dn16:4.43.3": "Oán thù không tích tụ nơi người tự chế,",
  "dn16:4.43.4": "Người thiện xảo từ bỏ điều ác,",
  "dn16:4.43.5": "Do đoạn tận tham, sân, si mà được tịch tịnh.”",
  "dn16:4.43.6": "Phần tụng đọc thứ tư.",
  "dn16:5.1.0": "26. Song thọ",
  "dn16:5.1.1": "Bấy giờ, Thế Tôn gọi Tôn giả Ānanda:",
  "dn16:5.1.2": "“Này Ānanda, hãy đi, chúng ta sẽ đến bờ bên kia sông Hiraññavatī, đến rừng cây sāla của dân Malla tại Upavattana gần Kusinārā.”",
  "dn16:5.1.3": "“Vâng, bạch Thế Tôn,” Tôn giả Ānanda vâng đáp Thế Tôn.",
  "dn16:5.1.4": "Bấy giờ, Thế Tôn cùng với đại chúng Tỳ-kheo đi đến bờ bên kia sông Hiraññavatī, đến rừng cây sāla của bộ tộc Malla tại Upavattana gần Kusinārā. Đến nơi, Ngài gọi Tôn giả Ānanda:",
  "dn16:5.1.5": "“Này Ānanda, hãy trải cho Ta một chiếc giường giữa hai cây sāla song đôi, đầu hướng về phương bắc. Ta mệt rồi, này Ānanda, Ta sẽ nằm xuống.”",
  "dn16:5.1.6": "“Vâng, bạch Thế Tôn.” Tôn giả Ānanda vâng lời Thế Tôn, trải một chiếc giường giữa hai cây sāla song đôi, đầu hướng về phương bắc.",
  "dn16:5.1.7": "Rồi Thế Tôn nằm xuống theo thế nằm sư tử, nghiêng hông bên phải, chân này đặt chồng lên chân kia, tỉnh giác và chánh niệm.",
  "dn16:5.2.1": "Lúc bấy giờ, hai cây sāla song đôi đều nở rộ hoa trái mùa.",
  "dn16:5.2.2": "Những hoa ấy rơi xuống, phủ xuống, rải đầy trên thân Như Lai để cúng dường Như Lai.",
  "dn16:5.2.3": "Cả những hoa mandārava cõi trời cũng từ hư không rơi xuống; chúng rơi xuống, phủ xuống, rải đầy trên thân Như Lai để cúng dường Như Lai.",
  "dn16:5.2.4": "Cả những bột chiên-đàn cõi trời cũng từ hư không rơi xuống; chúng rơi xuống, phủ xuống, rải đầy trên thân Như Lai để cúng dường Như Lai.",
  "dn16:5.2.5": "Cả những nhạc khí cõi trời cũng vang lên giữa hư không để cúng dường Như Lai.",
  "dn16:5.2.6": "Cả những khúc nhạc cõi trời cũng vang lên giữa hư không để cúng dường Như Lai.",
  "dn16:5.3.1": "Rồi Thế Tôn gọi Tôn giả Ānanda:",
  "dn16:5.3.2": "“Này Ānanda, hai cây sāla song đôi đều nở rộ hoa trái mùa.",
  "dn16:5.3.3": "Những hoa ấy rơi xuống, phủ xuống, rải đầy trên thân Như Lai để cúng dường Như Lai.",
  "dn16:5.3.4": "Cả những hoa mandārava cõi trời cũng từ hư không rơi xuống; chúng rơi xuống, phủ xuống, rải đầy trên thân Như Lai để cúng dường Như Lai.",
  "dn16:5.3.5": "Cả những bột chiên-đàn cõi trời cũng từ hư không rơi xuống; chúng rơi xuống, phủ xuống, rải đầy trên thân Như Lai để cúng dường Như Lai.",
  "dn16:5.3.6": "Cả những nhạc khí cõi trời cũng vang lên giữa hư không để cúng dường Như Lai.",
  "dn16:5.3.7": "Cả những khúc nhạc cõi trời cũng vang lên giữa hư không để cúng dường Như Lai.",
  "dn16:5.3.8": "Nhưng này Ānanda, không phải chỉ đến mức ấy mà Như Lai được tôn kính, được trọng vọng, được kính mến, được cúng dường, được tôn sùng.",
  "dn16:5.3.9": "Này Ānanda, vị Tỳ-kheo hay Tỳ-kheo-ni, nam cư sĩ hay nữ cư sĩ nào sống thực hành đúng pháp, hành trì thuận pháp, cư xử đúng đắn, sống theo pháp, vị ấy mới là người tôn kính Như Lai, trọng vọng Như Lai, kính mến Như Lai, cúng dường Như Lai, tôn sùng Như Lai bằng sự cúng dường tối thượng.",
  "dn16:5.3.10": "Vì vậy, này Ānanda, hãy sống thực hành đúng pháp, hành trì thuận pháp, cư xử đúng đắn, sống theo pháp.",
  "dn16:5.3.11": "Này Ānanda, các ông cần phải học tập như vậy.”",
  "dn16:5.4.0": "27. Trưởng lão Upavāṇa",
  "dn16:5.4.1": "Lúc bấy giờ, Tôn giả Upavāṇa đang đứng trước mặt Thế Tôn, quạt hầu Thế Tôn.",
  "dn16:5.4.2": "Rồi Thế Tôn bảo Tôn giả Upavāṇa lui ra:",
  "dn16:5.4.3": "“Hãy tránh ra, này Tỳ-kheo, đừng đứng trước mặt Ta.”",
  "dn16:5.4.4": "Bấy giờ, Tôn giả Ānanda nghĩ rằng:",
  "dn16:5.4.5": "“Tôn giả Upavāṇa này đã hầu cận Thế Tôn từ lâu, thường ở gần và đi lại bên cạnh Ngài.",
  "dn16:5.4.6": "Thế mà nay, vào lúc cuối cùng, Thế Tôn lại bảo Tôn giả Upavāṇa lui ra:",
  "dn16:5.4.7": "‘Hãy tránh ra, này Tỳ-kheo, đừng đứng trước mặt Ta.’",
  "dn16:5.4.8": "Vậy nhân gì, duyên gì mà Thế Tôn lại bảo Tôn giả Upavāṇa lui ra:",
  "dn16:5.4.9": "‘Hãy tránh ra, này tỳ-kheo, chớ đứng trước mặt Ta’?",
  "dn16:5.5.1": "Bấy giờ Tôn giả Ānanda bạch Thế Tôn rằng:",
  "dn16:5.5.2": "“Bạch Thế Tôn, Tôn giả Upavāṇa này từ lâu đã là người hầu cận Thế Tôn, thường ở gần và đi theo bên cạnh.",
  "dn16:5.5.3": "Thế mà nay Thế Tôn vào lúc cuối cùng lại bảo Tôn giả Upavāṇa tránh ra:",
  "dn16:5.5.4": "‘Hãy tránh ra, này tỳ-kheo, chớ đứng trước mặt Ta’.",
  "dn16:5.5.5": "Bạch Thế Tôn, nhân gì, duyên gì mà Thế Tôn bảo Tôn giả Upavāṇa tránh ra:",
  "dn16:5.5.6": "‘Hãy tránh ra, này tỳ-kheo, chớ đứng trước mặt Ta’?”",
  "dn16:5.5.7": "“Này Ānanda, phần lớn chư thiên trong mười thế giới đã tụ hội để chiêm ngưỡng Như Lai.",
  "dn16:5.5.8": "Này Ānanda, trong phạm vi rừng sāla của dân Mallā tại Upavattana ở Kusinārā, rộng mười hai do-tuần chung quanh, không có một chỗ nào dù nhỏ bằng đầu sợi lông mà không có các vị đại oai đức thiên chiếm đầy.",
  "dn16:5.5.9": "Này Ānanda, chư thiên than phiền rằng:",
  "dn16:5.5.10": "‘Chúng ta từ xa đến để chiêm ngưỡng Như Lai.",
  "dn16:5.5.11": "Hiếm khi lắm mới có các Như Lai, các bậc A-la-hán, các bậc Chánh Đẳng Giác xuất hiện ở đời.",
  "dn16:5.5.12": "Ngay đêm nay, vào canh cuối, Như Lai sẽ nhập parinibbāna.",
  "dn16:5.5.13": "Thế mà vị tỳ-kheo đại oai đức này đứng trước mặt Thế Tôn che khuất, khiến chúng ta không được chiêm ngưỡng Như Lai vào lúc cuối cùng’.”",
  "dn16:5.6.1": "“Bạch Thế Tôn, Thế Tôn tác ý đến chư thiên như thế nào?”",
  "dn16:5.6.2": "“Này Ānanda, có những chư thiên ở trên hư không còn tưởng là đất, xõa tóc than khóc, giơ tay than khóc, ngã lăn xuống, lăn qua lộn lại:",
  "dn16:5.6.3": "‘Thế Tôn sắp nhập parinibbāna quá nhanh, Thiện Thệ sắp nhập parinibbāna quá nhanh, con mắt của đời sắp biến mất quá nhanh’.",
  "dn16:5.6.4": "Này Ānanda, có những chư thiên ở trên mặt đất còn tưởng là đất, xõa tóc than khóc, giơ tay than khóc, ngã lăn xuống, lăn qua lộn lại:",
  "dn16:5.6.5": "‘Thế Tôn sắp nhập parinibbāna quá nhanh, Thiện Thệ sắp nhập parinibbāna quá nhanh, con mắt của đời sắp biến mất quá nhanh’.",
  "dn16:5.6.6": "Còn những chư thiên đã ly tham thì tỉnh táo chánh niệm mà kham nhẫn:",
  "dn16:5.6.7": "‘Các hành là vô thường, ở đây có thể làm gì được?’”",
  "dn16:5.7.0": "28. Bốn thánh tích gây xúc động",
  "dn16:5.7.1": "“Trước đây, bạch Thế Tôn, các tỳ-kheo sau khi an cư mùa mưa ở các phương đều đến để chiêm ngưỡng Như Lai.",
  "dn16:5.7.2": "Chúng con được thấy các vị tỳ-kheo đáng kính, được đến gần phụng sự.",
  "dn16:5.7.3": "Nhưng sau khi Thế Tôn diệt độ, bạch Thế Tôn, chúng con sẽ không còn được thấy các vị tỳ-kheo đáng kính, không còn được đến gần phụng sự.”",
  "dn16:5.8.1": "“Này Ānanda, có bốn nơi đáng chiêm bái, đáng xúc động đối với người con trai hiền tín thành.",
  "dn16:5.8.2": "Bốn nơi ấy là gì?",
  "dn16:5.8.3": "‘Tại đây Như Lai đản sinh’, này Ānanda, đó là nơi đáng chiêm bái, đáng xúc động đối với người con trai hiền tín thành.",
  "dn16:5.8.4": "‘Tại đây Như Lai đã chứng ngộ Vô thượng Chánh đẳng Chánh giác’, này Ānanda, đó là nơi đáng chiêm bái, đáng xúc động đối với người con trai hiền tín thành.",
  "dn16:5.8.5": "‘Tại đây Như Lai đã chuyển bánh xe Pháp vô thượng’, này Ānanda, đó là nơi đáng chiêm bái, đáng xúc động đối với người con trai hiền tín thành.",
  "dn16:5.8.6": "‘Ở đây Như Lai đã nhập Niết-bàn không còn dư y’ này, này A-nan, là nơi đáng được người con trai có lòng tin đến chiêm bái và khởi cảm hứng.",
  "dn16:5.8.7": "Này A-nan, đây là bốn nơi đáng được người con trai có lòng tin đến chiêm bái và khởi cảm hứng.",
  "dn16:5.8.8": "Này A-nan, sẽ có các Tỳ-kheo, Tỳ-kheo-ni, nam cư sĩ, nữ cư sĩ có lòng tin đến rằng:",
  "dn16:5.8.9": "‘Ở đây Như Lai đản sinh’, ‘ở đây Như Lai đã chứng ngộ Vô thượng Chánh đẳng Chánh giác’, ‘ở đây Như Lai đã chuyển bánh xe Pháp vô thượng’, ‘ở đây Như Lai đã nhập Niết-bàn không còn dư y’.",
  "dn16:5.8.10": "Này A-nan, bất cứ ai đi chiêm bái các thánh tích với tâm thanh tịnh mà mạng chung, tất cả những người ấy sau khi thân hoại mạng chung sẽ được sinh vào cõi lành, cõi trời.”",
  "dn16:5.9.0": "29. Lời hỏi của A-nan",
  "dn16:5.9.1": "“Bạch Thế Tôn, chúng con phải ứng xử thế nào đối với nữ giới?”",
  "dn16:5.9.2": "“Này A-nan, đừng nhìn.”",
  "dn16:5.9.3": "“Bạch Thế Tôn, nếu có nhìn thì phải ứng xử thế nào?”",
  "dn16:5.9.4": "“Này A-nan, đừng nói chuyện.”",
  "dn16:5.9.5": "“Nhưng bạch Thế Tôn, nếu đang nói chuyện thì phải ứng xử thế nào?”",
  "dn16:5.9.6": "“Này A-nan, phải an trú chánh niệm.”",
  "dn16:5.10.1": "“Bạch Thế Tôn, chúng con phải ứng xử thế nào đối với nhục thân của Như Lai?”",
  "dn16:5.10.2": "“Này A-nan, các ông đừng bận tâm đến việc cúng dường nhục thân của Như Lai.",
  "dn16:5.10.3": "Này A-nan, hãy nỗ lực vì mục đích cốt lõi, hãy chuyên tâm vào mục đích cốt lõi, hãy sống không phóng dật, nhiệt tâm, chuyên chú vào mục đích cốt lõi.",
  "dn16:5.10.4": "Này A-nan, có các vị hiền trí trong hàng Sát-đế-lỵ, hiền trí trong hàng Bà-la-môn, hiền trí trong hàng gia chủ, những người có lòng tịnh tín đối với Như Lai; họ sẽ cúng dường nhục thân của Như Lai.”",
  "dn16:5.11.1": "“Nhưng bạch Thế Tôn, phải ứng xử thế nào đối với nhục thân của Như Lai?”",
  "dn16:5.11.2": "“Này A-nan, như người ta ứng xử đối với nhục thân của vị Chuyển luân vương thế nào, thì cũng phải ứng xử đối với nhục thân của Như Lai như thế ấy.”",
  "dn16:5.11.3": "“Nhưng bạch Thế Tôn, người ta ứng xử thế nào đối với nhục thân của vị Chuyển luân vương?”",
  "dn16:5.11.4": "“Này A-nan, nhục thân của vị Chuyển luân vương được quấn bằng vải mới, quấn vải mới xong lại quấn bằng bông đã chải, quấn bông đã chải xong lại quấn bằng vải mới.",
  "dn16:5.11.5": "Theo cách ấy, quấn nhục thân của vị Chuyển luân vương bằng năm trăm lớp đôi, rồi đặt vào một quan tài sắt đựng dầu, đậy lại bằng một quan tài sắt khác, làm giàn hỏa bằng mọi thứ hương thơm rồi hỏa táng nhục thân của vị Chuyển luân vương.",
  "dn16:5.11.6": "Người ta dựng một tháp cho vị Chuyển luân vương ở ngã tư đường lớn.",
  "dn16:5.11.7": "Này A-nan, người ta ứng xử đối với nhục thân của vị Chuyển luân vương như vậy.",
  "dn16:5.11.8": "Này A-nan, như người ta ứng xử đối với nhục thân của vị Chuyển luân vương thế nào, thì cũng phải ứng xử đối với nhục thân của Như Lai như thế ấy.",
  "dn16:5.11.9": "Tháp của Như Lai phải được dựng ở ngã tư đường lớn.",
  "dn16:5.11.10": "Tại đó, những ai dâng hoa, hương, bột thơm, hoặc đảnh lễ, hoặc khởi lòng tịnh tín, thì điều ấy sẽ đem lại lợi ích và an lạc lâu dài cho họ.",
  "dn16:5.12.0": "30. Những hạng người xứng đáng được dựng tháp",
  "dn16:5.12.1": "Này A-nan, có bốn hạng người xứng đáng được dựng tháp.",
  "dn16:5.12.2": "Bốn hạng ấy là những ai?",
  "dn16:5.12.3": "Như Lai, bậc A-la-hán, Chánh đẳng Chánh giác xứng đáng được dựng tháp; bậc Độc giác Phật xứng đáng được dựng tháp; đệ tử của Như Lai xứng đáng được dựng tháp; vị vua Chuyển luân xứng đáng được dựng tháp.",
  "dn16:5.12.4": "Này Ānanda, do nhân duyên gì mà Như Lai, bậc A-la-hán, Chánh Đẳng Giác xứng đáng được dựng tháp?",
  "dn16:5.12.5": "‘Đây là tháp của Thế Tôn, bậc A-la-hán, Chánh Đẳng Giác ấy’, này Ānanda, nhiều người khởi lòng tịnh tín.",
  "dn16:5.12.6": "Họ sau khi khởi lòng tịnh tín tại đó, khi thân hoại mạng chung, được sinh vào cõi lành, cõi trời.",
  "dn16:5.12.7": "Này Ānanda, chính do nhân duyên ấy mà Như Lai, bậc A-la-hán, Chánh Đẳng Giác xứng đáng được dựng tháp.",
  "dn16:5.12.8": "Này Ānanda, do nhân duyên gì mà bậc Độc Giác Phật xứng đáng được dựng tháp?",
  "dn16:5.12.9": "‘Đây là tháp của Thế Tôn, bậc Độc Giác Phật ấy’, này Ānanda, nhiều người khởi lòng tịnh tín.",
  "dn16:5.12.10": "Họ sau khi khởi lòng tịnh tín tại đó, khi thân hoại mạng chung, được sinh vào cõi lành, cõi trời.",
  "dn16:5.12.11": "Này Ānanda, chính do nhân duyên ấy mà bậc Độc Giác Phật xứng đáng được dựng tháp.",
  "dn16:5.12.12": "Này Ānanda, do nhân duyên gì mà đệ tử của Như Lai xứng đáng được dựng tháp?",
  "dn16:5.12.13": "‘Đây là tháp của đệ tử của Thế Tôn, bậc A-la-hán, Chánh Đẳng Giác ấy’, này Ānanda, nhiều người khởi lòng tịnh tín.",
  "dn16:5.12.14": "Họ sau khi khởi lòng tịnh tín tại đó, khi thân hoại mạng chung, được sinh vào cõi lành, cõi trời.",
  "dn16:5.12.15": "Này Ānanda, chính do nhân duyên ấy mà đệ tử của Như Lai xứng đáng được dựng tháp.",
  "dn16:5.12.16": "Này Ānanda, do nhân duyên gì mà vị Chuyển luân vương xứng đáng được dựng tháp?",
  "dn16:5.12.17": "‘Đây là tháp của vị pháp vương chân chánh ấy’, này Ānanda, nhiều người khởi lòng tịnh tín.",
  "dn16:5.12.18": "Họ sau khi khởi lòng tịnh tín tại đó, khi thân hoại mạng chung, được sinh vào cõi lành, cõi trời.",
  "dn16:5.12.19": "Này Ānanda, chính do nhân duyên ấy mà vị Chuyển luân vương xứng đáng được dựng tháp.",
  "dn16:5.12.20": "Này Ānanda, đây là bốn hạng xứng đáng được dựng tháp.”",
  "dn16:5.13.0": "31. Pháp kỳ diệu về Ānanda",
  "dn16:5.13.1": "Bấy giờ Tôn giả Ānanda đi vào tịnh xá, tựa đầu vào khung cửa mà đứng khóc:",
  "dn16:5.13.2": "“Ta vẫn còn là bậc hữu học, còn việc phải làm, mà sự viên tịch của bậc Đạo Sư, người thương tưởng ta, sắp xảy ra.”",
  "dn16:5.13.3": "Bấy giờ Thế Tôn gọi các tỳ-kheo:",
  "dn16:5.13.4": "“Này các tỳ-kheo, Ānanda ở đâu?”",
  "dn16:5.13.5": "“Bạch Thế Tôn, Tôn giả Ānanda ấy đã đi vào tịnh xá, tựa đầu vào khung cửa mà đứng khóc:",
  "dn16:5.13.6": "‘Ta vẫn còn là bậc hữu học, còn việc phải làm, mà sự viên tịch của bậc Đạo Sư, người thương tưởng ta, sắp xảy ra.’”",
  "dn16:5.13.7": "Bấy giờ Thế Tôn bảo một vị tỳ-kheo:",
  "dn16:5.13.8": "“Này tỳ-kheo, hãy đi nhân danh Ta gọi Ānanda rằng:",
  "dn16:5.13.9": "‘Này hiền giả Ānanda, bậc Đạo Sư gọi thầy.’”",
  "dn16:5.13.10": "“Vâng, bạch Thế Tôn”, vị tỳ-kheo ấy vâng lời Thế Tôn, đi đến chỗ Tôn giả Ānanda; đến nơi, nói với Tôn giả Ānanda như sau:",
  "dn16:5.13.11": "“Này hiền giả Ānanda, bậc Đạo Sư gọi thầy.”",
  "dn16:5.14.1": "“Vâng, hiền giả”, Tôn giả Ānanda đáp lời vị tỳ-kheo ấy, rồi đi đến chỗ Thế Tôn; đến nơi, đảnh lễ Thế Tôn rồi ngồi xuống một bên. Khi Tôn giả Ānanda ngồi xuống một bên, Thế Tôn nói với Tôn giả như sau:",
  "dn16:5.14.2": "“Thôi, này Ānanda, chớ sầu muộn, chớ than khóc. Này Ānanda, chẳng phải Ta đã nói trước rằng: ",
  "dn16:5.14.3": "‘đối với mọi điều thân yêu, khả ái, đều có sự chia lìa, xa cách, đổi khác’ sao? ",
  "dn16:5.14.4": "Ở đây làm sao có thể được? Cái gì đã sinh, đã hiện hữu, do duyên hợp thành, có bản chất hoại diệt, thì không thể có chuyện: ‘mong rằng ngay cả thân của Như Lai cũng đừng tan hoại’. ",
  "dn16:5.14.5": "Này Ānanda, từ lâu con đã phụng sự Như Lai bằng thân nghiệp từ ái, lợi ích, an lạc, không hai, vô lượng; bằng khẩu nghiệp từ ái, lợi ích, an lạc, không hai, vô lượng; bằng ý nghiệp từ ái, lợi ích, an lạc, không hai, vô lượng. ",
  "dn16:5.14.6": "Con là người có phước. Hãy tinh tấn nỗ lực, chẳng bao lâu con sẽ thành bậc vô lậu” ",
  "dn16:5.15.1": "Bấy giờ, Thế Tôn gọi các tỳ-kheo: ",
  "dn16:5.15.2": "“Này các tỳ-kheo, những vị A-la-hán Chánh Đẳng Giác trong thời quá khứ, các vị Thế Tôn ấy cũng chỉ có những thị giả tối thắng như vậy, như Ānanda đối với Ta. ",
  "dn16:5.15.3": "Này các tỳ-kheo, những vị A-la-hán Chánh Đẳng Giác trong thời vị lai, các vị Thế Tôn ấy cũng sẽ có những thị giả tối thắng như vậy, như Ānanda đối với Ta. ",
  "dn16:5.15.4": "Này các tỳ-kheo, Ānanda là người trí tuệ; ",
  "dn16:5.15.5": "này các tỳ-kheo, Ānanda là người thông minh. ",
  "dn16:5.15.6": "Ānanda biết: ‘Đây là lúc để các tỳ-kheo đến yết kiến Như Lai, đây là lúc cho các tỳ-kheo-ni, đây là lúc cho các nam cư sĩ, đây là lúc cho các nữ cư sĩ, đây là lúc cho các vua, các đại thần của vua, các du sĩ ngoại đạo và các đệ tử ngoại đạo.’ ",
  "dn16:5.16.1": "Này các tỳ-kheo, có bốn pháp kỳ diệu, hy hữu nơi Ānanda. ",
  "dn16:5.16.2": "Bốn pháp ấy là gì? ",
  "dn16:5.16.3": "Này các tỳ-kheo, nếu hội chúng tỳ-kheo đến gặp Ānanda, thì chỉ thấy Ānanda thôi họ đã hoan hỷ. ",
  "dn16:5.16.4": "Nếu tại đó Ānanda thuyết pháp, thì họ cũng hoan hỷ với lời thuyết ấy. ",
  "dn16:5.16.5": "Này các tỳ-kheo, hội chúng tỳ-kheo vẫn chưa thỏa mãn, nhưng rồi Ānanda im lặng. ",
  "dn16:5.16.6": "Này các tỳ-kheo, nếu hội chúng tỳ-kheo-ni đến gặp Ānanda, thì chỉ thấy Ānanda thôi họ đã hoan hỷ. ",
  "dn16:5.16.7": "Nếu tại đó Ānanda thuyết pháp, thì họ cũng hoan hỷ với lời thuyết ấy. ",
  "dn16:5.16.8": "Này các tỳ-kheo, hội chúng tỳ-kheo-ni vẫn chưa thỏa mãn, nhưng rồi Ānanda im lặng. ",
  "dn16:5.16.9": "Này các tỳ-kheo, nếu hội chúng nam cư sĩ đến gặp Ānanda, thì chỉ thấy Ānanda thôi họ đã hoan hỷ. ",
  "dn16:5.16.10": "Nếu tại đó Ānanda thuyết pháp, thì họ cũng hoan hỷ với lời thuyết ấy. ",
  "dn16:5.16.11": "Này các tỳ-kheo, hội chúng nam cư sĩ vẫn chưa thỏa mãn, nhưng rồi Ānanda im lặng. ",
  "dn16:5.16.12": "Này các tỳ-kheo, nếu hội chúng nữ cư sĩ đến gặp Ānanda, thì chỉ thấy Ānanda thôi họ đã hoan hỷ. ",
  "dn16:5.16.13": "Nếu tại đó Ānanda thuyết pháp, thì họ cũng hoan hỷ với lời thuyết ấy. ",
  "dn16:5.16.14": "Này các tỳ-kheo, hội chúng nữ cư sĩ vẫn chưa thỏa mãn, nhưng rồi Ānanda im lặng. ",
  "dn16:5.16.15": "Này các tỳ-kheo, đó là bốn pháp kỳ diệu, hy hữu nơi Ānanda. ",
  "dn16:5.16.16": "Này các tỳ-kheo, cũng có bốn pháp kỳ diệu, hy hữu nơi vị Chuyển luân vương. ",
  "dn16:5.16.17": "Bốn pháp ấy là gì? ",
  "dn16:5.16.18": "Này các tỳ-kheo, nếu hội chúng sát-đế-lỵ đến gặp vị Chuyển luân vương, thì chỉ thấy vị ấy thôi họ đã hoan hỷ. ",
  "dn16:5.16.19": "Nếu tại đó vị Chuyển luân vương nói chuyện, thì họ cũng hoan hỷ với lời nói ấy. ",
  "dn16:5.16.20": "Này các Tỳ-kheo, hội chúng Sát-đế-lỵ vẫn chưa thỏa mãn. Bấy giờ vua Chuyển luân im lặng.",
  "dn16:5.16.21": "Này các Tỳ-kheo, nếu hội chúng Bà-la-môn …",
  "dn16:5.16.22": "hội chúng gia chủ …",
  "dn16:5.16.23": "hội chúng sa-môn đến yết kiến vua Chuyển luân, khi được diện kiến thì hội chúng ấy hoan hỷ.",
  "dn16:5.16.24": "Nếu tại đó vua Chuyển luân thuyết nói, thì hội chúng ấy cũng hoan hỷ vì lời thuyết ấy.",
  "dn16:5.16.25": "Này các Tỳ-kheo, hội chúng sa-môn vẫn chưa thỏa mãn. Bấy giờ vua Chuyển luân im lặng.",
  "dn16:5.16.26": "Cũng vậy, này các Tỳ-kheo, có bốn pháp hy hữu, kỳ diệu này nơi A-nan.",
  "dn16:5.16.27": "Này các Tỳ-kheo, nếu hội chúng Tỳ-kheo đến yết kiến A-nan, khi được diện kiến thì hội chúng ấy hoan hỷ.",
  "dn16:5.16.28": "Nếu tại đó A-nan thuyết pháp, thì hội chúng ấy cũng hoan hỷ vì lời thuyết pháp ấy.",
  "dn16:5.16.29": "Này các Tỳ-kheo, hội chúng Tỳ-kheo vẫn chưa thỏa mãn.",
  "dn16:5.16.30": "Bấy giờ A-nan im lặng.",
  "dn16:5.16.31": "Này các Tỳ-kheo, nếu hội chúng Tỳ-kheo-ni …",
  "dn16:5.16.32": "hội chúng nam cư sĩ …",
  "dn16:5.16.33": "hội chúng nữ cư sĩ đến yết kiến A-nan, khi được diện kiến thì hội chúng ấy hoan hỷ.",
  "dn16:5.16.34": "Nếu tại đó A-nan thuyết pháp, thì hội chúng ấy cũng hoan hỷ vì lời thuyết pháp ấy.",
  "dn16:5.16.35": "Này các Tỳ-kheo, hội chúng nữ cư sĩ vẫn chưa thỏa mãn.",
  "dn16:5.16.36": "Bấy giờ A-nan im lặng.",
  "dn16:5.16.37": "Này các Tỳ-kheo, đây là bốn pháp hy hữu, kỳ diệu nơi A-nan.”",
  "dn16:5.17.0": "32. Thuyết giảng kinh Đại Thiện Kiến",
  "dn16:5.17.1": "Khi được nói vậy, Tôn giả A-nan bạch Thế Tôn rằng:",
  "dn16:5.17.2": "“Bạch Thế Tôn, xin Thế Tôn đừng nhập Niết-bàn tại thị trấn nhỏ bé này, thị trấn hoang vắng này, thị trấn nơi cành nhánh này.",
  "dn16:5.17.3": "Bạch Thế Tôn, còn có những đại thành khác, như là—",
  "dn16:5.17.4": "Campā, Rājagaha, Sāvatthī, Sāketa, Kosambī, Bārāṇasī;",
  "dn16:5.17.5": "xin Thế Tôn nhập Niết-bàn tại đó.",
  "dn16:5.17.6": "Ở đó có nhiều đại phú Sát-đế-lỵ, đại phú Bà-la-môn, đại phú gia chủ kính tín Như Lai.",
  "dn16:5.17.7": "Họ sẽ cúng dường nhục thân của Như Lai.”",
  "dn16:5.17.8": "“Này A-nan, chớ nói như vậy, này A-nan, chớ nói như vậy:",
  "dn16:5.17.9": "‘thị trấn nhỏ bé, thị trấn hoang vắng, thị trấn nơi cành nhánh’.",
  "dn16:5.18.1": "Thuở xưa, này A-nan, có vua tên là Đại Thiện Kiến, là Chuyển luân vương, vị vua chân chánh theo pháp, chinh phục bốn phương, chiến thắng, đất nước được an định, đầy đủ bảy báu.",
  "dn16:5.18.2": "Này A-nan, dưới thời vua Đại Thiện Kiến, Kusinārā này là kinh đô tên Kusāvatī.",
  "dn16:5.18.3": "Về chiều dài, từ đông sang tây là mười hai do-tuần; về chiều rộng, từ bắc xuống nam là bảy do-tuần.",
  "dn16:5.18.4": "Này Ānanda, kinh đô Kusāvatī đã từng hưng thịnh, phồn vinh, đông dân, đầy người cư ngụ và sung túc.",
  "dn16:5.18.5": "Ví như, này Ānanda, kinh đô Āḷakamandā của chư thiên hưng thịnh, phồn vinh, đông đúc, đầy các dạ-xoa và sung túc;",
  "dn16:5.18.6": "cũng vậy, này Ānanda, kinh đô Kusāvatī đã từng hưng thịnh, phồn vinh, đông dân, đầy người cư ngụ và sung túc.",
  "dn16:5.18.7": "Này Ānanda, kinh đô Kusāvatī ngày đêm không vắng mười thứ âm thanh, đó là:",
  "dn16:5.18.8": "tiếng voi, tiếng ngựa, tiếng xe, tiếng trống, tiếng mudiṅga, tiếng đàn tỳ bà, tiếng ca hát, tiếng tù và, tiếng chập chõa, tiếng vỗ tay, và thứ mười là tiếng: ‘Hãy ăn đi, hãy uống đi, hãy nhai đi.’",
  "dn16:5.19.1": "Này Ānanda, hãy đi vào Kusinārā và báo cho các Mallā ở Kusinārā rằng:",
  "dn16:5.19.2": "‘Này các Vāseṭṭha, hôm nay vào canh cuối của đêm, Như Lai sẽ nhập Niết-bàn.",
  "dn16:5.19.3": "Hãy đến đi, này các Vāseṭṭha, hãy đến đi, này các Vāseṭṭha.",
  "dn16:5.19.4": "Chớ để về sau các ông phải hối tiếc rằng:",
  "dn16:5.19.5": "“Ngay trong địa phận làng xóm của chúng ta, Như Lai đã nhập Niết-bàn, mà chúng ta lại không được gặp Như Lai lần cuối.”’",
  "dn16:5.19.6": "“Vâng, bạch Thế Tôn,” Tôn giả Ānanda vâng lời Thế Tôn, đắp y, mang theo y bát, cùng một người đi vào Kusinārā.",
  "dn16:5.20.0": "33. Các Mallā đảnh lễ",
  "dn16:5.20.1": "Lúc bấy giờ, các Mallā ở Kusinārā đang tụ họp tại hội trường vì một công việc nào đó.",
  "dn16:5.20.2": "Rồi Tôn giả Ānanda đi đến hội trường của các Mallā ở Kusinārā; đến nơi, Tôn giả báo cho các Mallā ở Kusinārā rằng:",
  "dn16:5.20.3": "“Này các Vāseṭṭha, hôm nay vào canh cuối của đêm, Như Lai sẽ nhập Niết-bàn.",
  "dn16:5.20.4": "Hãy đến đi, này các Vāseṭṭha, hãy đến đi, này các Vāseṭṭha.",
  "dn16:5.20.5": "Chớ để về sau các ông phải hối tiếc rằng:",
  "dn16:5.20.6": "‘Ngay trong địa phận làng xóm của chúng ta, Như Lai đã nhập Niết-bàn, mà chúng ta lại không được gặp Như Lai lần cuối.’”",
  "dn16:5.21.1": "Nghe lời này của Tôn giả Ānanda, các Mallā, các con trai của Mallā, các con dâu của Mallā và các phụ nữ của Mallā đều đau buồn, sầu muộn, tâm đầy khổ não; có người xõa tóc mà khóc, giơ tay lên mà khóc, ngã vật xuống như cây bị chặt, lăn qua lộn lại:",
  "dn16:5.21.2": "“Quá sớm thay, Thế Tôn sẽ nhập Niết-bàn; quá sớm thay, Thiện Thệ sẽ nhập Niết-bàn; quá sớm thay, con mắt của đời sẽ biến mất khỏi thế gian.”",
  "dn16:5.21.3": "Rồi các Mallā, các con trai của Mallā, các con dâu của Mallā và các phụ nữ của Mallā, đau buồn, sầu muộn, tâm đầy khổ não, đi đến rừng sāla của các Mallā tại Upavattana, nơi Tôn giả Ānanda đang ở.",
  "dn16:5.22.1": "Bấy giờ Tôn giả Ānanda nghĩ rằng:",
  "dn16:5.22.2": "“Nếu ta để cho từng người một trong các Mallā ở Kusinārā đảnh lễ Thế Tôn, thì khi các Mallā ở Kusinārā vẫn còn chưa đảnh lễ xong, đêm nay sẽ tàn mất.",
  "dn16:5.22.3": "Hay là ta sắp xếp các Mallā ở Kusinārā theo từng gia đình, từng gia đình để họ đảnh lễ Thế Tôn:",
  "dn16:5.22.4": "‘Bạch Thế Tôn, vị Mallā tên như thế này, cùng với con cái, vợ, quyến thuộc và các quan chức, cúi đầu đảnh lễ dưới chân Thế Tôn.’”",
  "dn16:5.22.5": "Rồi Tôn giả Ānanda sắp xếp các Mallā ở Kusinārā theo từng gia đình, từng gia đình để đảnh lễ Thế Tôn:",
  "dn16:5.22.6": "“Bạch Thế Tôn, vị Mallā tên như thế này, cùng với con cái, vợ, quyến thuộc và các quan chức, cúi đầu đảnh lễ dưới chân Thế Tôn.”",
  "dn16:5.22.7": "Bằng cách ấy, Tôn giả Ānanda đã cho các Mallā ở Kusinārā đảnh lễ Thế Tôn ngay trong canh đầu của đêm.",
  "dn16:5.23.0": "34. Câu chuyện du sĩ Subhadda",
  "dn16:5.23.1": "Vào lúc bấy giờ, có một du sĩ tên là Subhadda đang cư trú tại Kusinārā.",
  "dn16:5.23.2": "Du sĩ Subhadda nghe rằng:",
  "dn16:5.23.3": "“Đêm nay, vào canh cuối, Sa-môn Gotama sẽ nhập Niết-bàn.”",
  "dn16:5.23.4": "Rồi du sĩ Subhadda nghĩ rằng:",
  "dn16:5.23.5": "“Ta đã từng nghe các du sĩ già cả, lớn tuổi, các bậc thầy và thầy của thầy nói rằng:",
  "dn16:5.23.6": "‘Hiếm khi các Như Lai xuất hiện ở đời, là những bậc A-la-hán, Chánh Đẳng Giác.’",
  "dn16:5.23.7": "Đêm nay, vào canh cuối, Sa-môn Gotama sẽ nhập Niết-bàn.",
  "dn16:5.23.8": "Và nay trong ta đã khởi lên điều nghi ngờ này,",
  "dn16:5.23.9": "ta lại có lòng tin như vậy đối với Sa-môn Gotama: ‘Sa-môn Gotama có thể thuyết pháp cho ta theo cách khiến ta từ bỏ được điều nghi ngờ này.’”",
  "dn16:5.24.1": "Rồi du sĩ Subhadda đi đến rừng sāla của người Malla tại Upavattana, đến chỗ Tôn giả Ānanda; sau khi đến, ông nói với Tôn giả Ānanda rằng:",
  "dn16:5.24.2": "“Thưa ngài Ānanda, tôi đã từng nghe các du sĩ già cả, lớn tuổi, các bậc thầy và thầy của thầy nói rằng:",
  "dn16:5.24.3": "‘Hiếm khi các Như Lai xuất hiện ở đời, là những bậc A-la-hán, Chánh Đẳng Giác.’",
  "dn16:5.24.4": "Đêm nay, vào canh cuối, Sa-môn Gotama sẽ nhập Niết-bàn.",
  "dn16:5.24.5": "Và nay trong tôi đã khởi lên điều nghi ngờ này—",
  "dn16:5.24.6": "tôi lại có lòng tin như vậy đối với Sa-môn Gotama: ‘Sa-môn Gotama có thể thuyết pháp cho tôi theo cách khiến tôi từ bỏ được điều nghi ngờ này.’",
  "dn16:5.24.7": "Mong rằng, thưa ngài Ānanda, tôi được gặp Sa-môn Gotama.”",
  "dn16:5.24.8": "Khi được nói vậy, Tôn giả Ānanda nói với du sĩ Subhadda rằng:",
  "dn16:5.24.9": "“Thôi, này hiền hữu Subhadda, chớ làm phiền Như Lai, Thế Tôn đang mệt.”",
  "dn16:5.24.10": "Lần thứ hai, du sĩ Subhadda …",
  "dn16:5.24.11": "đến lần thứ ba, du sĩ Subhadda nói với Tôn giả Ānanda rằng:",
  "dn16:5.24.12": "“Thưa ngài Ānanda, tôi đã từng nghe các du sĩ già cả, lớn tuổi, các bậc thầy và thầy của thầy nói rằng:",
  "dn16:5.24.13": "‘Hiếm khi các Như Lai xuất hiện ở đời, là những bậc A-la-hán, Chánh Đẳng Giác.’",
  "dn16:5.24.14": "Đêm nay, vào canh cuối, Sa-môn Gotama sẽ nhập Niết-bàn.",
  "dn16:5.24.15": "Và nay trong tôi đã khởi lên điều nghi ngờ này—",
  "dn16:5.24.16": "tôi lại có lòng tin như vậy đối với Sa-môn Gotama: ‘Sa-môn Gotama có thể thuyết pháp cho tôi theo cách khiến tôi từ bỏ được điều nghi ngờ này.’",
  "dn16:5.24.17": "Mong rằng, thưa ngài Ānanda, tôi được gặp Sa-môn Gotama.”",
  "dn16:5.24.18": "Đến lần thứ ba, Tôn giả Ānanda nói với du sĩ Subhadda rằng:",
  "dn16:5.24.19": "“Thôi, này hiền hữu Subhadda, chớ làm phiền Như Lai, Thế Tôn đang mệt.”",
  "dn16:5.25.1": "Thế Tôn nghe được cuộc đối thoại này giữa Tôn giả Ānanda và du sĩ Subhadda.",
  "dn16:5.25.2": "Rồi Thế Tôn gọi Tôn giả Ānanda:",
  "dn16:5.25.3": "“Thôi, này Ānanda, đừng ngăn Subhadda, hãy để Subhadda được yết kiến Như Lai.",
  "dn16:5.25.4": "Bất cứ điều gì Subhadda hỏi Ta, tất cả đều là hỏi vì muốn hiểu biết, không phải vì muốn quấy nhiễu.",
  "dn16:5.25.5": "Và điều gì được Ta trả lời khi được hỏi, ông ấy sẽ mau chóng hiểu ra.”",
  "dn16:5.25.6": "Bấy giờ Tôn giả Ānanda nói với du sĩ Subhadda như sau:",
  "dn16:5.25.7": "“Này hiền giả Subhadda, hãy đi đi, Thế Tôn cho phép ông vào yết kiến.”",
  "dn16:5.26.1": "Bấy giờ du sĩ Subhadda đi đến chỗ Thế Tôn; đến nơi, ông chào hỏi thân thiện với Thế Tôn, sau khi nói lên những lời thăm hỏi xã giao thân tình rồi ngồi xuống một bên. Khi đã ngồi xuống một bên, du sĩ Subhadda bạch Thế Tôn rằng:",
  "dn16:5.26.2": "“Thưa Tôn giả Gotama, những sa-môn, bà-la-môn này là những vị lãnh đạo hội chúng, lãnh đạo đồ chúng, thầy của đồ chúng, nổi tiếng, có danh vọng, là những giáo chủ được nhiều người tán thành,",
  "dn16:5.26.3": "ví như: Pūraṇa Kassapa, Makkhali Gosāla, Ajita Kesakambala, Pakudha Kaccāyana, Sañcaya Belaṭṭhaputta, Nigaṇṭha Nāṭaputta,",
  "dn16:5.26.4": "tất cả những vị ấy có thật sự tự mình chứng biết theo điều mình tuyên bố không, hay tất cả đều không chứng biết, hay một số chứng biết, một số không chứng biết?”",
  "dn16:5.26.5": "“Thôi, Subhadda, hãy để chuyện ấy qua đi:",
  "dn16:5.26.6": "‘Tất cả những vị ấy có thật sự tự mình chứng biết theo điều mình tuyên bố không, hay tất cả đều không chứng biết, hay một số chứng biết, một số không chứng biết?’",
  "dn16:5.26.7": "Ta sẽ thuyết pháp cho ông, này Subhadda;",
  "dn16:5.26.8": "hãy lắng nghe kỹ và khéo tác ý, Ta sẽ nói.”",
  "dn16:5.26.9": "“Vâng, bạch Thế Tôn,” du sĩ Subhadda vâng đáp Thế Tôn.",
  "dn16:5.26.10": "Thế Tôn nói như sau:",
  "dn16:5.27.1": "“Này Subhadda, trong pháp và luật nào không có Thánh đạo Tám ngành thì ở đó không có sa-môn. Ở đó cũng không có vị sa-môn bậc hai. Ở đó cũng không có vị sa-môn bậc ba. Ở đó cũng không có vị sa-môn bậc bốn.",
  "dn16:5.27.2": "Còn này Subhadda, trong pháp và luật nào có Thánh đạo Tám ngành thì ở đó có sa-môn, có vị sa-môn bậc hai, có vị sa-môn bậc ba, có vị sa-môn bậc bốn.",
  "dn16:5.27.3": "Này Subhadda, trong pháp và luật này có Thánh đạo Tám ngành; chỉ ở đây mới có sa-môn, ở đây có vị sa-môn bậc hai, ở đây có vị sa-môn bậc ba, ở đây có vị sa-môn bậc bốn; các học thuyết khác đều trống không đối với các sa-môn chân chính.",
  "dn16:5.27.4": "Và này Subhadda, nếu các tỳ-kheo này sống đúng đắn thì thế gian sẽ không vắng các bậc A-la-hán.",
  "dn16:5.27.5": "Này Subhadda, khi hai mươi chín tuổi,",
  "dn16:5.27.6": "Ta xuất gia, tìm cầu điều thiện xảo;",
  "dn16:5.27.7": "Hơn năm mươi năm,",
  "dn16:5.27.8": "Kể từ khi Ta xuất gia, này Subhadda;",
  "dn16:5.27.9": "Là người hành trì trong phạm vi giáo pháp chân chánh,",
  "dn16:5.27.10": "Ngoài đây ra không có sa-môn nào.",
  "dn16:5.27.11": "Cũng không có vị sa-môn bậc hai.",
  "dn16:5.27.12": "Cũng không có vị sa-môn bậc ba.",
  "dn16:5.27.13": "Cũng không có vị sa-môn bậc bốn.",
  "dn16:5.27.14": "Các học thuyết khác đều trống không đối với các sa-môn chân chính.",
  "dn16:5.27.15": "Và này Subhadda, nếu các tỳ-kheo này sống đúng đắn thì thế gian sẽ không vắng các bậc A-la-hán.”",
  "dn16:5.28.1": "Khi được nói vậy, du sĩ Subhadda bạch Thế Tôn như sau:",
  "dn16:5.28.2": "“Thật vi diệu, bạch Thế Tôn, thật vi diệu, bạch Thế Tôn.",
  "dn16:5.28.3": "Ví như, bạch Thế Tôn, người ta dựng đứng lại vật bị úp xuống, mở ra vật bị che kín, chỉ đường cho kẻ lạc lối, đem đèn dầu vào trong bóng tối để những ai có mắt có thể thấy các sắc; cũng vậy, Chánh pháp đã được Thế Tôn dùng nhiều phương cách trình bày rõ ràng.",
  "dn16:5.28.4": "Con xin quy y Thế Tôn, quy y Pháp và quy y Tỳ-kheo Tăng.",
  "dn16:5.28.5": "Mong con được xuất gia trước mặt Thế Tôn, mong được thọ cụ túc giới.”",
  "dn16:5.29.1": "“Này Subhadda, người trước đây theo ngoại đạo mà trong Pháp và Luật này mong được xuất gia, mong được thọ cụ túc giới, thì phải sống thử bốn tháng. Sau bốn tháng, nếu các Tỳ-kheo biết rõ người ấy đã phát tâm chân thành thì cho xuất gia, cho thọ cụ túc giới để thành Tỳ-kheo.",
  "dn16:5.29.2": "Tuy vậy, ở đây sự sai khác giữa các hạng người là điều đã được biết.”",
  "dn16:5.29.3": "“Bạch Thế Tôn, nếu những người trước đây theo ngoại đạo mà mong được xuất gia, mong được thọ cụ túc giới trong Pháp và Luật này phải sống thử bốn tháng, sau bốn tháng các Tỳ-kheo biết rõ người ấy đã phát tâm chân thành thì cho xuất gia, cho thọ cụ túc giới để thành Tỳ-kheo, thì con sẽ sống thử bốn năm; sau bốn năm, mong các Tỳ-kheo cho con xuất gia, cho con thọ cụ túc giới để thành Tỳ-kheo.”",
  "dn16:5.29.4": "Bấy giờ Thế Tôn gọi Tôn giả Ānanda:",
  "dn16:5.29.5": "“Vậy này Ānanda, hãy cho Subhadda xuất gia.”",
  "dn16:5.29.6": "“Vâng, bạch Thế Tôn,” Tôn giả Ānanda vâng đáp Thế Tôn.",
  "dn16:5.30.1": "Bấy giờ du sĩ Subhadda nói với Tôn giả Ānanda như sau:",
  "dn16:5.30.2": "“Thật là lợi ích cho hiền giả Ānanda, thật là khéo được cho hiền giả Ānanda,",
  "dn16:5.30.3": "vì ở đây các vị đã được tưới nước quán đảnh làm đệ tử nội trú ngay trước mặt bậc Đạo Sư.”",
  "dn16:5.30.4": "Du sĩ Subhadda đã được xuất gia trước mặt Thế Tôn, đã được thọ cụ túc giới.",
  "dn16:5.30.5": "Không bao lâu sau khi thọ cụ túc giới, Tôn giả Subhadda sống một mình, viễn ly, không phóng dật, nhiệt tâm, chuyên chú; chẳng bao lâu đã tự mình với thắng trí chứng ngộ, chứng đạt và an trú ngay trong hiện tại cứu cánh vô thượng của phạm hạnh, vì mục đích ấy mà các thiện nam tử chân chánh từ bỏ gia đình, sống không gia đình, xuất gia.",
  "dn16:5.30.6": "Vị ấy tự biết: “Sanh đã tận, phạm hạnh đã thành, việc cần làm đã làm xong, không còn trở lui trạng thái này nữa.”",
  "dn16:5.30.7": "Và Tôn giả Subhadda đã trở thành một vị A-la-hán.",
  "dn16:5.30.8": "Vị ấy là đệ tử được Thế Tôn đích thân chứng kiến sau cùng.",
  "dn16:5.30.9": "Phần tụng đọc thứ năm.",
  "dn16:6.1.0": "35. Lời dạy cuối cùng của Như Lai",
  "dn16:6.1.1": "Bấy giờ Thế Tôn gọi Tôn giả Ānanda:",
  "dn16:6.1.2": "“Này Ānanda, có thể các ông sẽ nghĩ rằng:",
  "dn16:6.1.3": "‘Lời dạy nay đã không còn bậc Đạo Sư, chúng ta không còn Thầy nữa.’",
  "dn16:6.1.4": "Này Ānanda, không nên thấy như vậy.",
  "dn16:6.1.5": "Này Ānanda, Pháp và Luật mà Ta đã thuyết giảng và chế định cho các ông, sau khi Ta diệt độ, sẽ là Đạo Sư của các ông.",
  "dn16:6.2.1": "Này Ānanda, như hiện nay các Tỳ-kheo giao tiếp với nhau bằng cách gọi nhau là ‘hiền giả’, thì sau khi Ta diệt độ không nên giao tiếp như vậy.",
  "dn16:6.2.2": "Này Ānanda, vị Tỳ-kheo lớn tuổi hạ hơn nên gọi vị Tỳ-kheo nhỏ tuổi hạ bằng tên, bằng họ, hoặc bằng cách gọi ‘hiền giả’.",
  "dn16:6.2.3": "Vị Tỳ-kheo nhỏ tuổi hạ hơn nên gọi vị Tỳ-kheo lớn tuổi hạ là ‘bạch ngài’ hoặc ‘tôn giả’.",
  "dn16:6.3.1": "Này Ānanda, nếu muốn, Tăng chúng sau khi Ta diệt độ có thể bãi bỏ các học giới nhỏ nhặt.",
  "dn16:6.4.1": "Này Ānanda, sau khi Ta diệt độ, hãy áp dụng hình phạt Phạm-đàn đối với tỳ-kheo Channa.”",
  "dn16:6.4.2": "“Bạch Thế Tôn, hình phạt Phạm-đàn là gì?”",
  "dn16:6.4.3": "“Này Ānanda, tỳ-kheo Channa muốn nói gì thì cứ nói.",
  "dn16:6.4.4": "Nhưng các tỳ-kheo không được nói chuyện với vị ấy, không được khuyên dạy, không được giáo giới vị ấy.”",
  "dn16:6.5.1": "Rồi Thế Tôn gọi các tỳ-kheo:",
  "dn16:6.5.2": "“Này các tỳ-kheo, nếu dù chỉ một tỳ-kheo nào còn có nghi hoặc hay phân vân về Phật, về Pháp, về Tăng, về đạo hay về con đường tu tập, thì hãy hỏi đi, này các tỳ-kheo, chớ để về sau phải hối tiếc rằng:",
  "dn16:6.5.3": "‘Bậc Đạo Sư đã hiện diện trước mặt chúng ta, mà chúng ta đã không thể trực tiếp thưa hỏi Thế Tôn.’”",
  "dn16:6.5.4": "Khi được nói vậy, các tỳ-kheo im lặng.",
  "dn16:6.6.1": "Lần thứ hai, Thế Tôn…",
  "dn16:6.6.2": "lần thứ ba, Thế Tôn gọi các tỳ-kheo:",
  "dn16:6.6.3": "“Này các tỳ-kheo, nếu dù chỉ một tỳ-kheo nào còn có nghi hoặc hay phân vân về Phật, về Pháp, về Tăng, về đạo hay về con đường tu tập, thì hãy hỏi đi, này các tỳ-kheo, chớ để về sau phải hối tiếc rằng:",
  "dn16:6.6.4": "‘Bậc Đạo Sư đã hiện diện trước mặt chúng ta, mà chúng ta đã không thể trực tiếp thưa hỏi Thế Tôn.’”",
  "dn16:6.6.5": "Đến lần thứ ba, các tỳ-kheo ấy vẫn im lặng.",
  "dn16:6.6.6": "Rồi Thế Tôn gọi các tỳ-kheo:",
  "dn16:6.6.7": "“Này các tỳ-kheo, có thể vì kính trọng bậc Đạo Sư mà các ông không hỏi. Vậy thì, này các tỳ-kheo, bạn hãy nói cho bạn.”",
  "dn16:6.6.8": "Khi được nói vậy, các tỳ-kheo vẫn im lặng.",
  "dn16:6.6.9": "Rồi Tôn giả Ānanda bạch Thế Tôn rằng:",
  "dn16:6.6.10": "“Thật vi diệu, bạch Thế Tôn, thật hy hữu, bạch Thế Tôn! Con tin tưởng nơi chúng tỳ-kheo này đến mức nghĩ rằng: ‘Không có dù chỉ một tỳ-kheo nào còn có nghi hoặc hay phân vân về Phật, về Pháp, về Tăng, về đạo hay về con đường tu tập.’”",
  "dn16:6.6.11": "“Này Ānanda, ông nói do lòng tin; còn ở đây, Như Lai biết bằng trí. Trong chúng tỳ-kheo này, không có dù chỉ một tỳ-kheo nào còn có nghi hoặc hay phân vân về Phật, về Pháp, về Tăng, về đạo hay về con đường tu tập.",
  "dn16:6.6.12": "Vì này Ānanda, trong năm trăm vị tỳ-kheo này, vị cuối cùng cũng là bậc nhập lưu, không còn đọa xứ, chắc chắn hướng đến giác ngộ.”",
  "dn16:6.7.1": "Rồi Thế Tôn gọi các tỳ-kheo:",
  "dn16:6.7.2": "“Này các tỳ-kheo, giờ đây Ta nhắn nhủ các ông:",
  "dn16:6.7.3": "Các hành là pháp hoại diệt, hãy tinh tấn không phóng dật mà thành tựu.”",
  "dn16:6.7.4": "Đó là lời cuối cùng của Như Lai.",
  "dn16:6.8.0": "36. Nói về sự nhập Niết-bàn",
  "dn16:6.8.1": "Rồi Thế Tôn nhập sơ thiền; từ sơ thiền xuất ra, Ngài nhập nhị thiền; từ nhị thiền xuất ra, Ngài nhập tam thiền; từ tam thiền xuất ra, Ngài nhập tứ thiền; từ tứ thiền xuất ra, Ngài nhập không vô biên xứ; từ không vô biên xứ xuất ra, Ngài nhập thức vô biên xứ; từ thức vô biên xứ xuất ra, Ngài nhập vô sở hữu xứ; từ vô sở hữu xứ xuất ra, Ngài nhập phi tưởng phi phi tưởng xứ; từ phi tưởng phi phi tưởng xứ xuất ra, Ngài nhập diệt thọ tưởng định.",
  "dn16:6.8.2": "Rồi Tôn giả Ānanda nói với Tôn giả Anuruddha rằng:",
  "dn16:6.8.3": "“Bạch ngài Anuruddha, Thế Tôn đã nhập Niết-bàn.”",
  "dn16:6.8.4": "“Này hiền giả Ānanda, Thế Tôn chưa nhập Niết-bàn, Ngài đang nhập diệt thọ tưởng định.”",
  "dn16:6.9.1": "Rồi Thế Tôn từ diệt thọ tưởng định xuất ra, nhập phi tưởng phi phi tưởng xứ; từ phi tưởng phi phi tưởng xứ xuất ra, nhập vô sở hữu xứ; từ vô sở hữu xứ xuất ra, nhập thức vô biên xứ; từ thức vô biên xứ xuất ra, nhập không vô biên xứ; từ không vô biên xứ xuất ra, nhập tứ thiền; từ tứ thiền xuất ra, nhập tam thiền; từ tam thiền xuất ra, nhập nhị thiền; từ nhị thiền xuất ra, nhập sơ thiền; từ sơ thiền xuất ra, nhập nhị thiền; từ nhị thiền xuất ra, nhập tam thiền; từ tam thiền xuất ra, nhập tứ thiền; vừa xuất khỏi tứ thiền, ngay sau đó Thế Tôn nhập Niết-bàn.",
  "dn16:6.10.1": "Khi Thế Tôn nhập Niết-bàn, cùng với sự nhập Niết-bàn ấy đã xảy ra một trận đại địa chấn kinh hoàng, rợn tóc gáy. Trống trời cũng vang lên.",
  "dn16:6.10.2": "Khi Thế Tôn nhập Niết-bàn, cùng với sự nhập Niết-bàn ấy, Phạm thiên Sahampati nói lên bài kệ này:",
  "dn16:6.10.3": "“Tất cả rồi sẽ buông bỏ,",
  "dn16:6.10.4": "mọi hữu tình trong đời đều phải bỏ thân tụ này;",
  "dn16:6.10.5": "Nơi nào có bậc Đạo Sư như vậy,",
  "dn16:6.10.6": "bậc vô song trong đời;",
  "dn16:6.10.7": "Như Lai, bậc đầy đủ uy lực,",
  "dn16:6.10.8": "bậc Chánh Đẳng Giác, đã nhập Niết-bàn.”",
  "dn16:6.10.9": "Khi Thế Tôn nhập Niết-bàn, cùng với sự nhập Niết-bàn ấy, Sakka, vua của chư thiên, nói lên bài kệ này:",
  "dn16:6.10.10": "“Các hành thật vô thường,",
  "dn16:6.10.11": "có tính chất sinh rồi diệt;",
  "dn16:6.10.12": "Đã sinh lên rồi, chúng hoại diệt,",
  "dn16:6.10.13": "sự lắng dịu của chúng là an lạc.”",
  "dn16:6.10.14": "Khi Thế Tôn nhập Niết-bàn, cùng với sự nhập Niết-bàn ấy, Tôn giả Anuruddha nói lên những bài kệ này:",
  "dn16:6.10.15": "“Không còn hơi thở ra vào,",
  "dn16:6.10.16": "ở bậc tâm an trú, như như ấy;",
  "dn16:6.10.17": "Bất động, hướng đến an tịnh,",
  "dn16:6.10.18": "bậc Mâu-ni đã xả bỏ mạng sống. ",
  "dn16:6.10.19": "Với tâm không hề suy sụp,",
  "dn16:6.10.20": "Ngài đã chịu đựng cảm thọ;",
  "dn16:6.10.21": "Như ngọn đèn tắt,",
  "dn16:6.10.22": "đó là sự giải thoát của tâm.”",
  "dn16:6.10.23": "Khi Thế Tôn nhập Niết-bàn, cùng với sự nhập Niết-bàn ấy, Tôn giả A-nan nói lên bài kệ này:",
  "dn16:6.10.24": "“Khi ấy thật là kinh hoàng,",
  "dn16:6.10.25": "khi ấy thật là rợn tóc gáy;",
  "dn16:6.10.26": "Khi bậc Chánh Đẳng Giác,",
  "dn16:6.10.27": "đầy đủ mọi tướng tốt, đã nhập Niết-bàn.”",
  "dn16:6.10.28": "Khi Thế Tôn nhập Niết-bàn, trong số các vị tỳ-kheo ở đó, những vị chưa ly tham, một số giơ tay lên than khóc, ngã vật xuống như cây bị chặt, lăn qua lộn lại mà than rằng: “Thế Tôn nhập Niết-bàn quá sớm, Thiện Thệ nhập Niết-bàn quá sớm, con mắt của thế gian đã biến mất quá sớm.”",
  "dn16:6.10.29": "Còn những vị tỳ-kheo đã ly tham thì chánh niệm tỉnh giác nhẫn chịu:",
  "dn16:6.10.30": "“Các hành là vô thường, ở đây có gì mà có thể khác được?”",
  "dn16:6.11.1": "Bấy giờ Tôn giả Anuruddha gọi các vị tỳ-kheo:",
  "dn16:6.11.2": "“Thôi, này chư hiền, chớ sầu muộn, chớ than khóc.",
  "dn16:6.11.3": "Này chư hiền, chẳng phải Thế Tôn đã nói trước rằng:",
  "dn16:6.11.4": "‘Mọi sự vật khả ái, đáng yêu đều phải chịu cảnh chia lìa, xa cách, đổi khác’ sao?",
  "dn16:6.11.5": "Này chư hiền, làm sao có thể được điều ấy? ‘Cái gì đã sinh, đã hiện hữu, do duyên hợp thành, có bản chất hoại diệt, thì mong rằng nó đừng hoại diệt’, không có chuyện như vậy.",
  "dn16:6.11.6": "Này chư hiền, các chư thiên đang than trách.”",
  "dn16:6.11.7": "“Bạch ngài, Tôn giả Anuruddha nghĩ đến các chư thiên như thế nào?”",
  "dn16:6.11.8": "“Này hiền giả Ānanda, có những chư thiên ở hư không, còn tưởng là đất, xõa tóc than khóc, giơ cao cánh tay than khóc, ngã lăn xuống đất, lăn qua lộn lại:",
  "dn16:6.11.9": "‘Thế Tôn nhập Niết-bàn quá sớm, Thiện Thệ nhập Niết-bàn quá sớm, con mắt của thế gian đã biến mất quá sớm.’",
  "dn16:6.11.10": "Này hiền giả Ānanda, có những chư thiên ở trên đất, còn tưởng là đất, xõa tóc than khóc, giơ cao cánh tay than khóc, ngã lăn xuống đất, lăn qua lộn lại:",
  "dn16:6.11.11": "‘Thế Tôn nhập Niết-bàn quá sớm, Thiện Thệ nhập Niết-bàn quá sớm, con mắt của thế gian đã biến mất quá sớm.’",
  "dn16:6.11.12": "Còn những chư thiên đã lìa tham thì tỉnh táo, chánh niệm, sáng suốt mà kham nhẫn:",
  "dn16:6.11.13": "‘Các hành là vô thường, làm sao có thể khác được.’”",
  "dn16:6.11.14": "Bấy giờ Tôn giả Anuruddha và Tôn giả Ānanda cùng nhau trải qua phần còn lại của đêm ấy bằng pháp thoại.",
  "dn16:6.12.1": "Bấy giờ Tôn giả Anuruddha nói với Tôn giả Ānanda:",
  "dn16:6.12.2": "“Này hiền giả Ānanda, hãy đi vào Kusinārā báo cho các Mallā ở Kusinārā biết:",
  "dn16:6.12.3": "‘Này các Vāseṭṭha, Thế Tôn đã nhập Niết-bàn,",
  "dn16:6.12.4": "nay các vị hãy làm điều gì mà các vị cho là phải thời.’”",
  "dn16:6.12.5": "“Vâng, bạch ngài,” Tôn giả Ānanda vâng lời Tôn giả Anuruddha, đến sáng sớm đắp y, mang bát và y, cùng với một vị nữa đi vào Kusinārā.",
  "dn16:6.12.6": "Lúc bấy giờ, các Mallā ở Kusinārā đang tụ họp tại hội trường vì chính công việc ấy.",
  "dn16:6.12.7": "Bấy giờ Tôn giả Ānanda đi đến hội trường của các Mallā ở Kusinārā; đến nơi, báo cho các Mallā ở Kusinārā biết:",
  "dn16:6.12.8": "“Này các Vāseṭṭha, Thế Tôn đã nhập Niết-bàn,",
  "dn16:6.12.9": "nay các vị hãy làm điều gì mà các vị cho là phải thời.”",
  "dn16:6.12.10": "Nghe lời này của Tôn giả Ānanda, các Mallā, các con trai của Mallā, các con dâu của Mallā và các phụ nữ của Mallā đều đau buồn, sầu não, tâm đầy khổ ưu; một số xõa tóc than khóc, giơ cao cánh tay than khóc, ngã lăn xuống đất, lăn qua lộn lại:",
  "dn16:6.12.11": "“Thế Tôn nhập Niết-bàn quá sớm, Thiện Thệ nhập Niết-bàn quá sớm, con mắt của thế gian đã biến mất quá sớm.”",
  "dn16:6.13.0": "37. Cúng dường nhục thân Phật",
  "dn16:6.13.1": "Bấy giờ các Mallā ở Kusinārā ra lệnh cho người ta:",
  "dn16:6.13.2": "“Thế thì này các anh, hãy tập hợp hương hoa và tất cả nhạc cụ ở Kusinārā lại.”",
  "dn16:6.13.3": "Bấy giờ các Mallā ở Kusinārā mang theo hương hoa, tất cả nhạc cụ và năm trăm cặp vải, đi đến rừng sāla của các Mallā tại Upavattana, nơi có nhục thân của Thế Tôn; đến nơi, họ tôn kính, kính trọng, tôn vinh, cúng dường nhục thân Thế Tôn bằng múa, hát, nhạc, vòng hoa và hương liệu, dựng các tấm màn vải và chuẩn bị các vòng tràng hoa, rồi trải qua một ngày như vậy.",
  "dn16:6.13.4": "Bấy giờ các Mallā ở Kusinārā nghĩ rằng:",
  "dn16:6.13.5": "“Hôm nay đã quá muộn để hỏa táng nhục thân của Thế Tôn; ngày mai chúng ta sẽ hỏa táng nhục thân của Thế Tôn.”",
  "dn16:6.13.6": "Rồi các Mallā ở Kusinārā tôn kính, kính trọng, quý mến, cúng dường nhục thân của Thế Tôn bằng múa, hát, nhạc, vòng hoa và hương thơm, làm các tấm trướng vải và chuẩn bị đài tròn, như vậy họ đã trải qua ngày thứ hai, cũng trải qua ngày thứ ba, cũng trải qua ngày thứ tư, cũng trải qua ngày thứ năm, cũng trải qua ngày thứ sáu.",
  "dn16:6.14.1": "Rồi đến ngày thứ bảy, các Mallā ở Kusinārā nghĩ rằng:",
  "dn16:6.14.2": "“Chúng ta sẽ tôn kính, kính trọng, quý mến, cúng dường nhục thân của Thế Tôn bằng múa, hát, nhạc, vòng hoa và hương thơm, rồi khiêng đi về phía nam của thành, vòng ra bên ngoài phía nam của thành, và sẽ hỏa táng nhục thân của Thế Tôn ở phía nam thành.”",
  "dn16:6.14.3": "Lúc bấy giờ, tám vị thủ lãnh của người Mallā, đầu đã tắm gội, mặc y phục mới,",
  "dn16:6.14.4": "nghĩ rằng: “Chúng ta sẽ nâng nhục thân của Thế Tôn lên”, nhưng không thể nâng lên được.",
  "dn16:6.14.5": "Rồi các Mallā ở Kusinārā nói với Tôn giả Anuruddha rằng:",
  "dn16:6.14.6": "“Bạch ngài Anuruddha, do nhân gì, do duyên gì mà tám vị thủ lãnh của người Mallā này, đầu đã tắm gội, mặc y phục mới,",
  "dn16:6.14.7": "nghĩ rằng: ‘Chúng ta sẽ nâng nhục thân của Thế Tôn lên’, mà lại không thể nâng lên được?”",
  "dn16:6.14.8": "“Này các Vāseṭṭha, ý định của các ông là một đằng, ý định của chư thiên lại là một nẻo khác.”",
  "dn16:6.15.1": "“Bạch ngài, ý định của chư thiên là thế nào?”",
  "dn16:6.15.2": "“Này các Vāseṭṭha, ý định của các ông là:",
  "dn16:6.15.3": "‘Chúng ta sẽ tôn kính, kính trọng, quý mến, cúng dường nhục thân của Thế Tôn bằng múa, hát, nhạc, vòng hoa và hương thơm, rồi khiêng đi về phía nam của thành, vòng ra bên ngoài phía nam của thành, và sẽ hỏa táng nhục thân của Thế Tôn’;",
  "dn16:6.15.4": "còn ý định của chư thiên là:",
  "dn16:6.15.5": "‘Chúng ta sẽ tôn kính, kính trọng, quý mến, cúng dường nhục thân của Thế Tôn bằng các điệu múa, tiếng hát, âm nhạc, vòng hoa và hương thơm cõi trời; rồi khiêng đi về phía bắc của thành, đưa vào thành bằng cổng phía bắc, đi qua giữa trung tâm thành, ra khỏi bằng cổng phía đông, rồi tại ngôi tháp của người Mallā tên là Makuṭabandhana ở phía đông thành, chúng ta sẽ hỏa táng nhục thân của Thế Tôn tại đó.’”",
  "dn16:6.15.6": "“Bạch ngài, như ý định của chư thiên, xin hãy như vậy.”",
  "dn16:6.16.1": "Lúc bấy giờ, thành Kusinārā cho đến các ngã tư, ngã ba và chỗ quanh co chật hẹp đều được phủ đầy hoa mandārava cao đến đầu gối.",
  "dn16:6.16.2": "Rồi chư thiên và các Mallā ở Kusinārā tôn kính, kính trọng, quý mến, cúng dường nhục thân của Thế Tôn bằng các điệu múa, tiếng hát, âm nhạc, vòng hoa và hương thơm của cõi trời và loài người; khiêng đi về phía bắc của thành, đưa vào thành bằng cổng phía bắc, đi qua giữa trung tâm thành, ra khỏi bằng cổng phía đông, rồi đặt nhục thân của Thế Tôn tại ngôi tháp của người Mallā tên là Makuṭabandhana ở phía đông thành.",
  "dn16:6.17.1": "Rồi các Mallā ở Kusinārā nói với Tôn giả Ānanda rằng:",
  "dn16:6.17.2": "“Bạch ngài Ānanda, chúng tôi phải xử sự thế nào đối với nhục thân của Như Lai?”",
  "dn16:6.17.3": "“Này các Vāseṭṭha, người ta xử sự đối với nhục thân của vị Chuyển luân vương thế nào, thì cũng nên xử sự đối với nhục thân của Như Lai như vậy.”",
  "dn16:6.17.4": "“Bạch ngài Ānanda, người ta xử sự đối với nhục thân của vị Chuyển luân vương như thế nào?”",
  "dn16:6.17.5": "“Này các Vāseṭṭha, nhục thân của vị Chuyển luân vương được quấn bằng vải mới, quấn xong bằng vải mới thì lại quấn bằng bông đã chải, quấn xong bằng bông đã chải thì lại quấn bằng vải mới.",
  "dn16:6.17.6": "Theo cách ấy, sau khi quấn nhục thân của vị Chuyển luân vương bằng năm trăm lớp đôi, người ta đặt vào một quan tài sắt đựng dầu, rồi đậy lên bằng một quan tài sắt khác, làm giàn hỏa bằng tất cả các thứ hương thơm và hỏa táng nhục thân của vị Chuyển luân vương.",
  "dn16:6.17.7": "Người ta dựng một tháp cho vị Chuyển luân vương tại ngã tư đường lớn.",
  "dn16:6.17.8": "Này các Vāseṭṭha, người ta xử sự đối với nhục thân của vị Chuyển luân vương như vậy.",
  "dn16:6.17.9": "Này các Vāseṭṭha, người ta xử sự đối với nhục thân của vị Chuyển luân vương thế nào, thì cũng nên xử sự đối với nhục thân của Như Lai như vậy.",
  "dn16:6.17.10": "Nên dựng tháp của Như Lai tại ngã tư đường lớn.",
  "dn16:6.17.11": "Ở đó, những ai dâng vòng hoa, hương thơm, phấn hương, hoặc đảnh lễ, hoặc khởi tâm tịnh tín, thì điều ấy sẽ đem lại lợi ích và an lạc lâu dài cho họ.”",
  "dn16:6.18.1": "Rồi các Mallā ở Kusinārā ra lệnh cho người ta:",
  "dn16:6.18.2": "“Vậy thì, này các Mallā, hãy gom bông vải đã được đánh tơi lại.”",
  "dn16:6.18.3": "Bấy giờ, các Mallā ở Kusinārā quấn thân thể của Thế Tôn bằng vải mới, rồi quấn bằng bông vải đã được đánh tơi; quấn bằng bông vải đã được đánh tơi rồi lại quấn bằng vải mới.",
  "dn16:6.18.4": "Theo cách ấy, quấn thân thể của Thế Tôn bằng năm trăm lớp đôi, rồi đặt vào một quan tài sắt đựng dầu, lấy một quan tài sắt khác đậy lên, làm một giàn hỏa bằng tất cả các thứ hương, rồi đặt thân thể của Thế Tôn lên giàn hỏa.",
  "dn16:6.19.0": "38. Chuyện Trưởng lão Mahākassapa",
  "dn16:6.19.1": "Lúc bấy giờ, Tôn giả Mahākassapa đang đi từ Pāvā đến Kusinārā cùng với đại chúng Tỳ-kheo khoảng năm trăm vị.",
  "dn16:6.19.2": "Rồi Tôn giả Mahākassapa rời khỏi đường, ngồi xuống dưới gốc một cây.",
  "dn16:6.19.3": "Lúc bấy giờ, có một du sĩ Ājīvaka cầm hoa mandārava từ Kusinārā đi đến Pāvā.",
  "dn16:6.19.4": "Tôn giả Mahākassapa thấy du sĩ Ājīvaka ấy từ xa đi đến, thấy vậy liền nói với người ấy:",
  "dn16:6.19.5": "“Này hiền giả, ông có biết bậc Đạo Sư của chúng tôi không?”",
  "dn16:6.19.6": "“Vâng, hiền giả, tôi biết. Hôm nay đã bảy ngày kể từ khi Sa-môn Gotama nhập Niết-bàn.",
  "dn16:6.19.7": "Vì thế tôi đã lấy được hoa mandārava này.”",
  "dn16:6.19.8": "Ở đó, những vị Tỳ-kheo nào chưa lìa tham thì có người dang tay khóc lóc, ngã quỵ xuống, lăn qua lộn lại:",
  "dn16:6.19.9": "“Thế Tôn nhập Niết-bàn quá sớm, Thiện Thệ nhập Niết-bàn quá sớm, con mắt của đời đã biến mất quá sớm.”",
  "dn16:6.19.10": "Còn những vị Tỳ-kheo đã lìa tham thì chánh niệm tỉnh giác, kham nhẫn chịu đựng:",
  "dn16:6.19.11": "“Các hành là vô thường, ở đây có thể làm gì được?”",
  "dn16:6.20.1": "Lúc bấy giờ, một vị xuất gia già tên là Subhadda đang ngồi trong hội chúng ấy.",
  "dn16:6.20.2": "Rồi Subhadda, vị xuất gia già ấy, nói với các Tỳ-kheo ấy rằng:",
  "dn16:6.20.3": "“Thôi, này các hiền giả, đừng buồn, đừng than khóc. Chúng ta đã được giải thoát khỏi vị đại Sa-môn ấy rồi. Chúng ta đã bị quấy rầy bởi lời này:",
  "dn16:6.20.4": "‘Điều này được phép cho các ông, điều này không được phép cho các ông.’",
  "dn16:6.20.5": "Nhưng nay, điều gì chúng ta muốn, chúng ta sẽ làm; điều gì chúng ta không muốn, chúng ta sẽ không làm.”",
  "dn16:6.20.6": "Rồi Tôn giả Mahākassapa gọi các Tỳ-kheo:",
  "dn16:6.20.7": "“Thôi, này các hiền giả, đừng buồn, đừng than khóc.",
  "dn16:6.20.8": "Này các hiền giả, chẳng phải điều này đã được Thế Tôn nói trước rồi sao:",
  "dn16:6.20.9": "‘Đối với tất cả những gì thân yêu, khả ái, đều có sự khác biệt, sự chia lìa, sự đổi khác.’",
  "dn16:6.20.10": "Này các hiền giả, ở đây có thể làm gì được? Cái gì đã sinh, đã hiện hữu, đã được tạo thành, có bản chất hoại diệt, thì thân thể của Như Lai cũng không thể không tan hoại; không có chuyện ấy.”",
  "dn16:6.21.1": "Lúc bấy giờ, bốn vị thủ lãnh của người Mallā, sau khi gội đầu và mặc y phục mới, nghĩ rằng:",
  "dn16:6.21.2": "“Chúng ta sẽ châm lửa giàn hỏa của Thế Tôn”, nhưng không thể châm lửa được.",
  "dn16:6.21.3": "Rồi các Mallā ở Kusinārā nói với Tôn giả Anuruddha rằng:",
  "dn16:6.21.4": "“Bạch ngài Anuruddha, do nhân gì, do duyên gì mà bốn vị thủ lãnh của người Mallā này, sau khi gội đầu và mặc y phục mới, nghĩ rằng:",
  "dn16:6.21.5": "‘Chúng ta sẽ châm lửa giàn hỏa của Thế Tôn’, mà không thể châm lửa được?”",
  "dn16:6.21.6": "“Này Vāseṭṭha, ý định của chư thiên là khác.”",
  "dn16:6.21.7": "“Bạch Thế Tôn, ý định của chư thiên là thế nào?”",
  "dn16:6.21.8": "“Này Vāseṭṭha, ý định của chư thiên là:",
  "dn16:6.21.9": "‘Tôn giả Mahākassapa đang từ Pāvā đi trên đường đến Kusinārā cùng với đại chúng Tỳ-kheo gồm khoảng năm trăm vị Tỳ-kheo.",
  "dn16:6.21.10": "Chừng nào Tôn giả Mahākassapa chưa đảnh lễ dưới chân Đức Thế Tôn bằng đầu mình, thì chừng ấy giàn hỏa táng của Đức Thế Tôn sẽ chưa bốc cháy.’”",
  "dn16:6.21.11": "“Bạch Thế Tôn, mong sự việc diễn ra đúng như ý định của chư thiên.”",
  "dn16:6.22.1": "Bấy giờ Tôn giả Mahākassapa đi đến ngôi tháp của các Mallā ở Kusinārā tên là Makuṭabandhana, nơi có giàn hỏa táng của Đức Thế Tôn; sau khi đến, ngài để một bên vai áo, chắp tay cung kính, đi nhiễu quanh giàn hỏa táng ba vòng theo chiều bên phải, rồi cúi đầu đảnh lễ dưới chân Đức Thế Tôn.",
  "dn16:6.22.2": "Năm trăm vị Tỳ-kheo ấy cũng để một bên vai áo, chắp tay cung kính, đi nhiễu quanh giàn hỏa táng ba vòng theo chiều bên phải, rồi cúi đầu đảnh lễ dưới chân Đức Thế Tôn.",
  "dn16:6.22.3": "Và khi Tôn giả Mahākassapa cùng năm trăm vị Tỳ-kheo ấy đã đảnh lễ xong, giàn hỏa táng của Đức Thế Tôn tự nhiên bốc cháy.",
  "dn16:6.23.1": "Khi thân thể Đức Thế Tôn đang cháy, bất cứ phần nào là da, hay bì, hay thịt, hay gân, hay chất nhờn, thì không thấy tro, cũng không thấy muội than;",
  "dn16:6.23.2": "chỉ còn lại xá-lợi.",
  "dn16:6.23.3": "Ví như khi bơ sữa hay dầu cháy thì không thấy tro, cũng không thấy muội than;",
  "dn16:6.23.4": "cũng vậy, khi thân thể Đức Thế Tôn đang cháy, bất cứ phần nào là da, hay bì, hay thịt, hay gân, hay chất nhờn, thì không thấy tro, cũng không thấy muội than;",
  "dn16:6.23.5": "chỉ còn lại xá-lợi.",
  "dn16:6.23.6": "Trong năm trăm cặp vải ấy, chỉ có hai tấm không bị cháy: một tấm trong cùng và một tấm ngoài cùng.",
  "dn16:6.23.7": "Và khi thân thể Đức Thế Tôn đã cháy xong, từ giữa hư không hiện ra những dòng nước dập tắt giàn hỏa táng của Đức Thế Tôn.",
  "dn16:6.23.8": "Từ cây sāla nước cũng vọt lên dập tắt giàn hỏa táng của Đức Thế Tôn.",
  "dn16:6.23.9": "Người Mallā ở Kusinārā cũng dùng mọi thứ nước thơm để dập tắt giàn hỏa táng của Đức Thế Tôn.",
  "dn16:6.23.10": "Bấy giờ người Mallā ở Kusinārā đặt xá-lợi của Đức Thế Tôn trong hội trường suốt bảy ngày, làm hàng rào giáo mác và cho bao quanh bằng tường cung nỏ, rồi dùng múa hát, âm nhạc, vòng hoa và hương thơm mà tôn kính, trọng vọng, kính lễ và cúng dường.",
  "dn16:6.24.0": "39. Phân chia xá-lợi thân",
  "dn16:6.24.1": "Vua Ajātasattu xứ Magadha, con bà Vedehī, nghe tin:",
  "dn16:6.24.2": "“Nghe nói Đức Thế Tôn đã nhập Niết-bàn tại Kusinārā.”",
  "dn16:6.24.3": "Bấy giờ vua Ajātasattu xứ Magadha, con bà Vedehī, sai sứ đến người Mallā ở Kusinārā:",
  "dn16:6.24.4": "“Đức Thế Tôn là một vị Sát-đế-lỵ, ta cũng là một vị Sát-đế-lỵ; ta cũng xứng đáng được một phần xá-lợi của Đức Thế Tôn; ta cũng sẽ xây tháp và tổ chức đại lễ tôn thờ xá-lợi của Đức Thế Tôn.”",
  "dn16:6.24.5": "Người Licchavī ở Vesālī nghe tin:",
  "dn16:6.24.6": "“Nghe nói Đức Thế Tôn đã nhập Niết-bàn tại Kusinārā.”",
  "dn16:6.24.7": "Bấy giờ người Licchavī ở Vesālī sai sứ đến người Mallā ở Kusinārā:",
  "dn16:6.24.8": "“Đức Thế Tôn là một vị Sát-đế-lỵ, chúng tôi cũng là những vị Sát-đế-lỵ; chúng tôi cũng xứng đáng được một phần xá-lợi của Đức Thế Tôn; chúng tôi cũng sẽ xây tháp và tổ chức đại lễ tôn thờ xá-lợi của Đức Thế Tôn.”",
  "dn16:6.24.9": "Người Sākyā ở Kapilavatthu nghe tin:",
  "dn16:6.24.10": "“Nghe nói Đức Thế Tôn đã nhập Niết-bàn tại Kusinārā.”",
  "dn16:6.24.11": "Bấy giờ, những người Sākya ở Kapilavatthu sai sứ giả đến các Mallā ở Kusinārā:",
  "dn16:6.24.12": "“Thế Tôn là bậc tối thượng trong hàng thân tộc của chúng tôi, chúng tôi cũng xứng đáng được một phần xá-lợi của Thế Tôn, chúng tôi cũng sẽ xây tháp lớn cho xá-lợi của Thế Tôn.”",
  "dn16:6.24.13": "Rồi những người Buli ở Allakappa nghe tin:",
  "dn16:6.24.14": "“Nghe nói Thế Tôn đã nhập Niết-bàn tại Kusinārā.”",
  "dn16:6.24.15": "Bấy giờ, những người Buli ở Allakappa sai sứ giả đến các Mallā ở Kusinārā:",
  "dn16:6.24.16": "“Thế Tôn cũng là một vị Sát-đế-lỵ, chúng tôi cũng là Sát-đế-lỵ, chúng tôi cũng xứng đáng được một phần xá-lợi của Thế Tôn, chúng tôi cũng sẽ xây tháp lớn cho xá-lợi của Thế Tôn.”",
  "dn16:6.24.17": "Rồi những người Koḷiya ở Rāmagāma nghe tin:",
  "dn16:6.24.18": "“Nghe nói Thế Tôn đã nhập Niết-bàn tại Kusinārā.”",
  "dn16:6.24.19": "Bấy giờ, những người Koḷiya ở Rāmagāma sai sứ giả đến các Mallā ở Kusinārā:",
  "dn16:6.24.20": "“Thế Tôn cũng là một vị Sát-đế-lỵ, chúng tôi cũng là Sát-đế-lỵ, chúng tôi cũng xứng đáng được một phần xá-lợi của Thế Tôn, chúng tôi cũng sẽ xây tháp lớn cho xá-lợi của Thế Tôn.”",
  "dn16:6.24.21": "Rồi vị Bà-la-môn ở Veṭṭhadīpa nghe tin:",
  "dn16:6.24.22": "“Nghe nói Thế Tôn đã nhập Niết-bàn tại Kusinārā.”",
  "dn16:6.24.23": "Bấy giờ, vị Bà-la-môn ở Veṭṭhadīpa sai sứ giả đến các Mallā ở Kusinārā:",
  "dn16:6.24.24": "“Thế Tôn cũng là một vị Sát-đế-lỵ, còn tôi là Bà-la-môn, tôi cũng xứng đáng được một phần xá-lợi của Thế Tôn, tôi cũng sẽ xây tháp lớn cho xá-lợi của Thế Tôn.”",
  "dn16:6.24.25": "Rồi những người Mallā ở Pāvā nghe tin:",
  "dn16:6.24.26": "“Nghe nói Thế Tôn đã nhập Niết-bàn tại Kusinārā.”",
  "dn16:6.24.27": "Bấy giờ, những người Mallā ở Pāvā sai sứ giả đến các Mallā ở Kusinārā:",
  "dn16:6.24.28": "“Thế Tôn cũng là một vị Sát-đế-lỵ, chúng tôi cũng là Sát-đế-lỵ, chúng tôi cũng xứng đáng được một phần xá-lợi của Thế Tôn, chúng tôi cũng sẽ xây tháp lớn cho xá-lợi của Thế Tôn.”",
  "dn16:6.25.1": "Khi được nói vậy, các Mallā ở Kusinārā nói với hội chúng ấy rằng:",
  "dn16:6.25.2": "“Thế Tôn đã nhập Niết-bàn trong địa phận làng của chúng tôi, chúng tôi sẽ không chia phần xá-lợi của Thế Tôn.”",
  "dn16:6.25.3": "Khi được nói vậy, Bà-la-môn Doṇa nói với hội chúng ấy rằng:",
  "dn16:6.25.4": "“Xin chư vị hãy nghe một lời của tôi,",
  "dn16:6.25.5": "Đức Phật của chúng ta là bậc chủ trương nhẫn nhục;",
  "dn16:6.25.6": "Thật không phải điều tốt đẹp khi vì bậc tối thượng ấy,",
  "dn16:6.25.7": "Mà xảy ra tranh chấp về việc chia xá-lợi.",
  "dn16:6.25.8": "Mong tất cả chư vị cùng nhau hòa hợp, đồng lòng,",
  "dn16:6.25.9": "Hoan hỷ mà chia thành tám phần;",
  "dn16:6.25.10": "Để các tháp được dựng lên khắp các phương,",
  "dn16:6.25.11": "Và nhiều người sẽ khởi lòng tịnh tín đối với bậc có mắt.”",
  "dn16:6.25.12": "“Vậy thì, này Bà-la-môn, chính ông hãy chia xá-lợi của Thế Tôn thành tám phần bằng nhau, phân chia công bằng.”",
  "dn16:6.25.13": "“Vâng, thưa chư vị” — bà-la-môn Doṇa đáp lời các hội chúng, các bộ tộc ấy, rồi chia đều xá-lợi của Thế Tôn thành tám phần bằng nhau, và nói với các hội chúng, các bộ tộc ấy rằng:",
  "dn16:6.25.14": "“Xin chư vị hãy cho tôi cái bình này; tôi cũng sẽ xây tháp và tổ chức đại lễ cúng dường cho cái bình ấy.”",
  "dn16:6.25.15": "Họ đã trao cái bình cho bà-la-môn Doṇa.",
  "dn16:6.26.1": "Những người Moriya ở Pippalivana nghe tin rằng:",
  "dn16:6.26.2": "“Đức Thế Tôn đã nhập Niết-bàn tại Kusinārā.”",
  "dn16:6.26.3": "Bấy giờ, những người Moriya ở Pippalivana sai sứ đến những người Malla ở Kusinārā:",
  "dn16:6.26.4": "“Đức Thế Tôn cũng là một vị sát-đế-lỵ, chúng tôi cũng là sát-đế-lỵ; chúng tôi cũng xứng đáng được một phần xá-lợi của Thế Tôn; chúng tôi cũng sẽ xây tháp và tổ chức đại lễ cúng dường xá-lợi của Thế Tôn.”",
  "dn16:6.26.5": "“Không còn phần xá-lợi nào của Thế Tôn nữa, xá-lợi của Thế Tôn đã được chia xong.",
  "dn16:6.26.6": "Từ đây, các ông hãy mang than tro đi.”",
  "dn16:6.26.7": "Họ từ đó mang than tro đi.",
  "dn16:6.27.0": "40. Cúng dường tháp xá-lợi",
  "dn16:6.27.1": "Bấy giờ, vua Ajātasattu, con bà Vedehī, vua xứ Magadha, đã xây tháp và tổ chức đại lễ cúng dường xá-lợi của Thế Tôn tại Rājagaha.",
  "dn16:6.27.2": "Những người Licchavī ở Vesālī cũng đã xây tháp và tổ chức đại lễ cúng dường xá-lợi của Thế Tôn tại Vesālī.",
  "dn16:6.27.3": "Những người Sakya ở Kapilavatthu cũng đã xây tháp và tổ chức đại lễ cúng dường xá-lợi của Thế Tôn tại Kapilavatthu.",
  "dn16:6.27.4": "Những người Buli ở Allakappa cũng đã xây tháp và tổ chức đại lễ cúng dường xá-lợi của Thế Tôn tại Allakappa.",
  "dn16:6.27.5": "Những người Koḷiya ở Rāmagāma cũng đã xây tháp và tổ chức đại lễ cúng dường xá-lợi của Thế Tôn tại Rāmagāma.",
  "dn16:6.27.6": "Vị bà-la-môn ở Veṭṭhadīpa cũng đã xây tháp và tổ chức đại lễ cúng dường xá-lợi của Thế Tôn tại Veṭṭhadīpa.",
  "dn16:6.27.7": "Những người Malla ở Pāvā cũng đã xây tháp và tổ chức đại lễ cúng dường xá-lợi của Thế Tôn tại Pāvā.",
  "dn16:6.27.8": "Những người Malla ở Kusinārā cũng đã xây tháp và tổ chức đại lễ cúng dường xá-lợi của Thế Tôn tại Kusinārā.",
  "dn16:6.27.9": "Bà-la-môn Doṇa cũng đã xây tháp và tổ chức đại lễ cúng dường cho cái bình.",
  "dn16:6.27.10": "Những người Moriya ở Pippalivana cũng đã xây tháp và tổ chức đại lễ cúng dường than tro tại Pippalivana.",
  "dn16:6.27.11": "Như vậy, có tám tháp xá-lợi, tháp thứ chín là tháp cái bình, tháp thứ mười là tháp than tro.",
  "dn16:6.27.12": "Sự việc xưa kia là như vậy.",
  "dn16:6.28.1": "Xá-lợi của bậc có mắt được tám doṇa,",
  "dn16:6.28.2": "Bảy doṇa được tôn thờ trong cõi Jambudīpa;",
  "dn16:6.28.3": "Còn một doṇa của bậc tối thắng trong loài người,",
  "dn16:6.28.4": "Được Nāgarāja tôn thờ tại Rāmagāma.",
  "dn16:6.28.5": "Một chiếc răng được chư thiên cõi trời Ba Mươi Ba cúng dường,",
  "dn16:6.28.6": "Một chiếc khác được tôn thờ tại thành Gandhāra;",
  "dn16:6.28.7": "Còn một chiếc nữa ở trong lãnh thổ vua Kāliṅga,",
  "dn16:6.28.8": "Một vị long vương tôn kính Ngài.",
  "dn16:6.28.9": "Chính nhờ oai lực ấy mà quả đất này,",
  "dn16:6.28.10": "được trang hoàng bằng những lễ phẩm thù thắng;",
  "dn16:6.28.11": "cũng vậy, thân thể này của bậc có mắt,",
  "dn16:6.28.12": "được khéo tôn trí bởi những người hết sức tôn kính.",
  "dn16:6.28.13": "Được Thiên chủ, Long chủ, Nhân chủ cúng dường,",
  "dn16:6.28.14": "cũng được những bậc tối thắng trong loài người cúng dường;",
  "dn16:6.28.15": "hãy chắp tay đảnh lễ Ngài,",
  "dn16:6.28.16": "vì Đức Phật thật khó gặp trong hàng trăm kiếp.",
  "dn16:6.28.17": "Bốn mươi chiếc răng,",
  "dn16:6.28.18": "cùng tóc và lông, tất cả,",
  "dn16:6.28.19": "chư thiên đã mang đi từng món một,",
  "dn16:6.28.20": "qua từng vòng thế giới nối tiếp nhau.",
  "dn16:6.28.21": "Kinh Đại Bát Niết-bàn chấm dứt, phần thứ ba."
}
window.BILARA["dn16"]["vi"]["dn16:source"] =
   "Dịch từ nguồn Pali https://suttacentral.net/";
